import type { PublicCard } from '../../../types';

export const historyCards: PublicCard[] = [
  { id: 'dc-history-0001', deck_id: 'deck-history', front: 'Fall of the Western Roman Empire', back: '476 CE. The deposition of Emperor Romulus Augustulus by Germanic chieftain Odoacer, traditionally marking the end of ancient Rome and the beginning of the Middle Ages.', sort_order: 1 , front_translations: {"es":"Caída del Imperio Romano del Occidente","de":"Untergang des Weströmischen Reiches","fr":"Chute de l'Empire romain d'Occident","tr":"Batı Roma İmparatorluğu'nun Çöküşü","nl":"Val van het West-Romeinse Rijk","ru":"Падение Западной Римской империи","zh":"西罗马帝国的灭亡","pt_BR":"Queda do Império Romano do Ocidente","pt_PT":"Queda do Império Romano do Ocidente"}, back_translations: {"es":"476 d.C. La deposición del emperador Romulo Augústulo por el jefe germánico Odoacro, marcando tradicionalmente el fin de la Roma antiga y el início de la Edad Media.","de":"476 n. Chr. Die Absetzung von Kaiser Romulus Augustulus durch den germanischen Anführer Odoaker, die traditionell das Ende der Antike und den Beginn des Mittelalters markiert.","fr":"476 apr. J.-C. La déposition de l'empereur Romulus Augustule par le chef germanique Odoacre, marquant traditionnellement la fin de la Rome antique et le début du Moyen Âge.","tr":"MS 476. Germen lideri Odoacer tarafından İmparator Romulus Augustulus'un tahttan indirilmesi; geleneksel olarak antik Roma'nın sonu ve Orta Çağ'ın başlangıcı olarak kabul edilir.","nl":"476 n.Chr. De afzetting van keizer Romulus Augustulus door de Germaanse aanvoerder Odoaker, die traditioneel het einde van het antieke Rome en het begin van de Middeleeuwen markeert.","ru":"476 г. н.э. Свержение императора Ромула Августула германским вождём Одоакром, традиционно считающееся концом античного Рима и началом Средних веков.","zh":"公元476年。日耳曼首领奥多亚克废黜皇帝罗慕路斯·奥古斯图卢斯，传统上标志着古罗马的终结和中世纪的开始。","pt_BR":"476 d.C. A deposição do imperador Rômulo Augústulo pelo chefe germânico Odoacro, marcando tradicionalmente o fim da Roma antiga e o início da Idade Média.","pt_PT":"476 d.C. A deposição do imperador Rómulo Augústulo pelo chefe germânico Odoacro, marcando tradicionalmente o fim da Roma antiga e o início da Idade Média."}},
  { id: 'dc-history-0002', deck_id: 'deck-history', front: 'Battle of Marathon', back: '490 BCE. Athenian forces defeated the Persian invasion army, preserving Greek independence and halting Persian westward expansion into Europe.', sort_order: 2 , front_translations: {"es":"Batalla de Maratona","de":"Schlacht von Marathon","fr":"Bataille de Marathon","tr":"Marathon Muharebesi","nl":"Slag bij Marathon","ru":"Марафонская битва","zh":"马拉松战役","pt_BR":"Batalha de Maratona","pt_PT":"Batalha de Maratona"}, back_translations: {"es":"490 a.C. As fuerzas atenienses derrotaram el exército invasor persa, preservando a independencia grega y detendo a expansão persa para el oeste en la Europa.","de":"490 v. Chr. Athenische Kräfte besiegten das persische Invasionsheer und bewahrten die griechische Unabhängigkeit sowie die persische Westexpansion nach Europa.","fr":"490 av. J.-C. Les forces athéniennes ont vaincu l'armée d'invasion perse, préservant l'indépendance grecque et stoppant l'expansion perse vers l'ouest en Europe.","tr":"MÖ 490. Atina kuvvetleri, İran istila ordusunu yenerek Yunan bağımsızlığını korudu ve Perslerin Avrupa'ya doğru batı yönlü genişlemesini durdurdu.","nl":"490 v.Chr. Atheense troepen versloegen het Perzische invasieleger, waarmee de Griekse onafhankelijkheid bewaard bleef en de Perzische westwaartse expansie naar Europa werd gestuit.","ru":"490 г. до н.э. Афинские силы разгромили персидскую армию вторжения, сохранив независимость Греции и остановив персидскую экспансию на запад в Европу.","zh":"公元前490年。雅典军队击败了波斯入侵军，维护了希腊的独立，阻止了波斯向西扩张进入欧洲。","pt_BR":"490 a.C. As forças atenienses derrotaram o exército invasor persa, preservando a independência grega e detendo a expansão persa para o oeste na Europa.","pt_PT":"490 a.C. As forças atenienses derrotaram o exército invasor persa, preservando a independência grega e detendo a expansão persa para o ocidente na Europa."}},
  { id: 'dc-history-0003', deck_id: 'deck-history', front: 'Magna Carta', back: '1215 CE. A charter signed by King John of England limiting royal power and establishing for the first time that everyone, including the king, was subject to the law.', sort_order: 3 , front_translations: {"es":"Magna Carta","de":"Magna Carta","fr":"La Grande Charte (Magna Carta)","tr":"Magna Carta","nl":"Magna Carta","ru":"Великая хартия вольностей","zh":"《大宪章》","pt_BR":"Magna Carta","pt_PT":"Magna Carta"}, back_translations: {"es":"1215 d.C. Una carta assinada por el rey João de la Inglaterra que limitava el poder real y estabelecia por la primera vez que todos, incluyendo el rey, estavam sujeitos a la ley.","de":"1215 n. Chr. Eine von König Johann von England unterzeichnete Urkunde, die die königliche Macht einschränkte und erstmals festlegte, dass alle – auch der König – dem Gesetz unterworfen sind.","fr":"1215 apr. J.-C. Une charte signée par le roi Jean d'Angleterre limitant le pouvoir royal et établissant pour la première fois que tout le monde, y compris le roi, était soumis à la loi.","tr":"MS 1215. İngiltere Kralı John tarafından imzalanan ve kraliyet gücünü sınırlayan, kral dahil herkesin yasalara tabi olduğunu ilk kez ortaya koyan bir belge.","nl":"1215 n.Chr. Een handvest ondertekend door koning Jan van Engeland dat de koninklijke macht beperkte en voor het eerst vastlegde dat iedereen, inclusief de koning, onderworpen was aan de wet.","ru":"1215 г. н.э. Хартия, подписанная королём Иоанном Английским, ограничивавшая королевскую власть и впервые устанавливавшая, что все, включая короля, подчиняются закону.","zh":"公元1215年。英格兰国王约翰签署的一份宪章，限制了王权，首次确立了包括国王在内的所有人都须服从法律的原则。","pt_BR":"1215 d.C. Uma carta assinada pelo rei João da Inglaterra que limitava o poder real e estabelecia pela primeira vez que todos, incluindo o rei, estavam sujeitos à lei.","pt_PT":"1215 d.C. Uma carta assinada pelo rei João de Inglaterra que limitava o poder real e estabelecia pela primeira vez que todos, incluindo o rei, estavam sujeitos à lei."}},
  { id: 'dc-history-0004', deck_id: 'deck-history', front: 'Black Death', back: '1347–1351. A devastating bubonic plague pandemic that killed an estimated one-third of Europe\'s population, fundamentally reshaping medieval society and labor relations.', sort_order: 4 , front_translations: {"es":"Peste Negra","de":"Schwarzer Tod","fr":"La Peste noire","tr":"Kara Ölüm","nl":"De Zwarte Dood","ru":"Чёрная смерть","zh":"黑死病","pt_BR":"Peste Negra","pt_PT":"Peste Negra"}, back_translations: {"es":"1347–1351. Una devastadora pandemia de peste bubonica que matou cerca de un terço de la población europeia, remodelando fundamentalmente a sociedad medieval y las relaciones de trabajo.","de":"1347–1351. Eine verheerende Beulenpest-Pandemie, die etwa ein Drittel der europäischen Bevölkerung tötete und die mittelalterliche Gesellschaft sowie die Arbeitsverhältnisse grundlegend veränderte.","fr":"1347–1351. Une dévastatrice pandémie de peste bubonique qui tua environ un tiers de la population européenne, remodelant fondamentalement la société médiévale et les relations de travail.","tr":"1347–1351. Avrupa nüfusunun yaklaşık üçte birini öldüren, ortaçağ toplumunu ve işçi ilişkilerini köklü biçimde dönüştüren yıkıcı bir veba salgını.","nl":"1347–1351. Een verwoestende builenpestpandemie die naar schatting een derde van de Europese bevolking doodde en de middeleeuwse samenleving en arbeidsverhoudingen fundamenteel veranderde.","ru":"1347–1351. Опустошительная пандемия бубонной чумы, унёсшая жизни около трети населения Европы, коренным образом изменив средневековое общество и трудовые отношения.","zh":"1347–1351年。一场毁灭性的腺鼠疫大流行，杀死了欧洲约三分之一的人口，从根本上重塑了中世纪社会和劳动关系。","pt_BR":"1347–1351. Uma devastadora pandemia de peste bubônica que matou cerca de um terço da população europeia, remodelando fundamentalmente a sociedade medieval e as relações de trabalho.","pt_PT":"1347–1351. Uma devastadora pandemia de peste bubónica que matou cerca de um terço da população europeia, remodelando fundamentalmente a sociedade medieval e as relações laborais."}},
  { id: 'dc-history-0005', deck_id: 'deck-history', front: 'Construction of the Pyramids of Giza', back: 'c. 2560 BCE. Built during the Fourth Dynasty of ancient Egypt as tombs for pharaohs; the Great Pyramid of Khufu is the only surviving wonder of the ancient world.', sort_order: 5 , front_translations: {"es":"Construcción de las Piramides de Gizé","de":"Bau der Pyramiden von Gizeh","fr":"Construction des pyramides de Gizeh","tr":"Gize Piramitlerinin İnşası","nl":"Bouw van de piramides van Gizeh","ru":"Строительство пирамид Гизы","zh":"吉萨金字塔群的建造","pt_BR":"Construção das Pirâmides de Gizé","pt_PT":"Construção das Pirâmides de Gizé"}, back_translations: {"es":"c. 2560 a.C. Construídas durante a Quarta Dinastia del antigo Egito como tumbas para los faraós; a Grande Piramide de Quéops es a única maravilha del mundo antigo aún existente.","de":"ca. 2560 v. Chr. Während der Vierten Dynastie des alten Ägypten als Grabmäler für Pharaonen erbaut; die Große Pyramide des Cheops ist das einzige erhaltene Weltwunder der Antike.","fr":"Vers 2560 av. J.-C. Construites sous la IVe dynastie de l'Égypte ancienne comme tombeaux pour les pharaons ; la Grande Pyramide de Khéops est la seule merveille du monde antique encore debout.","tr":"MÖ yaklaşık 2560. Antik Mısır'ın Dördüncü Hanedanı döneminde firavunlar için mezar olarak inşa edildi; Khufu'nun Büyük Piramidi, antik dünyanın günümüze ulaşan tek harikasıdır.","nl":"ca. 2560 v.Chr. Gebouwd tijdens de Vierde Dynastie van het oude Egypte als grafmonumenten voor farao's; de Grote Pyramide van Cheops is het enige nog bestaande wonder van de antieke wereld.","ru":"ок. 2560 г. до н.э. Построены в эпоху Четвёртой династии Древнего Египта как гробницы для фараонов; Великая пирамида Хуфу — единственное сохранившееся чудо древнего мира.","zh":"约公元前2560年。建于古埃及第四王朝，作为法老的陵墓；胡夫大金字塔是古代世界七大奇迹中唯一保存至今的。","pt_BR":"c. 2560 a.C. Construídas durante a Quarta Dinastia do antigo Egito como tumbas para os faraós; a Grande Pirâmide de Quéops é a única maravilha do mundo antigo ainda existente.","pt_PT":"c. 2560 a.C. Construídas durante a Quarta Dinastia do antigo Egito como túmulos para os faraós; a Grande Pirâmide de Quéops é a única maravilha do mundo antigo ainda existente."}},
  { id: 'dc-history-0006', deck_id: 'deck-history', front: 'Fall of Constantinople', back: '1453 CE. Ottoman Sultan Mehmed II conquered the Byzantine capital, ending the Eastern Roman Empire and opening a new era of Ottoman dominance in the eastern Mediterranean.', sort_order: 6 , front_translations: {"es":"Caída de Constantinopla","de":"Fall von Konstantinopel","fr":"Chute de Constantinople","tr":"Konstantinopolis'in Fethi","nl":"Val van Constantinopel","ru":"Падение Константинополя","zh":"君士坦丁堡的陷落","pt_BR":"Queda de Constantinopla","pt_PT":"Queda de Constantinopla"}, back_translations: {"es":"1453 d.C. El sultão otomano Mehmed II conquistou a capital bizantina, encerrando el Imperio Romano del Oriente y abrindo una nueva era de domínio otomano en el Mediterraneo oriental.","de":"1453 n. Chr. Der osmanische Sultan Mehmed II. eroberte die byzantinische Hauptstadt, beendete das Oströmische Reich und leitete eine neue Ära osmanischer Vorherrschaft im östlichen Mittelmeerraum ein.","fr":"1453 apr. J.-C. Le sultan ottoman Mehmed II conquit la capitale byzantine, mettant fin à l'Empire romain d'Orient et ouvrant une nouvelle ère de domination ottomane en Méditerranée orientale.","tr":"MS 1453. Osmanlı Sultanı II. Mehmed, Bizans başkentini fethederek Doğu Roma İmparatorluğu'na son verdi ve Doğu Akdeniz'de yeni bir Osmanlı egemenliği dönemini başlattı.","nl":"1453 n.Chr. Ottomaans sultan Mehmed II veroverde de Byzantijnse hoofdstad, waarmee het Oost-Romeinse Rijk eindigde en een nieuw tijdperk van Ottomaanse dominantie in het oostelijke Middellandse Zeegebied begon.","ru":"1453 г. н.э. Османский султан Мехмед II завоевал византийскую столицу, положив конец Восточной Римской империи и открыв новую эпоху османского господства в восточном Средиземноморье.","zh":"公元1453年。奥斯曼苏丹穆罕默德二世攻克拜占庭首都，终结了东罗马帝国，开启了奥斯曼帝国在东地中海主导地位的新纪元。","pt_BR":"1453 d.C. O sultão otomano Mehmed II conquistou a capital bizantina, encerrando o Império Romano do Oriente e abrindo uma nova era de domínio otomano no Mediterrâneo oriental.","pt_PT":"1453 d.C. O sultão otomano Mehmed II conquistou a capital bizantina, encerrando o Império Romano do Oriente e abrindo uma nova era de domínio otomano no Mediterrâneo oriental."}},
  { id: 'dc-history-0007', deck_id: 'deck-history', front: 'Columbus Reaches the Americas', back: '1492. Christopher Columbus landed in the Caribbean, initiating sustained European contact with the Americas and beginning the Age of Exploration and colonization.', sort_order: 7 , front_translations: {"es":"Colombo Chega a las Américas","de":"Kolumbus erreicht Amerika","fr":"Colomb atteint les Amériques","tr":"Kolomb Amerika'ya Ulaşıyor","nl":"Columbus bereikt Amerika","ru":"Колумб достигает Америки","zh":"哥伦布抵达美洲","pt_BR":"Colombo Chega às Américas","pt_PT":"Colombo Chega às Américas"}, back_translations: {"es":"1492. Cristóvão Colombo desembarcou en el Caribe, iniciando el contato europeu sustentado con las Américas y começando a Era de las Descubrimientos y de la colonización.","de":"1492. Christoph Kolumbus landete in der Karibik, leitete den dauerhaften europäischen Kontakt mit Amerika ein und begann das Zeitalter der Entdeckungen und Kolonisierung.","fr":"1492. Christophe Colomb débarqua dans les Caraïbes, initiant un contact européen soutenu avec les Amériques et débutant l'Ère des Grandes Découvertes et de la colonisation.","tr":"1492. Kristof Kolomb Karayipler'e çıkarma yaparak Avrupa'nın Amerika ile sürekli temasını başlattı ve Keşifler Çağı ile sömürgeciliğin önünü açtı.","nl":"1492. Christoffel Columbus landde in het Caribisch gebied en initieerde duurzaam Europees contact met de Amerika's, waarmee het Tijdperk van Ontdekkingen en kolonisatie begon.","ru":"1492. Христофор Колумб высадился на Карибских островах, положив начало устойчивому европейскому контакту с Америкой и открыв Эпоху Великих географических открытий и колонизации.","zh":"1492年。克里斯托弗·哥伦布在加勒比海登陆，开启了欧洲与美洲的持续接触，并开始了大探索时代和殖民化进程。","pt_BR":"1492. Cristóvão Colombo desembarcou no Caribe, iniciando o contato europeu sustentado com as Américas e começando a Era das Descobertas e da colonização.","pt_PT":"1492. Cristóvão Colombo desembarcou nas Caraíbas, iniciando o contacto europeu sustentado com as Américas e dando início à Era dos Descobrimentos e da colonização."}},
  { id: 'dc-history-0008', deck_id: 'deck-history', front: 'Protestant Reformation', back: '1517. Martin Luther published his 95 Theses challenging Catholic Church practices, sparking a religious revolution that permanently divided Western Christianity.', sort_order: 8 , front_translations: {"es":"Reforma Protestante","de":"Protestantische Reformation","fr":"Réforme protestante","tr":"Protestan Reformasyonu","nl":"Protestantse Reformatie","ru":"Протестантская Реформация","zh":"新教改革","pt_BR":"Reforma Protestante","pt_PT":"Reforma Protestante"}, back_translations: {"es":"1517. Martinho Lutero publicou sus 95 Teses questionando las práticas de la Igreja Católica, desencadeando una revolución religiosa que dividiu permanentemente el Cristianismo ocidental.","de":"1517. Martin Luther veröffentlichte seine 95 Thesen, in denen er Praktiken der katholischen Kirche kritisierte, und löste damit eine religiöse Revolution aus, die das westliche Christentum dauerhaft spaltete.","fr":"1517. Martin Luther publia ses 95 thèses contestant les pratiques de l'Église catholique, déclenchant une révolution religieuse qui divisa définitivement le christianisme occidental.","tr":"1517. Martin Luther, Katolik Kilisesi uygulamalarını sorgulayan 95 Tez'ini yayımladı; bu durum, Batı Hristiyanlığını kalıcı olarak bölen bir dini devrime yol açtı.","nl":"1517. Maarten Luther publiceerde zijn 95 stellingen die de praktijken van de Katholieke Kerk ter discussie stelden, waarmee hij een religieuze revolutie ontketende die het westerse christendom permanent verdeelde.","ru":"1517. Мартин Лютер опубликовал 95 тезисов, оспаривавших практику католической церкви, что вызвало религиозную революцию, навсегда расколовшую западное христианство.","zh":"1517年。马丁·路德发表《九十五条论纲》，质疑天主教会的做法，引发了一场永久分裂西方基督教的宗教革命。","pt_BR":"1517. Martinho Lutero publicou suas 95 Teses questionando as práticas da Igreja Católica, desencadeando uma revolução religiosa que dividiu permanentemente o Cristianismo ocidental.","pt_PT":"1517. Martinho Lutero publicou as suas 95 Teses questionando as práticas da Igreja Católica, desencadeando uma revolução religiosa que dividiu permanentemente o Cristianismo ocidental."}},
  { id: 'dc-history-0009', deck_id: 'deck-history', front: 'French Revolution', back: '1789–1799. A period of radical political and social transformation in France that abolished the monarchy, established republican government, and spread ideals of liberty, equality, and fraternity.', sort_order: 9 , front_translations: {"es":"Revolución Francesa","de":"Französische Revolution","fr":"Révolution française","tr":"Fransız Devrimi","nl":"Franse Revolutie","ru":"Французская революция","zh":"法国大革命","pt_BR":"Revolução Francesa","pt_PT":"Revolução Francesa"}, back_translations: {"es":"1789–1799. Un período de transformación política y social radical en la França que aboliu a monarquía, estabeleceu un gobierno republicano y difundiu los ideais de liberdad, igualdad y fraternidad.","de":"1789–1799. Eine Zeit des radikalen politischen und gesellschaftlichen Wandels in Frankreich, die die Monarchie abschaffte, eine republikanische Regierung etablierte und die Ideale von Freiheit, Gleichheit und Brüderlichkeit verbreitete.","fr":"1789–1799. Une période de transformation politique et sociale radicale en France qui abolit la monarchie, établit un gouvernement républicain et diffusa les idéaux de liberté, d'égalité et de fraternité.","tr":"1789–1799. Fransa'da monarşiyi ortadan kaldıran, cumhuriyet yönetimini kuran ve özgürlük, eşitlik ile kardeşlik ideallerini yayan köklü bir siyasi ve sosyal dönüşüm dönemi.","nl":"1789–1799. Een periode van radicale politieke en sociale transformatie in Frankrijk die de monarchie afschafte, een republikeinse regering vestigde en de idealen van vrijheid, gelijkheid en broederschap verspreidde.","ru":"1789–1799. Период радикальных политических и социальных преобразований во Франции, упразднившего монархию, установившего республиканское правление и распространившего идеалы свободы, равенства и братства.","zh":"1789–1799年。法国经历了激进的政治和社会变革，废除了君主制，建立了共和政府，并传播了自由、平等、博爱的理念。","pt_BR":"1789–1799. Um período de transformação política e social radical na França que aboliu a monarquia, estabeleceu um governo republicano e difundiu os ideais de liberdade, igualdade e fraternidade.","pt_PT":"1789–1799. Um período de transformação política e social radical em França que aboliu a monarquia, estabeleceu um governo republicano e difundiu os ideais de liberdade, igualdade e fraternidade."}},
  { id: 'dc-history-0010', deck_id: 'deck-history', front: 'American Declaration of Independence', back: '1776. The thirteen American colonies formally declared independence from Britain, articulating Enlightenment principles of natural rights and popular sovereignty.', sort_order: 10 , front_translations: {"es":"Declaración de Independencia de los EUA","de":"Amerikanische Unabhängigkeitserklärung","fr":"Déclaration d'indépendance américaine","tr":"Amerikan Bağımsızlık Bildirisi","nl":"Amerikaanse Onafhankelijkheidsverklaring","ru":"Американская Декларация независимости","zh":"美国《独立宣言》","pt_BR":"Declaração de Independência dos EUA","pt_PT":"Declaração de Independência dos EUA"}, back_translations: {"es":"1776. As treze colonias americanas declararam formalmente a independencia de la Grã-Bretanha, articulando principios iluministas de derechos naturais y soberania popular.","de":"1776. Die dreizehn amerikanischen Kolonien erklärten offiziell ihre Unabhängigkeit von Großbritannien und formulierten aufklärerische Grundsätze der natürlichen Rechte und Volkssouveränität.","fr":"1776. Les treize colonies américaines déclarèrent formellement leur indépendance vis-à-vis de la Grande-Bretagne, en formulant les principes des Lumières sur les droits naturels et la souveraineté populaire.","tr":"1776. On üç Amerikan kolonisi, doğal haklar ve halk egemenliğine ilişkin Aydınlanma ilkelerini dile getirerek İngiltere'den resmi olarak bağımsızlıklarını ilan etti.","nl":"1776. De dertien Amerikaanse koloniën verklaarden officieel hun onafhankelijkheid van Groot-Brittannië, waarbij ze Verlichtingsprincipes van natuurlijke rechten en volkssouvereiniteit verwoordden.","ru":"1776. Тринадцать американских колоний официально провозгласили независимость от Британии, провозгласив просветительские принципы естественных прав и народного суверенитета.","zh":"1776年。十三个美洲殖民地正式宣布脱离英国独立，阐明了启蒙运动关于自然权利和人民主权的原则。","pt_BR":"1776. As treze colônias americanas declararam formalmente a independência da Grã-Bretanha, articulando princípios iluministas de direitos naturais e soberania popular.","pt_PT":"1776. As treze colónias americanas declararam formalmente a independência da Grã-Bretanha, articulando princípios iluministas de direitos naturais e soberania popular."}},
  { id: 'dc-history-0011', deck_id: 'deck-history', front: 'Industrial Revolution', back: '1760–1840. A period of rapid industrialization beginning in Britain, transforming agrarian economies into industrial ones through mechanization, steam power, and factory systems.', sort_order: 11 , front_translations: {"es":"Revolución Industrial","de":"Industrielle Revolution","fr":"Révolution industrielle","tr":"Sanayi Devrimi","nl":"Industriële Revolutie","ru":"Промышленная революция","zh":"工业革命","pt_BR":"Revolução Industrial","pt_PT":"Revolução Industrial"}, back_translations: {"es":"1760–1840. Un período de rápida industrialización que começou en la Grã-Bretanha, transformando economias agrárias en industriais por medio de la mecanización, de la energía a vapor y de los sistemas fabris.","de":"1760–1840. Eine Periode rascher Industrialisierung, die in Großbritannien begann und Agrargesellschaften durch Mechanisierung, Dampfkraft und Fabriksysteme in Industriegesellschaften verwandelte.","fr":"1760–1840. Une période de rapide industrialisation commençant en Grande-Bretagne, transformant les économies agraires en économies industrielles grâce à la mécanisation, la vapeur et les systèmes d'usines.","tr":"1760–1840. İngiltere'de başlayan ve tarım ekonomilerini makineleşme, buhar gücü ve fabrika sistemleri aracılığıyla sanayi ekonomilerine dönüştüren hızlı sanayileşme dönemi.","nl":"1760–1840. Een periode van snelle industrialisering die in Groot-Brittannië begon en agrarische economieën door mechanisering, stoomkracht en fabriekssystemen in industriële economieën transformeerde.","ru":"1760–1840. Период стремительной индустриализации, начавшийся в Британии и превративший аграрные экономики в промышленные посредством механизации, паровой энергии и фабричных систем.","zh":"1760–1840年。始于英国的快速工业化时期，通过机械化、蒸汽动力和工厂制度，将农业经济转变为工业经济。","pt_BR":"1760–1840. Um período de rápida industrialização que começou na Grã-Bretanha, transformando economias agrárias em industriais por meio da mecanização, da energia a vapor e dos sistemas fabris.","pt_PT":"1760–1840. Um período de rápida industrialização que começou na Grã-Bretanha, transformando economias agrárias em industriais através da mecanização, da energia a vapor e dos sistemas fabris."}},
  { id: 'dc-history-0012', deck_id: 'deck-history', front: 'Napoleon Bonaparte', back: '1769–1821. French military genius and emperor who dominated Europe after the Revolution; his Napoleonic Code influenced legal systems worldwide and his campaigns reshaped European borders.', sort_order: 12 , front_translations: {"es":"Napoleão Bonaparte","de":"Napoleon Bonaparte","fr":"Napoléon Bonaparte","tr":"Napolyon Bonapart","nl":"Napoleon Bonaparte","ru":"Наполеон Бонапарт","zh":"拿破仑·波拿巴","pt_BR":"Napoleão Bonaparte","pt_PT":"Napoleão Bonaparte"}, back_translations: {"es":"1769–1821. Genio militar y emperador frances que dominou a Europa após a Revolución; su Código Napoleonico influenciou sistemas jurídicos en todo el mundo y sus campanhas remodelaram las fronteras europeias.","de":"1769–1821. Französisches Militärgenie und Kaiser, der nach der Revolution Europa dominierte; sein Code Napoléon beeinflusste Rechtssysteme weltweit, und seine Feldzüge veränderten Europas Grenzen.","fr":"1769–1821. Génie militaire et empereurifique français qui domina l'Europe après la Révolution ; son Code Napoléon influença les systèmes juridiques du monde entier et ses campagnes remodelèrent les frontières européennes.","tr":"1769–1821. Devrimden sonra Avrupa'ya hükmeden Fransız askeri dehası ve imparatoru; Napolyon Kanunu dünya çapında hukuk sistemlerini etkiledi, seferleri ise Avrupa sınırlarını yeniden şekillendirdi.","nl":"1769–1821. Frans militair genie en keizer die Europa domineerde na de Revolutie; zijn Napoleontische Code beïnvloedde rechtssystemen wereldwijd en zijn campagnes reshapten de Europese grenzen.","ru":"1769–1821. Французский военный гений и император, господствовавший над Европой после Революции; его Наполеоновский кодекс повлиял на правовые системы всего мира, а его кампании изменили европейские границы.","zh":"1769–1821年。法国军事天才和皇帝，革命后主宰欧洲；他的《拿破仑法典》影响了全球法律体系，他的战争征伐重塑了欧洲版图。","pt_BR":"1769–1821. Gênio militar e imperador francês que dominou a Europa após a Revolução; seu Código Napoleônico influenciou sistemas jurídicos em todo o mundo e suas campanhas remodelaram as fronteiras europeias.","pt_PT":"1769–1821. Génio militar e imperador francês que dominou a Europa após a Revolução; o seu Código Napoleónico influenciou sistemas jurídicos em todo o mundo e as suas campanhas remodelaram as fronteiras europeias."}},
  { id: 'dc-history-0013', deck_id: 'deck-history', front: 'World War I', back: '1914–1918. A global conflict triggered by the assassination of Archduke Franz Ferdinand; it resulted in ~20 million deaths, the collapse of four empires, and laid the groundwork for WWII.', sort_order: 13 , front_translations: {"es":"Primera Guerra Mundial","de":"Erster Weltkrieg","fr":"Première Guerre mondiale","tr":"Birinci Dünya Savaşı","nl":"Eerste Wereldoorlog","ru":"Первая мировая война","zh":"第一次世界大战","pt_BR":"Primeira Guerra Mundial","pt_PT":"Primeira Guerra Mundial"}, back_translations: {"es":"1914–1918. Un conflito global desencadeado por el assassinato del arquiduque Franz Ferdinand; resultou en ~20 milhões de mortes, el colapso de cuatro imperios y lançou las bases para a Segunda Guerra Mundial.","de":"1914–1918. Ein globaler Konflikt, ausgelöst durch die Ermordung von Erzherzog Franz Ferdinand; er führte zu ~20 Millionen Toten, dem Zusammenbruch von vier Kaiserreichen und legte den Grundstein für den Zweiten Weltkrieg.","fr":"1914–1918. Un conflit mondial déclenché par l'assassinat de l'archiduc François-Ferdinand ; il entraîna ~20 millions de morts, l'effondrement de quatre empires et posa les bases de la Seconde Guerre mondiale.","tr":"1914–1918. Arşidük Franz Ferdinand'ın suikastıyla başlayan küresel çatışma; yaklaşık 20 milyon ölüme, dört imparatorluğun çöküşüne yol açtı ve İkinci Dünya Savaşı'nın zeminini hazırladı.","nl":"1914–1918. Een wereldwijd conflict uitgelokt door de aanslag op aartshertog Franz Ferdinand; het resulteerde in ~20 miljoen doden, de ineenstorting van vier keizerrijken en legde de basis voor WOII.","ru":"1914–1918. Мировой конфликт, спровоцированный убийством эрцгерцога Франца Фердинанда; унёс жизни около 20 миллионов человек, привёл к краху четырёх империй и заложил почву для Второй мировой войны.","zh":"1914–1918年。由弗朗茨·斐迪南大公遇刺引发的全球冲突，导致约2000万人死亡，四大帝国崩溃，并为第二次世界大战埋下了祸根。","pt_BR":"1914–1918. Um conflito global desencadeado pelo assassinato do arquiduque Franz Ferdinand; resultou em ~20 milhões de mortes, o colapso de quatro impérios e lançou as bases para a Segunda Guerra Mundial.","pt_PT":"1914–1918. Um conflito global desencadeado pelo assassinato do arquiduque Franz Ferdinand; resultou em ~20 milhões de mortes, o colapso de quatro impérios e lançou as bases para a Segunda Guerra Mundial."}},
  { id: 'dc-history-0014', deck_id: 'deck-history', front: 'World War II', back: '1939–1945. The deadliest conflict in history, resulting in ~70–85 million deaths; it ended with Allied victory over Nazi Germany and Imperial Japan and reshaped the global order.', sort_order: 14 , front_translations: {"es":"Segunda Guerra Mundial","de":"Zweiter Weltkrieg","fr":"Seconde Guerre mondiale","tr":"İkinci Dünya Savaşı","nl":"Tweede Wereldoorlog","ru":"Вторая мировая война","zh":"第二次世界大战","pt_BR":"Segunda Guerra Mundial","pt_PT":"Segunda Guerra Mundial"}, back_translations: {"es":"1939–1945. El conflito más mortal de la historia, resultando en ~70–85 milhões de mortes; terminou con a vitória aliada sobre a Alemanha nazista y el Japão Imperial y remodelou a ordem global.","de":"1939–1945. Der tödlichste Konflikt der Geschichte mit ~70–85 Millionen Toten; er endete mit dem Sieg der Alliierten über Nazideutschland und das Kaiserreich Japan und formte die globale Ordnung neu.","fr":"1939–1945. Le conflit le plus meurtrier de l'histoire, faisant ~70–85 millions de morts ; il s'acheva par la victoire des Alliés sur l'Allemagne nazie et le Japon impérial et remodela l'ordre mondial.","tr":"1939–1945. Tarihte yaşanmış en ölümcül çatışma; yaklaşık 70–85 milyon ölüme yol açtı, Nazi Almanyası ile İmparatorluk Japonya'sına karşı Müttefik zaferiyle sona erdi ve küresel düzeni yeniden şekillendirdi.","nl":"1939–1945. Het dodelijkste conflict in de geschiedenis, met ~70–85 miljoen doden; het eindigde met de geallieerde overwinning op nazi-Duitsland en keizerlijk Japan en reshapte de wereldorde.","ru":"1939–1945. Самый смертоносный конфликт в истории, унёсший жизни около 70–85 миллионов человек; завершился победой союзников над нацистской Германией и Японской империей и изменил мировой порядок.","zh":"1939–1945年。历史上死亡人数最多的冲突，造成约7000万至8500万人死亡；以盟军战胜纳粹德国和日本帝国而告终，重塑了全球秩序。","pt_BR":"1939–1945. O conflito mais mortal da história, resultando em ~70–85 milhões de mortes; terminou com a vitória aliada sobre a Alemanha nazista e o Japão Imperial e remodelou a ordem global.","pt_PT":"1939–1945. O conflito mais mortífero da história, resultando em ~70–85 milhões de mortes; terminou com a vitória aliada sobre a Alemanha nazi e o Japão Imperial e remodelou a ordem global."}},
  { id: 'dc-history-0015', deck_id: 'deck-history', front: 'Holocaust', back: '1941–1945. The systematic, state-sponsored murder of six million Jews and millions of others by the Nazi regime, representing an unprecedented genocide in modern history.', sort_order: 15 , front_translations: {"es":"Holocausto","de":"Holocaust","fr":"La Shoah (Holocaust)","tr":"Holokost","nl":"Holocaust","ru":"Холокост","zh":"大屠杀（纳粹屠犹）","pt_BR":"Holocausto","pt_PT":"Holocausto"}, back_translations: {"es":"1941–1945. El assassinato sistemático y patrocinado por el Estado de seis milhões de judeus y milhões de outras personas por el regime nazista, representando un genocídio sin precedentes en la historia moderna.","de":"1941–1945. Der systematische, staatlich geförderte Mord an sechs Millionen Juden und Millionen anderer Menschen durch das NS-Regime, der einen beispiellosen Genozid in der modernen Geschichte darstellt.","fr":"1941–1945. Le meurtre systématique et parrainé par l'État de six millions de Juifs et de millions d'autres personnes par le régime nazi, représentant un génocide sans précédent dans l'histoire moderne.","tr":"1941–1945. Nazi rejimi tarafından altı milyon Yahudi ve milyonlarca başka kişinin sistematik, devlet destekli katledilmesi; modern tarihte emsalsiz bir soykırımı temsil eder.","nl":"1941–1945. De systematische, door de staat gesponsorde moord op zes miljoen Joden en miljoenen anderen door het naziregime, wat een ongekende genocide in de moderne geschiedenis vertegenwoordigt.","ru":"1941–1945. Систематическое, спонсированное государством уничтожение нацистским режимом шести миллионов евреев и миллионов других людей, представляющее собой беспрецедентный геноцид в современной истории.","zh":"1941–1945年。纳粹政权对600万犹太人及数百万其他人的系统性、国家主导的屠杀，是现代历史上前所未有的种族灭绝。","pt_BR":"1941–1945. O assassinato sistemático e patrocinado pelo Estado de seis milhões de judeus e milhões de outras pessoas pelo regime nazista, representando um genocídio sem precedentes na história moderna.","pt_PT":"1941–1945. O assassinato sistemático e patrocinado pelo Estado de seis milhões de judeus e milhões de outras pessoas pelo regime nazi, representando um genocídio sem precedentes na história moderna."}},
  { id: 'dc-history-0016', deck_id: 'deck-history', front: 'Russian Revolution', back: '1917. Two revolutions overthrew the Tsarist autocracy and brought the Bolsheviks under Lenin to power, establishing the world\'s first communist state.', sort_order: 16 , front_translations: {"es":"Revolución Russa","de":"Russische Revolution","fr":"Révolution russe","tr":"Rus Devrimi","nl":"Russische Revolutie","ru":"Русская революция","zh":"俄国革命","pt_BR":"Revolução Russa","pt_PT":"Revolução Russa"}, back_translations: {"es":"1917. Dos revoluciones derrubaram a autocracia tsarista y trouxeram los bolcheviques liderados por Lenin al poder, estableciendo el primero Estado comunista del mundo.","de":"1917. Zwei Revolutionen stürzten die zaristische Autokratie und brachten die Bolschewiki unter Lenin an die Macht, womit der erste kommunistische Staat der Welt gegründet wurde.","fr":"1917. Deux révolutions renversèrent l'autocratie tsariste et amenèrent les bolcheviks sous Lénine au pouvoir, établissant le premier État communiste au monde.","tr":"1917. İki devrim, Çarlık otokrasisini devirdi ve Lenin önderliğinde Bolşevikleri iktidara getirerek dünyanın ilk komünist devletini kurdu.","nl":"1917. Twee revoluties omverwierpen de tsaristische autocratie en brachten de bolsjewieken onder Lenin aan de macht, waarmee de eerste communistische staat ter wereld werd gevestigd.","ru":"1917. Две революции свергли царское самодержавие и привели к власти большевиков под руководством Ленина, положив начало первому в мире коммунистическому государству.","zh":"1917年。两场革命推翻了沙皇专制统治，列宁领导的布尔什维克党上台执政，建立了世界上第一个共产主义国家。","pt_BR":"1917. Duas revoluções derrubaram a autocracia tsarista e trouxeram os bolcheviques liderados por Lenin ao poder, estabelecendo o primeiro Estado comunista do mundo.","pt_PT":"1917. Duas revoluções derrubaram a autocracia tsarista e trouxeram os bolcheviques liderados por Lenine ao poder, estabelecendo o primeiro Estado comunista do mundo."}},
  { id: 'dc-history-0017', deck_id: 'deck-history', front: 'Cold War', back: '1947–1991. A period of geopolitical tension between the United States and Soviet Union; characterized by proxy wars, the arms race, and the Space Race rather than direct conflict.', sort_order: 17 , front_translations: {"es":"Guerra Fría","de":"Kalter Krieg","fr":"Guerre froide","tr":"Soğuk Savaş","nl":"Koude Oorlog","ru":"Холодная война","zh":"冷战","pt_BR":"Guerra Fria","pt_PT":"Guerra Fria"}, back_translations: {"es":"1947–1991. Un período de tensão geopolítica entre los Estados Unidos y a União Soviética; caracterizado por guerras por procuración, a corrida armamentista y a corrida espacial, en vez de conflito direto.","de":"1947–1991. Eine Phase geopolitischer Spannungen zwischen den USA und der Sowjetunion; gekennzeichnet durch Stellvertreterkriege, das Wettrüsten und das Raumfahrtwettrennen statt direktem Konflikt.","fr":"1947–1991. Une période de tensions géopolitiques entre les États-Unis et l'Union soviétique ; caractérisée par des guerres par procuration, la course aux armements et la conquête spatiale plutôt que par des conflits directs.","tr":"1947–1991. Amerika Birleşik Devletleri ile Sovyetler Birliği arasındaki jeopolitik gerilim dönemi; doğrudan çatışma yerine vekâlet savaşları, silahlanma yarışı ve Uzay Yarışı ile karakterize edildi.","nl":"1947–1991. Een periode van geopolitieke spanning tussen de Verenigde Staten en de Sovjet-Unie; gekenmerkt door proxyoorlogen, de wapenwedloop en de ruimtewedloop in plaats van direct conflict.","ru":"1947–1991. Период геополитической напряжённости между США и Советским Союзом; характеризовался прокси-войнами, гонкой вооружений и космической гонкой вместо прямого столкновения.","zh":"1947–1991年。美国与苏联之间的地缘政治紧张时期；以代理战争、军备竞赛和太空竞赛为特征，而非直接冲突。","pt_BR":"1947–1991. Um período de tensão geopolítica entre os Estados Unidos e a União Soviética; caracterizado por guerras por procuração, a corrida armamentista e a corrida espacial, em vez de conflito direto.","pt_PT":"1947–1991. Um período de tensão geopolítica entre os Estados Unidos e a União Soviética; caracterizado por guerras por procuração, a corrida armamentista e a corrida espacial, em vez de conflito direto."}},
  { id: 'dc-history-0018', deck_id: 'deck-history', front: 'Moon Landing (Apollo 11)', back: '1969. American astronauts Neil Armstrong and Buzz Aldrin became the first humans to walk on the Moon, marking the culmination of the Space Race.', sort_order: 18 , front_translations: {"es":"Pouso en la Lua (Apollo 11)","de":"Mondlandung (Apollo 11)","fr":"Alunissage (Apollo 11)","tr":"Ay'a İniş (Apollo 11)","nl":"Maanlanding (Apollo 11)","ru":"Высадка на Луну (Аполлон-11)","zh":"登月（阿波罗11号）","pt_BR":"Pouso na Lua (Apollo 11)","pt_PT":"Aterragem na Lua (Apollo 11)"}, back_translations: {"es":"1969. Los astronautas americanos Neil Armstrong y Buzz Aldrin tornaram-se los primeros humanos a caminhar en la Lua, marcando el punto culminante de la Corrida Espacial.","de":"1969. Die amerikanischen Astronauten Neil Armstrong und Buzz Aldrin wurden die ersten Menschen, die auf dem Mond liefen, und markierten damit den Höhepunkt des Weltraumwettlaufs.","fr":"1969. Les astronautes américains Neil Armstrong et Buzz Aldrin devinrent les premiers humains à marcher sur la Lune, marquant l'apogée de la course à l'espace.","tr":"1969. Amerikalı astronotlar Neil Armstrong ve Buzz Aldrin, Ay'da yürüyen ilk insanlar oldu; bu olay Uzay Yarışı'nın doruk noktasını simgeledi.","nl":"1969. De Amerikaanse astronauten Neil Armstrong en Buzz Aldrin werden de eerste mensen die op de Maan liepen, wat het hoogtepunt van de Space Race markeerde.","ru":"1969. Американские астронавты Нил Армстронг и Базз Олдрин стали первыми людьми, ступившими на поверхность Луны, что ознаменовало кульминацию космической гонки.","zh":"1969年。美国宇航员尼尔·阿姆斯特朗和巴兹·奥尔德林成为首批登上月球的人类，标志着太空竞赛的巅峰。","pt_BR":"1969. Os astronautas americanos Neil Armstrong e Buzz Aldrin tornaram-se os primeiros humanos a caminhar na Lua, marcando o ponto culminante da Corrida Espacial.","pt_PT":"1969. Os astronautas americanos Neil Armstrong e Buzz Aldrin tornaram-se os primeiros humanos a caminhar na Lua, marcando o ponto culminante da Corrida Espacial."}},
  { id: 'dc-history-0019', deck_id: 'deck-history', front: 'Fall of the Berlin Wall', back: '1989. The dismantling of the wall dividing East and West Berlin symbolized the end of the Cold War and led to German reunification in 1990.', sort_order: 19 , front_translations: {"es":"Caída del Muro de Berlim","de":"Fall der Berliner Mauer","fr":"Chute du mur de Berlin","tr":"Berlin Duvarı'nın Yıkılması","nl":"Val van de Berlijnse Muur","ru":"Падение Берлинской стены","zh":"柏林墙的倒塌","pt_BR":"Queda do Muro de Berlim","pt_PT":"Queda do Muro de Berlim"}, back_translations: {"es":"1989. El desmantelamento del muro que dividia Berlim Oriental y Ocidental simbolizou el fin de la Guerra Fría y levou a la reunificación alemã en 1990.","de":"1989. Der Abriss der Mauer, die Ost- und Westberlin trennte, symbolisierte das Ende des Kalten Krieges und führte 1990 zur deutschen Wiedervereinigung.","fr":"1989. Le démantèlement du mur divisant Berlin-Est et Berlin-Ouest symbolisa la fin de la Guerre froide et conduisit à la réunification allemande en 1990.","tr":"1989. Doğu ve Batı Berlin'i birbirinden ayıran duvarın yıkılması Soğuk Savaş'ın sonunu simgeledi ve 1990'da Almanya'nın yeniden birleşmesine zemin hazırladı.","nl":"1989. Het slopen van de muur die Oost- en West-Berlijn verdeelde symboliseerde het einde van de Koude Oorlog en leidde tot de Duitse hereniging in 1990.","ru":"1989. Снос стены, разделявшей Восточный и Западный Берлин, стал символом конца Холодной войны и привёл к воссоединению Германии в 1990 году.","zh":"1989年。分隔东西柏林的墙被拆除，象征着冷战的结束，并于1990年促成了德国的统一。","pt_BR":"1989. O desmantelamento do muro que dividia Berlim Oriental e Ocidental simbolizou o fim da Guerra Fria e levou à reunificação alemã em 1990.","pt_PT":"1989. O desmantelamento do muro que dividia Berlim Oriental e Ocidental simbolizou o fim da Guerra Fria e levou à reunificação alemã em 1990."}},
  { id: 'dc-history-0020', deck_id: 'deck-history', front: 'Dissolution of the Soviet Union', back: '1991. The USSR formally dissolved into 15 independent republics, ending the Cold War and leaving the United States as the sole global superpower.', sort_order: 20 , front_translations: {"es":"Disolución de la União Soviética","de":"Auflösung der Sowjetunion","fr":"Dissolution de l'Union soviétique","tr":"Sovyetler Birliği'nin Çöküşü","nl":"Ontbinding van de Sovjet-Unie","ru":"Распад Советского Союза","zh":"苏联解体","pt_BR":"Dissolução da União Soviética","pt_PT":"Dissolução da União Soviética"}, back_translations: {"es":"1991. La URSS se dissolveu formalmente en 15 repúblicas independentes, encerrando a Guerra Fría y deixando los Estados Unidos como única superpotencia global.","de":"1991. Die UdSSR löste sich formell in 15 unabhängige Republiken auf, beendete den Kalten Krieg und hinterließ die USA als einzige globale Supermacht.","fr":"1991. L'URSS se dissolut formellement en 15 républiques indépendantes, mettant fin à la Guerre froide et laissant les États-Unis comme seule superpuissance mondiale.","tr":"1991. SSCB resmen 15 bağımsız cumhuriyete ayrıldı; Soğuk Savaş sona erdi ve Amerika Birleşik Devletleri tek küresel süper güç olarak kaldı.","nl":"1991. De USSR loste formeel op in 15 onafhankelijke republieken, waarmee de Koude Oorlog eindigde en de Verenigde Staten als enige mondiale supermacht overbleven.","ru":"1991. СССР официально распался на 15 независимых республик, положив конец Холодной войне и оставив США единственной мировой сверхдержавой.","zh":"1991年。苏联正式解体为15个独立共和国，冷战宣告结束，美国成为唯一的全球超级大国。","pt_BR":"1991. A URSS se dissolveu formalmente em 15 repúblicas independentes, encerrando a Guerra Fria e deixando os Estados Unidos como única superpotência global.","pt_PT":"1991. A URSS dissolveu-se formalmente em 15 repúblicas independentes, encerrando a Guerra Fria e deixando os Estados Unidos como única superpotência global."}},
  { id: 'dc-history-0021', deck_id: 'deck-history', front: 'Battle of Thermopylae', back: '480 BCE. A small force of Greek soldiers, famously 300 Spartans, held a narrow pass against a massive Persian army, becoming a lasting symbol of heroic self-sacrifice.', sort_order: 21 , front_translations: {"es":"Batalla de las Termópilas","de":"Schlacht von Thermopylae","fr":"Bataille des Thermopyles","tr":"Termopil Muharebesi","nl":"Slag bij Thermopylae","ru":"Битва при Фермопилах","zh":"温泉关战役","pt_BR":"Batalha das Termópilas","pt_PT":"Batalha das Termópilas"}, back_translations: {"es":"480 a.C. Un pequeño grupo de soldados gregos, famosos por los 300 espartanos, defendeu un desfiladero estrecho contra un enorme exército persa, tornando-se un símbolo duradouro de sacrifício heroico.","de":"480 v. Chr. Eine kleine Truppe griechischer Soldaten – berühmt sind die 300 Spartaner – hielt einen engen Pass gegen eine riesige Persische Armee und wurde zu einem dauerhaften Symbol heldenhafter Selbstaufopferung.","fr":"480 av. J.-C. Une petite troupe de soldats grecs, célèbres pour les 300 Spartiates, tint un défilé étroit contre une immense armée perse, devenant un symbole durable de sacrifice héroïque.","tr":"MÖ 480. Aralarında ünlü 300 Spartalı'nın da bulunduğu küçük bir Yunan kuvveti, dar bir geçitte devasa bir Pers ordusuna direndi ve kahraman öz-fedakârlığın kalıcı bir simgesi haline geldi.","nl":"480 v.Chr. Een kleine groep Griekse soldaten, beroemd de 300 Spartanen, hield een nauwe bergpas tegen een massaal Perzisch leger, en werd een blijvend symbool van heroïsche zelfopoffering.","ru":"480 г. до н.э. Небольшой отряд греческих воинов, в том числе знаменитые 300 спартанцев, удерживал узкий проход против огромной персидской армии, став вечным символом героического самопожертвования.","zh":"公元前480年。一小支希腊军队，尤以300名斯巴达人著称，在狭窄的山口抵抗庞大的波斯军队，成为英雄自我牺牲的永恒象征。","pt_BR":"480 a.C. Um pequeno grupo de soldados gregos, famosos pelos 300 espartanos, defendeu um desfiladeiro estreito contra um enorme exército persa, tornando-se um símbolo duradouro de sacrifício heroico.","pt_PT":"480 a.C. Um pequeno grupo de soldados gregos, famosos pelos 300 espartanos, defendeu um desfiladeiro estreito contra um enorme exército persa, tornando-se um símbolo duradouro de sacrifício heroico."}},
  { id: 'dc-history-0022', deck_id: 'deck-history', front: 'Peloponnesian War', back: '431–404 BCE. A devastating conflict between Athens and Sparta that weakened Greek city-states, ultimately facilitating the Macedonian conquest of Greece.', sort_order: 22 , front_translations: {"es":"Guerra del Peloponeso","de":"Peloponnesischer Krieg","fr":"Guerre du Péloponnèse","tr":"Peloponnesos Savaşı","nl":"Peloponnesische Oorlog","ru":"Пелопоннесская война","zh":"伯罗奔尼撒战争","pt_BR":"Guerra do Peloponeso","pt_PT":"Guerra do Peloponeso"}, back_translations: {"es":"431–404 a.C. Un conflito devastador entre Atenas y Esparta que enfraqueceu las cidades-estado gregas, facilitando por fin a conquista macedonica de la Grécia.","de":"431–404 v. Chr. Ein verheerender Konflikt zwischen Athen und Sparta, der die griechischen Stadtstaaten schwächte und letztlich die makedonische Eroberung Griechenlands ermöglichte.","fr":"431–404 av. J.-C. Un conflit dévastateur entre Athènes et Sparte qui affaiblit les cités grecques, facilitant finalement la conquête macédonienne de la Grèce.","tr":"MÖ 431–404. Atina ile Sparta arasındaki yıkıcı çatışma, Yunan şehir devletlerini zayıflattı ve sonunda Makedonya'nın Yunanistan'ı fethini kolaylaştırdı.","nl":"431–404 v.Chr. Een verwoestend conflict tussen Athene en Sparta dat de Griekse stadstaten verzwakte en uiteindelijk de Macedonische verovering van Griekenland vergemakkelijkte.","ru":"431–404 гг. до н.э. Опустошительный конфликт между Афинами и Спартой, ослабивший греческие полисы и в конечном счёте способствовавший македонскому завоеванию Греции.","zh":"公元前431–404年。雅典与斯巴达之间的毁灭性冲突，削弱了希腊城邦，最终为马其顿征服希腊创造了条件。","pt_BR":"431–404 a.C. Um conflito devastador entre Atenas e Esparta que enfraqueceu as cidades-estado gregas, facilitando por fim a conquista macedônica da Grécia.","pt_PT":"431–404 a.C. Um conflito devastador entre Atenas e Esparta que enfraqueceu as cidades-estado gregas, facilitando por fim a conquista macedónica da Grécia."}},
  { id: 'dc-history-0023', deck_id: 'deck-history', front: 'Alexander the Great', back: '356–323 BCE. Macedonian king who conquered the Persian Empire, Egypt, and reached as far as India, spreading Greek culture across the ancient world.', sort_order: 23 , front_translations: {"es":"Alexandre, el Grande","de":"Alexander der Große","fr":"Alexandre le Grand","tr":"Büyük İskender","nl":"Alexander de Grote","ru":"Александр Великий","zh":"亚历山大大帝","pt_BR":"Alexandre, o Grande","pt_PT":"Alexandre, o Grande"}, back_translations: {"es":"356–323 a.C. Rey macedonio que conquistou el Imperio Persa, el Egito y chegou hasta a Índia, difundindo a cultura grega por el mundo antigo.","de":"356–323 v. Chr. Makedonischer König, der das Persische Reich, Ägypten eroberte und bis nach Indien vordrang und dabei die griechische Kultur in der Alten Welt verbreitete.","fr":"356–323 av. J.-C. Roi macédonien qui conquit l'Empire perse, l'Égypte et atteignit l'Inde, diffusant la culture grecque à travers le monde antique.","tr":"MÖ 356–323. Pers İmparatorluğu'nu, Mısır'ı fetheden ve Hindistan'a kadar ulaşan, antik dünyaya Yunan kültürünü yayan Makedon kral.","nl":"356–323 v.Chr. Macedonische koning die het Perzische Rijk en Egypte veroverde en tot in India reikte, en de Griekse cultuur over de antieke wereld verspreidde.","ru":"356–323 гг. до н.э. Македонский царь, завоевавший Персидскую империю, Египет и дошедший до Индии, распространив греческую культуру по всему древнему миру.","zh":"公元前356–323年。马其顿国王，征服了波斯帝国、埃及，并抵达印度，将希腊文化传播至古代世界各地。","pt_BR":"356–323 a.C. Rei macedônio que conquistou o Império Persa, o Egito e chegou até a Índia, difundindo a cultura grega pelo mundo antigo.","pt_PT":"356–323 a.C. Rei macedónico que conquistou o Império Persa, o Egito e chegou até à Índia, difundindo a cultura grega pelo mundo antigo."}},
  { id: 'dc-history-0024', deck_id: 'deck-history', front: 'Julius Caesar\'s Assassination', back: '44 BCE. Roman dictator Julius Caesar was assassinated by a group of senators on the Ides of March, triggering civil wars that ended the Roman Republic.', sort_order: 24 , front_translations: {"es":"Assassinato de Júlio César","de":"Ermordung Julius Caesars","fr":"Assassinat de Jules César","tr":"Julius Caesar'ın Suikastı","nl":"Moord op Julius Caesar","ru":"Убийство Юлия Цезаря","zh":"尤利乌斯·恺撒遇刺","pt_BR":"Assassinato de Júlio César","pt_PT":"Assassinato de Júlio César"}, back_translations: {"es":"44 a.C. El ditador romano Júlio César fue assassinado por un grupo de senadores en los Idos de Março, desencadeando guerras civis que encerraram a República Romana.","de":"44 v. Chr. Der römische Diktator Julius Caesar wurde an den Iden des März von einer Gruppe Senatoren ermordet, was Bürgerkriege auslöste, die die Römische Republik beendeten.","fr":"44 av. J.-C. Le dictateur romain Jules César fut assassiné par un groupe de sénateurs aux Ides de Mars, déclenchant des guerres civiles qui mirent fin à la République romaine.","tr":"MÖ 44. Roma diktatörü Julius Caesar, Mart Ayı'nın Idus'unda bir grup senatör tarafından suikaste kurban gitti; bu olay Roma Cumhuriyeti'ne son veren iç savaşları tetikledi.","nl":"44 v.Chr. De Romeinse dictator Julius Caesar werd door een groep senatoren op de Ides van maart vermoord, waarmee burgeroorlogen werden ontketend die de Romeinse Republiek beëindigden.","ru":"44 г. до н.э. Римский диктатор Юлий Цезарь был убит группой сенаторов в мартовские иды, что спровоцировало гражданские войны, положившие конец Римской республике.","zh":"公元前44年。罗马独裁者尤利乌斯·恺撒在三月十五日被一群元老院议员刺杀，由此引发的内战终结了罗马共和国。","pt_BR":"44 a.C. O ditador romano Júlio César foi assassinado por um grupo de senadores nos Idos de Março, desencadeando guerras civis que encerraram a República Romana.","pt_PT":"44 a.C. O ditador romano Júlio César foi assassinado por um grupo de senadores nos Idos de Março, desencadeando guerras civis que encerraram a República Romana."}},
  { id: 'dc-history-0025', deck_id: 'deck-history', front: 'Founding of Rome (Traditional)', back: '753 BCE. According to Roman tradition, Romulus founded the city of Rome; the Roman Republic was later established in 509 BCE after the overthrow of the last king.', sort_order: 25 , front_translations: {"es":"Fundación de Roma (Tradicional)","de":"Gründung Roms (Traditionell)","fr":"Fondation de Rome (Tradition)","tr":"Roma'nın Kuruluşu (Geleneksel)","nl":"Stichting van Rome (Traditioneel)","ru":"Основание Рима (традиционная дата)","zh":"罗马的建城（传说）","pt_BR":"Fundação de Roma (Tradicional)","pt_PT":"Fundação de Roma (Tradicional)"}, back_translations: {"es":"753 a.C. Según a tradición romana, Romulo fundou a cidad de Roma; a República Romana fue estabelecida más tarde en 509 a.C. após a derrubada del último rey.","de":"753 v. Chr. Der Überlieferung nach gründete Romulus die Stadt Rom; die Römische Republik wurde später 509 v. Chr. nach dem Sturz des letzten Königs errichtet.","fr":"753 av. J.-C. Selon la tradition romaine, Romulus fonda la ville de Rome ; la République romaine fut plus tard établie en 509 av. J.-C. après le renversement du dernier roi.","tr":"MÖ 753. Roma geleneğine göre Romulus şehri kurdu; Roma Cumhuriyeti ise son kralın devrilmesinin ardından MÖ 509'da kuruldu.","nl":"753 v.Chr. Volgens de Romeinse traditie stichtte Romulus de stad Rome; de Romeinse Republiek werd later gevestigd in 509 v.Chr. na de omverwerping van de laatste koning.","ru":"753 г. до н.э. Согласно римской традиции, Ромул основал город Рим; Римская республика была позднее провозглашена в 509 г. до н.э. после свержения последнего царя.","zh":"公元前753年。根据罗马传统，罗慕路斯建立了罗马城；后来在公元前509年，末代国王被推翻后，罗马共和国宣告成立。","pt_BR":"753 a.C. Segundo a tradição romana, Rômulo fundou a cidade de Roma; a República Romana foi estabelecida mais tarde em 509 a.C. após a derrubada do último rei.","pt_PT":"753 a.C. Segundo a tradição romana, Rómulo fundou a cidade de Roma; a República Romana foi estabelecida mais tarde em 509 a.C. após a deposição do último rei."}},
  { id: 'dc-history-0026', deck_id: 'deck-history', front: 'Battle of Actium', back: '31 BCE. Octavian\'s naval victory over Mark Antony and Cleopatra ended the last challenge to his power, allowing him to become Augustus, the first Roman Emperor.', sort_order: 26 , front_translations: {"es":"Batalla de Ácio","de":"Schlacht bei Actium","fr":"Bataille d'Actium","tr":"Actium Muharebesi","nl":"Slag bij Actium","ru":"Битва при Акции","zh":"亚克兴角战役","pt_BR":"Batalha de Ácio","pt_PT":"Batalha de Ácio"}, back_translations: {"es":"31 a.C. La vitória naval de Otávio sobre Marco Antonio y Cleópatra encerrou el último desafio al su poder, permitiendo-lhe tornar-se Augusto, el primero Emperador Romano.","de":"31 v. Chr. Octavians Seesieg über Marcus Antonius und Kleopatra beendete die letzte Herausforderung seiner Macht und ermöglichte ihm, als Augustus der erste römische Kaiser zu werden.","fr":"31 av. J.-C. La victoire navale d'Octave sur Marc Antoine et Cléopâtre mit fin au dernier défi à son pouvoir, lui permettant de devenir Auguste, le premier empereur romain.","tr":"MÖ 31. Octavianus'ın Marcus Antonius ve Kleopatra'ya karşı kazandığı deniz zaferi, iktidarına yönelik son meydan okumayı sona erdirdi ve onun ilk Roma İmparatoru Augustus olmasını sağladı.","nl":"31 v.Chr. Octavianus' maritieme overwinning op Marcus Antonius en Cleopatra beëindigde de laatste bedreiging voor zijn macht en stelde hem in staat Augustus, de eerste Romeinse keizer, te worden.","ru":"31 г. до н. э. Победа Октавиана в морском сражении над Марком Антонием и Клеопатрой положила конец последнему вызову его власти, позволив ему стать Августом — первым римским императором.","zh":"公元前31年。屋大维在海战中击败马克·安东尼和克娄巴特拉，消除了对其权力的最后挑战，得以成为第一位罗马皇帝奥古斯都。","pt_BR":"31 a.C. A vitória naval de Otávio sobre Marco Antônio e Cleópatra encerrou o último desafio ao seu poder, permitindo-lhe tornar-se Augusto, o primeiro Imperador Romano.","pt_PT":"31 a.C. A vitória naval de Octávio sobre Marco António e Cleópatra pôs fim ao último desafio ao seu poder, permitindo-lhe tornar-se Augusto, o primeiro Imperador Romano."}},
  { id: 'dc-history-0027', deck_id: 'deck-history', front: 'Rise of Islam', back: '610–632 CE. The Prophet Muhammad received divine revelations forming the Quran and founded Islam in Arabia; by 750 CE Muslim rule extended from Spain to Central Asia.', sort_order: 27 , front_translations: {"es":"Ascensão del Islã","de":"Aufstieg des Islams","fr":"Naissance de l'islam","tr":"İslam'ın Yükselişi","nl":"Opkomst van de islam","ru":"Возникновение ислама","zh":"伊斯兰教的兴起","pt_BR":"Ascensão do Islã","pt_PT":"Ascensão do Islão"}, back_translations: {"es":"610–632 d.C. El Profeta Maomé recebeu revelaciones divinas que formaram el Alcorão y fundou el Islã en la Arábia; en 750 d.C., el domínio musulmán se estendia de la Espanha a la Ásia Central.","de":"610–632 n. Chr. Der Prophet Muhammad empfing göttliche Offenbarungen, aus denen der Koran entstand, und gründete den Islam in Arabien; bis 750 n. Chr. erstreckte sich die muslimische Herrschaft von Spanien bis Zentralasien.","fr":"610–632 apr. J.-C. Le prophète Muhammad reçut des révélations divines formant le Coran et fonda l'islam en Arabie ; en 750 apr. J.-C., la domination musulmane s'étendait de l'Espagne à l'Asie centrale.","tr":"610–632. Peygamber Muhammed, Kur'an'ı oluşturan ilahi vahiyleri aldı ve Arabistan'da İslam'ı kurdu; 750 yılına kadar Müslüman egemenliği İspanya'dan Orta Asya'ya uzandı.","nl":"610–632 n.Chr. De profeet Mohammed ontving goddelijke openbaringen die de Koran vormden en stichtte de islam in Arabië; tegen 750 n.Chr. strekte de moslimheerschappij zich uit van Spanje tot Centraal-Azië.","ru":"610–632 г. н. э. Пророк Мухаммад получил Божественные откровения, составившие Коран, и основал ислам в Аравии; к 750 г. н. э. мусульманское владычество распространилось от Испании до Центральной Азии.","zh":"公元610–632年。先知穆罕默德接受神圣启示，形成《古兰经》，并在阿拉伯半岛创立伊斯兰教；至公元750年，穆斯林统治范围从西班牙延伸至中亚。","pt_BR":"610–632 d.C. O Profeta Maomé recebeu revelações divinas que formaram o Alcorão e fundou o Islã na Arábia; em 750 d.C., o domínio muçulmano se estendia da Espanha à Ásia Central.","pt_PT":"610–632 d.C. O Profeta Maomé recebeu revelações divinas que formaram o Alcorão e fundou o Islão na Arábia; em 750 d.C., o domínio muçulmano estendia-se da Espanha à Ásia Central."}},
  { id: 'dc-history-0028', deck_id: 'deck-history', front: 'Crusades', back: '1096–1291. A series of religious wars launched by European Christians to reclaim the Holy Land from Muslim rule; they had lasting effects on relations between Europe and the Middle East.', sort_order: 28 , front_translations: {"es":"Cruzadas","de":"Kreuzzüge","fr":"Croisades","tr":"Haçlı Seferleri","nl":"Kruistochten","ru":"Крестовые походы","zh":"十字军东征","pt_BR":"Cruzadas","pt_PT":"Cruzadas"}, back_translations: {"es":"1096–1291. Una série de guerras religiosas lançadas por cristianos europeus para recuperar a Tierra Santa del domínio musulmán; tiveram efectos duradouros en las relaciones entre a Europa y el Oriente Médio.","de":"1096–1291. Eine Reihe von Religionskriegen europäischer Christen zur Rückeroberung des Heiligen Landes von der muslimischen Herrschaft; sie hatten dauerhafte Auswirkungen auf die Beziehungen zwischen Europa und dem Nahen Osten.","fr":"1096–1291. Une série de guerres religieuses menées par des chrétiens européens pour reprendre la Terre sainte à la domination musulmane ; elles ont eu des effets durables sur les relations entre l'Europe et le Moyen-Orient.","tr":"1096–1291. Kutsal Toprakları Müslüman yönetiminden geri almak için Avrupalı Hristiyanlar tarafından başlatılan bir dizi din savaşı; bu seferler Avrupa ile Orta Doğu arasındaki ilişkiler üzerinde kalıcı etkiler bıraktı.","nl":"1096–1291. Een reeks religieuze oorlogen van Europese christenen om het Heilige Land te heroveren op moslimheerschappij; ze hadden blijvende gevolgen voor de betrekkingen tussen Europa en het Midden-Oosten.","ru":"1096–1291. Серия религиозных войн, развязанных европейскими христианами для отвоевания Святой Земли у мусульман; крестовые походы оказали долгосрочное влияние на отношения между Европой и Ближним Востоком.","zh":"1096–1291年。欧洲基督徒发动的一系列宗教战争，旨在从穆斯林手中夺回圣地；这些战争对欧洲与中东的关系产生了深远影响。","pt_BR":"1096–1291. Uma série de guerras religiosas lançadas por cristãos europeus para recuperar a Terra Santa do domínio muçulmano; tiveram efeitos duradouros nas relações entre a Europa e o Oriente Médio.","pt_PT":"1096–1291. Uma série de guerras religiosas lançadas por cristãos europeus para recuperar a Terra Santa do domínio muçulmano; tiveram efeitos duradouros nas relações entre a Europa e o Médio Oriente."}},
  { id: 'dc-history-0029', deck_id: 'deck-history', front: 'Mongol Empire', back: '1206–1368. Founded by Genghis Khan, it became the largest contiguous land empire in history, stretching from East Asia to Eastern Europe and facilitating trade along the Silk Road.', sort_order: 29 , front_translations: {"es":"Imperio Mongol","de":"Mongolisches Reich","fr":"Empire mongol","tr":"Moğol İmparatorluğu","nl":"Mongoolse Rijk","ru":"Монгольская империя","zh":"蒙古帝国","pt_BR":"Império Mongol","pt_PT":"Império Mongol"}, back_translations: {"es":"1206–1368. Fundado por Gengis Khan, tornou-se el mayor imperio terrestre contiguo de la historia, estendendo-se de la Ásia Oriental a la Europa Oriental y facilitando el comercio a lo ancho de la Rota de la Seda.","de":"1206–1368. Von Dschingis Khan gegründet, war es das größte zusammenhängende Landimperium der Geschichte, das sich von Ostasien bis Osteuropa erstreckte und den Handel auf der Seidenstraße förderte.","fr":"1206–1368. Fondé par Gengis Khan, il fut le plus grand empire terrestre contigu de l'histoire, s'étendant de l'Asie de l'Est à l'Europe orientale et facilitant le commerce le long de la Route de la soie.","tr":"1206–1368. Cengiz Han tarafından kurulan bu imparatorluk, Doğu Asya'dan Doğu Avrupa'ya uzanan ve İpek Yolu boyunca ticareti kolaylaştıran tarihin en büyük kara imparatorluğu oldu.","nl":"1206–1368. Gesticht door Genghis Khan, werd het het grootste aaneengesloten landimperium in de geschiedenis, dat zich uitstrekte van Oost-Azië tot Oost-Europa en de handel langs de Zijderoute bevorderde.","ru":"1206–1368. Основанная Чингисханом, Монгольская империя стала крупнейшей в истории непрерывной сухопутной империей, простиравшейся от Восточной Азии до Восточной Европы и способствовавшей торговле по Шёлковому пути.","zh":"1206–1368年。由成吉思汗建立，是历史上最大的连续陆地帝国，从东亚延伸至东欧，并促进了丝绸之路上的贸易往来。","pt_BR":"1206–1368. Fundado por Gengis Khan, tornou-se o maior império terrestre contíguo da história, estendendo-se da Ásia Oriental à Europa Oriental e facilitando o comércio ao longo da Rota da Seda.","pt_PT":"1206–1368. Fundado por Gengis Khan, tornou-se o maior império terrestre contíguo da história, estendendo-se da Ásia Oriental à Europa Oriental e facilitando o comércio ao longo da Rota da Seda."}},
  { id: 'dc-history-0030', deck_id: 'deck-history', front: 'Hundred Years\' War', back: '1337–1453. A series of conflicts between England and France over the French throne; Joan of Arc\'s military leadership helped turn the tide in France\'s favor.', sort_order: 30 , front_translations: {"es":"Guerra de los Cien Anos","de":"Hundertjähriger Krieg","fr":"Guerre de Cent Ans","tr":"Yüzyıl Savaşları","nl":"Honderdjarige Oorlog","ru":"Столетняя война","zh":"百年战争","pt_BR":"Guerra dos Cem Anos","pt_PT":"Guerra dos Cem Anos"}, back_translations: {"es":"1337–1453. Una série de conflitos entre a Inglaterra y a França por el trono frances; a liderazgo militar de Joana d'Arc ajudou a reverter a situación en favor de la França.","de":"1337–1453. Eine Reihe von Konflikten zwischen England und Frankreich um den französischen Thron; Jeanne d'Arcs militärische Führung half, das Blatt zugunsten Frankreichs zu wenden.","fr":"1337–1453. Une série de conflits entre l'Angleterre et la France pour le trône de France ; le leadership militaire de Jeanne d'Arc aida à renverser la situation en faveur de la France.","tr":"1337–1453. Fransa tahtı için İngiltere ile Fransa arasında yaşanan bir dizi çatışma; Jeanne d'Arc'ın askeri liderliği, dengenin Fransa lehine dönmesine yardımcı oldu.","nl":"1337–1453. Een reeks conflicten tussen Engeland en Frankrijk over de Franse troon; het militaire leiderschap van Jeanne d'Arc hielp het tij te keren in het voordeel van Frankrijk.","ru":"1337–1453. Серия конфликтов между Англией и Францией за французский трон; военное руководство Жанны д'Арк помогло переломить ход войны в пользу Франции.","zh":"1337–1453年。英法两国围绕法国王位展开的一系列冲突；贞德的军事领导力帮助局势转向有利于法国的方向。","pt_BR":"1337–1453. Uma série de conflitos entre a Inglaterra e a França pelo trono francês; a liderança militar de Joana d'Arc ajudou a reverter a situação em favor da França.","pt_PT":"1337–1453. Uma série de conflitos entre a Inglaterra e a França pelo trono francês; a liderança militar de Joana d'Arc ajudou a reverter a situação a favor de França."}},
  { id: 'dc-history-0031', deck_id: 'deck-history', front: 'Joan of Arc', back: '1412–1431. A French peasant girl who claimed divine guidance and led French forces to crucial victories during the Hundred Years\' War; she was later burned at the stake for heresy.', sort_order: 31 , front_translations: {"es":"Joana d'Arc","de":"Jeanne d'Arc","fr":"Jeanne d'Arc","tr":"Jeanne d'Arc","nl":"Jeanne d'Arc","ru":"Жанна д'Арк","zh":"圣女贞德","pt_BR":"Joana d'Arc","pt_PT":"Joana d'Arc"}, back_translations: {"es":"1412–1431. Una camponesa francesa que afirmava recibir orientación divina y liderou las fuerzas francesas a vitórias cruciais durante a Guerra de los Cien Anos; posteriormente fue queimada en la foguera por heresia.","de":"1412–1431. Ein französisches Bauermmädchen, das göttliche Führung beanspruchte und die französischen Truppen im Hundertjährigen Krieg zu entscheidenden Siegen führte; sie wurde später als Ketzerin auf dem Scheiterhaufen verbrannt.","fr":"1412–1431. Une paysanne française qui se réclamait d'une guidance divine et conduisit les forces françaises à des victoires cruciales pendant la guerre de Cent Ans ; elle fut ensuite brûlée vive pour hérésie.","tr":"1412–1431. İlahi rehberlik aldığını iddia eden ve Yüzyıl Savaşları sırasında Fransız kuvvetlerini kritik zaferlere taşıyan bir Fransız köylü kızı; daha sonra sapkınlıktan dolayı yakılarak idam edildi.","nl":"1412–1431. Een Frans boerenmeisje dat goddelijke leiding claimde en de Franse troepen tijdens de Honderdjarige Oorlog naar cruciale overwinningen leidde; ze werd later wegens ketterij verbrand op de brandstapel.","ru":"1412–1431. Французская крестьянская девушка, утверждавшая, что получает Божественное руководство; она привела французские войска к решающим победам во время Столетней войны и впоследствии была сожжена на костре как еретичка.","zh":"1412–1431年。一位声称受到神灵指引的法国农家女，在百年战争中率领法军取得了关键胜利；她后来以异端罪被处以火刑。","pt_BR":"1412–1431. Uma camponesa francesa que afirmava receber orientação divina e liderou as forças francesas a vitórias cruciais durante a Guerra dos Cem Anos; posteriormente foi queimada na fogueira por heresia.","pt_PT":"1412–1431. Uma camponesa francesa que afirmava receber orientação divina e conduziu as forças francesas a vitórias cruciais durante a Guerra dos Cem Anos; foi posteriormente queimada na fogueira por heresia."}},
  { id: 'dc-history-0032', deck_id: 'deck-history', front: 'The Renaissance', back: '14th–17th centuries. A cultural and intellectual movement beginning in Italy that revived interest in classical antiquity, producing breakthroughs in art, science, and humanist philosophy.', sort_order: 32 , front_translations: {"es":"El Renacimiento","de":"Die Renaissance","fr":"La Renaissance","tr":"Rönesans","nl":"De Renaissance","ru":"Эпоха Возрождения","zh":"文艺复兴","pt_BR":"O Renascimento","pt_PT":"O Renascimento"}, back_translations: {"es":"Siglos XIV–XVII. Un movimiento cultural y intelectual que começou en la Itália y reviveu el interesse por la Antiguidad clássica, produciendo avanços en las artes, en las ciencias y en la filosofia humanista.","de":"14.–17. Jahrhundert. Eine kulturelle und intellektuelle Bewegung, die in Italien begann und das Interesse an der klassischen Antike wiederbelebte; sie brachte Durchbrüche in Kunst, Wissenschaft und humanistischer Philosophie hervor.","fr":"XIVe–XVIIe siècles. Un mouvement culturel et intellectuel né en Italie qui raviva l'intérêt pour l'Antiquité classique, produisant des percées en art, en science et en philosophie humaniste.","tr":"14.–17. yüzyıllar. İtalya'da başlayan ve klasik antikiteye olan ilgiyi yeniden canlandıran kültürel ve entelektüel bir hareket; sanat, bilim ve hümanist felsefede atılımlara yol açtı.","nl":"14e–17e eeuw. Een culturele en intellectuele beweging die begon in Italië en de interesse in de klassieke oudheid nieuw leven inblies; ze produceerde doorbraken in kunst, wetenschap en humanistische filosofie.","ru":"XIV–XVII века. Культурное и интеллектуальное движение, зародившееся в Италии, возродившее интерес к классической античности и давшее миру прорывы в области искусства, науки и гуманистической философии.","zh":"14至17世纪。一场始于意大利的文化和思想运动，复兴了对古典时代的兴趣，在艺术、科学和人文主义哲学方面取得了重大突破。","pt_BR":"Séculos XIV–XVII. Um movimento cultural e intelectual que começou na Itália e reviveu o interesse pela Antiguidade clássica, produzindo avanços nas artes, nas ciências e na filosofia humanista.","pt_PT":"Séculos XIV–XVII. Um movimento cultural e intelectual que começou em Itália e reviveu o interesse pela Antiguidade clássica, produzindo avanços nas artes, nas ciências e na filosofia humanista."}},
  { id: 'dc-history-0033', deck_id: 'deck-history', front: 'Leonardo da Vinci', back: '1452–1519. The quintessential Renaissance man; painter of the Mona Lisa and The Last Supper, and a visionary scientist whose notebooks contained designs centuries ahead of their time.', sort_order: 33 , front_translations: {"es":"Leonardo de la Vinci","de":"Leonardo da Vinci","fr":"Léonard de Vinci","tr":"Leonardo da Vinci","nl":"Leonardo da Vinci","ru":"Леонардо да Винчи","zh":"列奥纳多·达·芬奇","pt_BR":"Leonardo da Vinci","pt_PT":"Leonardo da Vinci"}, back_translations: {"es":"1452–1519. El arquétipo del hombre del Renacimiento; pintor de la Mona Lisa y de la Última Ceia, y un cientista visionário cujos cadernos continham projetos siglos a la frente de su tiempo.","de":"1452–1519. Der Inbegriff des Renaissancemenschen; Maler der Mona Lisa und des Letzten Abendmahls und visionärer Wissenschaftler, dessen Notizbücher Entwürfe enthielten, die ihrer Zeit um Jahrhunderte voraus waren.","fr":"1452–1519. Le génie universel de la Renaissance par excellence ; peintre de la Joconde et de La Cène, et scientifique visionnaire dont les carnets contenaient des dessins en avance de plusieurs siècles sur leur temps.","tr":"1452–1519. Rönesans insanının mükemmel örneği; Mona Lisa ve Son Akşam Yemeği'nin ressamı ve not defterlerinde yüzyıllar ötesindeki tasarımlar barındıran vizyoner bir bilim insanı.","nl":"1452–1519. De ultieme Renaissance-mens; schilder van de Mona Lisa en Het Laatste Avondmaal, en een visionaire wetenschapper wiens notitieboeken ontwerpen bevatten die eeuwen voor hun tijd waren.","ru":"1452–1519. Воплощение человека эпохи Возрождения; художник, создавший «Мону Лизу» и «Тайную вечерю», и провидец-учёный, чьи записные книжки содержали разработки, опередившие время на столетия.","zh":"1452–1519年。文艺复兴全才的典范；《蒙娜丽莎》和《最后的晚餐》的画家，同时也是一位富有远见的科学家，其笔记本中的设计超前了几个世纪。","pt_BR":"1452–1519. O arquétipo do homem do Renascimento; pintor da Mona Lisa e da Última Ceia, e um cientista visionário cujos cadernos continham projetos séculos à frente de seu tempo.","pt_PT":"1452–1519. O arquétipo do homem do Renascimento; pintor da Mona Lisa e da Última Ceia, e um cientista visionário cujos cadernos continham projetos séculos à frente do seu tempo."}},
  { id: 'dc-history-0034', deck_id: 'deck-history', front: 'Galileo Galilei', back: '1564–1642. Italian astronomer who championed heliocentrism and used a telescope to observe Jupiter\'s moons; his conflict with the Church marked a turning point in the science-religion relationship.', sort_order: 34 , front_translations: {"es":"Galileu Galilei","de":"Galileo Galilei","fr":"Galilée","tr":"Galileo Galilei","nl":"Galileo Galilei","ru":"Галилео Галилей","zh":"伽利略·伽利雷","pt_BR":"Galileu Galilei","pt_PT":"Galileu Galilei"}, back_translations: {"es":"1564–1642. Astronomo italiano que defendeu el heliocentrismo y usou un telescópio para observar las luas de Júpiter; su conflito con a Igreja marcou un punto de virada en la relación entre ciencia y religión.","de":"1564–1642. Italienischer Astronom, der den Heliozentrismus verteidigte und ein Teleskop zur Beobachtung der Jupitermonde einsetzte; sein Konflikt mit der Kirche markierte einen Wendepunkt im Verhältnis zwischen Wissenschaft und Religion.","fr":"1564–1642. Astronome italien qui défendit l'héliocentrisme et utilisa un télescope pour observer les lunes de Jupiter ; son conflit avec l'Église marqua un tournant dans les relations entre science et religion.","tr":"1564–1642. Heliosentrizmi savunan ve Jüpiter'in uydularını gözlemlemek için teleskop kullanan İtalyan astronom; Kilise ile yaşadığı çatışma, bilim-din ilişkisinde bir dönüm noktası oldu.","nl":"1564–1642. Italiaanse astronoom die het heliocentrisme verdedigde en een telescoop gebruikte om de manen van Jupiter te observeren; zijn conflict met de Kerk markeerde een keerpunt in de verhouding tussen wetenschap en religie.","ru":"1564–1642. Итальянский астроном, отстаивавший гелиоцентризм и наблюдавший спутники Юпитера в телескоп; его конфликт с Церковью стал поворотным моментом в отношениях между наукой и религией.","zh":"1564–1642年。意大利天文学家，倡导日心说并使用望远镜观测木星卫星；他与教会的冲突标志着科学与宗教关系的转折点。","pt_BR":"1564–1642. Astrônomo italiano que defendeu o heliocentrismo e usou um telescópio para observar as luas de Júpiter; seu conflito com a Igreja marcou um ponto de virada na relação entre ciência e religião.","pt_PT":"1564–1642. Astrónomo italiano que defendeu o heliocentrismo e usou um telescópio para observar as luas de Júpiter; o seu conflito com a Igreja marcou um ponto de viragem na relação entre ciência e religião."}},
  { id: 'dc-history-0035', deck_id: 'deck-history', front: 'Copernican Revolution', back: '1543. Nicolaus Copernicus published his heliocentric model of the solar system, challenging the church-backed geocentric view and transforming astronomy.', sort_order: 35 , front_translations: {"es":"Revolución Copernicana","de":"Kopernikanische Revolution","fr":"Révolution copernicienne","tr":"Kopernik Devrimi","nl":"Copernicaanse Revolutie","ru":"Коперниканский переворот","zh":"哥白尼革命","pt_BR":"Revolução Copernicana","pt_PT":"Revolução Copernicana"}, back_translations: {"es":"1543. Nicolau Copérnico publicou su modelo heliocentrico del sistema solar, desafiando a visão geocentrica apoiada por la Igreja y transformando a astronomia.","de":"1543. Nikolaus Kopernikus veröffentlichte sein heliozentrisches Modell des Sonnensystems und stellte damit das von der Kirche unterstützte geozentrische Weltbild in Frage, was die Astronomie grundlegend veränderte.","fr":"1543. Nicolas Copernic publia son modèle héliocentrique du système solaire, remettant en cause la vision géocentrique soutenue par l'Église et transformant l'astronomie.","tr":"1543. Nikolaus Kopernik, güneş sisteminin güneş merkezli modelini yayımladı; kilise destekli dünya merkezli görüşü sorgulayarak astronomiye dönüştürdü.","nl":"1543. Nicolaus Copernicus publiceerde zijn heliocentrisch model van het zonnestelsel, dat het door de kerk gesteunde geocentrische wereldbeeld uitdaagde en de astronomie transformeerde.","ru":"1543. Николай Коперник опубликовал гелиоцентрическую модель Солнечной системы, бросив вызов геоцентрическому взгляду, поддерживаемому Церковью, и преобразовав астрономию.","zh":"1543年。尼古拉·哥白尼发表了太阳系日心说模型，挑战了教会支持的地心说，从根本上改变了天文学。","pt_BR":"1543. Nicolau Copérnico publicou seu modelo heliocêntrico do sistema solar, desafiando a visão geocêntrica apoiada pela Igreja e transformando a astronomia.","pt_PT":"1543. Nicolau Copérnico publicou o seu modelo heliocêntrico do sistema solar, desafiando a visão geocêntrica apoiada pela Igreja e transformando a astronomia."}},
  { id: 'dc-history-0036', deck_id: 'deck-history', front: 'Gutenberg\'s Printing Press', back: 'c. 1440. Johannes Gutenberg\'s movable-type printing press revolutionized the spread of information, making books affordable and accelerating the Renaissance, Reformation, and scientific revolution.', sort_order: 36 , front_translations: {"es":"La Prensa de Gutenberg","de":"Gutenbergs Druckerpresse","fr":"L'imprimerie de Gutenberg","tr":"Gutenberg'in Matbaası","nl":"Gutenbergs drukpers","ru":"Печатный станок Гутенберга","zh":"古腾堡印刷机","pt_BR":"A Prensa de Gutenberg","pt_PT":"A Prensa de Gutenberg"}, back_translations: {"es":"Por volta de 1440. La prensa de tipos móveis de Johannes Gutenberg revolucionou a difusão de la información, tornando los livros acessibles y acelerando el Renacimiento, a Reforma y a revolución científica.","de":"Um 1440. Johannes Gutenbergs Druckerpresse mit beweglichen Lettern revolutionierte die Verbreitung von Informationen, machte Bücher erschwinglich und beschleunigte Renaissance, Reformation und wissenschaftliche Revolution.","fr":"Vers 1440. La presse à caractères mobiles de Johannes Gutenberg révolutionna la diffusion de l'information, rendant les livres abordables et accélérant la Renaissance, la Réforme et la révolution scientifique.","tr":"Yaklaşık 1440. Johannes Gutenberg'in hareketli harfli baskı makinesi bilginin yayılmasını devrimleştirdi; kitapları uygun fiyatlı hale getirerek Rönesans, Reform ve bilimsel devrimini hızlandırdı.","nl":"Rond 1440. Johannes Gutenbergs drukpers met losse letters revolutioneerde de verspreiding van informatie, maakte boeken betaalbaar en versnelde de Renaissance, de Reformatie en de wetenschappelijke revolutie.","ru":"Ок. 1440. Печатный станок с подвижными литерами Иоганна Гутенберга произвёл революцию в распространении информации, сделав книги доступными и ускорив эпоху Возрождения, Реформацию и научную революцию.","zh":"约1440年。约翰内斯·古腾堡的活字印刷机彻底革新了信息传播方式，使书籍变得平价，并加速了文艺复兴、宗教改革和科学革命的进程。","pt_BR":"Por volta de 1440. A prensa de tipos móveis de Johannes Gutenberg revolucionou a difusão da informação, tornando os livros acessíveis e acelerando o Renascimento, a Reforma e a revolução científica.","pt_PT":"Por volta de 1440. A prensa de tipos móveis de Johannes Gutenberg revolucionou a difusão da informação, tornando os livros acessíveis e acelerando o Renascimento, a Reforma e a revolução científica."}},
  { id: 'dc-history-0037', deck_id: 'deck-history', front: 'Vasco da Gama', back: '1497–1499. Portuguese explorer who completed the first sea voyage from Europe to India around the Cape of Good Hope, opening a direct trade route to Asia.', sort_order: 37 , front_translations: {"es":"Vasco de la Gama","de":"Vasco da Gama","fr":"Vasco de Gama","tr":"Vasco da Gama","nl":"Vasco da Gama","ru":"Васко да Гама","zh":"瓦斯科·达·伽马","pt_BR":"Vasco da Gama","pt_PT":"Vasco da Gama"}, back_translations: {"es":"1497–1499. Explorador portugues que completou a primera viaje marítima de la Europa a la Índia, contornando el Cabo de la Boa Esperança, abrindo una rota comercial direta para a Ásia.","de":"1497–1499. Portugiesischer Entdecker, der die erste Seereise von Europa nach Indien um das Kap der Guten Hoffnung vollendete und damit eine direkte Handelsroute nach Asien eröffnete.","fr":"1497–1499. L'explorateur portugais qui effectua le premier voyage maritime de l'Europe vers l'Inde en contournant le cap de Bonne-Espérance, ouvrant une route commerciale directe vers l'Asie.","tr":"1497–1499. Ümit Burnu'nu dolaşarak Avrupa'dan Hindistan'a ilk deniz yolculuğunu tamamlayan Portekizli kaşif; Asya'ya doğrudan bir ticaret yolu açtı.","nl":"1497–1499. Portugese ontdekkingsreiziger die de eerste zeevoyage van Europa naar India rondom Kaap de Goede Hoop voltooide en zo een directe handelsroute naar Azië opende.","ru":"1497–1499. Португальский мореплаватель, совершивший первое морское путешествие из Европы в Индию вокруг мыса Доброй Надежды, открыв прямой торговый маршрут в Азию.","zh":"1497–1499年。葡萄牙探险家，完成了绕好望角从欧洲到印度的首次海上航行，开辟了通往亚洲的直接贸易航线。","pt_BR":"1497–1499. Explorador português que completou a primeira viagem marítima da Europa à Índia, contornando o Cabo da Boa Esperança, abrindo uma rota comercial direta para a Ásia.","pt_PT":"1497–1499. Explorador português que completou a primeira viagem marítima da Europa à Índia, contornando o Cabo da Boa Esperança, abrindo uma rota comercial direta para a Ásia."}},
  { id: 'dc-history-0038', deck_id: 'deck-history', front: 'Ferdinand Magellan', back: '1519–1522. Led the first circumnavigation of the globe, proving Earth\'s spherical shape; he was killed in the Philippines but his crew completed the journey.', sort_order: 38 , front_translations: {"es":"Fernão de Magalhães","de":"Ferdinand Magellan","fr":"Ferdinand Magellan","tr":"Ferdinand Magellan","nl":"Ferdinand Magellaan","ru":"Фернан Магеллан","zh":"费迪南德·麦哲伦","pt_BR":"Fernão de Magalhães","pt_PT":"Fernão de Magalhães"}, back_translations: {"es":"1519–1522. Liderou a primera circum-navegación del globo, provando a forma esférica de la Tierra; fue morto en las Filipinas, pero su tripulación completou a viaje.","de":"1519–1522. Führte die erste Weltumsegelung an und bewies damit die Kugelgestalt der Erde; er wurde auf den Philippinen getötet, aber seine Crew vollendete die Reise.","fr":"1519–1522. Dirigea la première circumnavigation du globe, prouvant la forme sphérique de la Terre ; il fut tué aux Philippines mais son équipage termina le voyage.","tr":"1519–1522. Dünyanın küresel şeklini kanıtlayarak kürenin ilk kez dolaşılmasına öncülük etti; Filipinler'de hayatını kaybetti, ancak mürettebatı yolculuğu tamamladı.","nl":"1519–1522. Leidde de eerste omzeiling van de aarde, waarmee hij de bolvorm bewees; hij werd gedood op de Filippijnen maar zijn bemanning voltooide de reis.","ru":"1519–1522. Возглавил первое кругосветное плавание, доказав шарообразность Земли; был убит на Филиппинах, однако его команда завершила путешествие.","zh":"1519–1522年。领导了首次环球航行，证明了地球是球形的；他在菲律宾遇难，但其船员完成了这次航行。","pt_BR":"1519–1522. Liderou a primeira circum-navegação do globo, provando a forma esférica da Terra; foi morto nas Filipinas, mas sua tripulação completou a viagem.","pt_PT":"1519–1522. Liderou a primeira circum-navegação do globo, provando a forma esférica da Terra; foi morto nas Filipinas, mas a sua tripulação completou a viagem."}},
  { id: 'dc-history-0039', deck_id: 'deck-history', front: 'Spanish Conquest of the Aztec Empire', back: '1519–1521. Hernán Cortés and his conquistadors overthrew the Aztec Empire, aided by smallpox epidemics and indigenous allies, establishing Spanish colonial rule over Mexico.', sort_order: 39 , front_translations: {"es":"Conquista Espanhola del Imperio Asteca","de":"Spanische Eroberung des Aztekenreiches","fr":"Conquête espagnole de l'Empire aztèque","tr":"Aztec İmparatorluğu'nun İspanyollar Tarafından Fethi","nl":"Spaanse verovering van het Azteekse Rijk","ru":"Испанское завоевание Империи ацтеков","zh":"西班牙征服阿兹特克帝国","pt_BR":"Conquista Espanhola do Império Asteca","pt_PT":"Conquista Espanhola do Império Asteca"}, back_translations: {"es":"1519–1521. Hernán Cortés y sus conquistadores derrubaram el Imperio Asteca, auxiliados por epidemias de varíola y aliados indígenas, estableciendo el domínio colonial espanhol sobre el México.","de":"1519–1521. Hernán Cortés und seine Konquistadoren stürzten das Aztekenreich mithilfe von Pockenepidemien und indigenen Verbündeten und etablierten die spanische Kolonialherrschaft über Mexiko.","fr":"1519–1521. Hernán Cortés et ses conquistadors renversèrent l'Empire aztèque, aidés par des épidémies de variole et des alliés indigènes, établissant la domination coloniale espagnole sur le Mexique.","tr":"1519–1521. Hernán Cortés ve conquistadorları, çiçek hastalığı salgınları ve yerli müttefiklerin yardımıyla Aztec İmparatorluğu'nu devirdi ve Meksika üzerinde İspanya'nın sömürge yönetimini kurdu.","nl":"1519–1521. Hernán Cortés en zijn conquistadores veroverden het Azteekse Rijk, geholpen door pokkenepidemieën en inheemse bondgenoten, en vestigden Spaans koloniaal bestuur over Mexico.","ru":"1519–1521. Эрнан Кортес и его конкистадоры свергли Империю ацтеков при помощи эпидемий оспы и местных союзников, установив испанское колониальное господство над Мексикой.","zh":"1519–1521年。埃尔南·科尔特斯及其征服者借助天花疫情和土著盟友推翻了阿兹特克帝国，在墨西哥建立了西班牙殖民统治。","pt_BR":"1519–1521. Hernán Cortés e seus conquistadores derrubaram o Império Asteca, auxiliados por epidemias de varíola e aliados indígenas, estabelecendo o domínio colonial espanhol sobre o México.","pt_PT":"1519–1521. Hernán Cortés e os seus conquistadores derrubaram o Império Asteca, auxiliados por epidemias de varíola e aliados indígenas, estabelecendo o domínio colonial espanhol sobre o México."}},
  { id: 'dc-history-0040', deck_id: 'deck-history', front: 'Transatlantic Slave Trade', back: '16th–19th centuries. The forced transportation of approximately 12–15 million Africans to the Americas; it had devastating effects on African societies and shaped the modern world\'s demographics.', sort_order: 40 , front_translations: {"es":"Tráfico Transatlantico de Esclavos","de":"Transatlantischer Sklavenhandel","fr":"Traite transatlantique des esclaves","tr":"Transatlantik Köle Ticareti","nl":"Transatlantische slavenhandel","ru":"Трансатлантическая работорговля","zh":"跨大西洋奴隶贸易","pt_BR":"Tráfico Transatlântico de Escravos","pt_PT":"Tráfico Transatlântico de Escravos"}, back_translations: {"es":"Siglos XVI–XIX. El transporte forçado de aproximadamente 12–15 milhões de africanos para las Américas; teve efectos devastadores sobre las sociedades africanas y moldou a demografia del mundo moderno.","de":"16.–19. Jahrhundert. Der erzwungene Transport von etwa 12–15 Millionen Afrikanern nach Amerika; er hatte verheerende Auswirkungen auf afrikanische Gesellschaften und prägte die Bevölkerungsstruktur der modernen Welt.","fr":"XVIe–XIXe siècles. Le transport forcé d'environ 12 à 15 millions d'Africains vers les Amériques ; il eut des effets dévastateurs sur les sociétés africaines et façonna la démographie du monde moderne.","tr":"16.–19. yüzyıllar. Yaklaşık 12–15 milyon Afrikalının Amerika'ya zorla taşınması; Afrika toplumları üzerinde yıkıcı etkiler bıraktı ve modern dünyanın demografik yapısını şekillendirdi.","nl":"16e–19e eeuw. Het gedwongen transport van ongeveer 12–15 miljoen Afrikanen naar de Amerika's; het had verwoestende gevolgen voor Afrikaanse samenlevingen en vormde de moderne werelddemografie.","ru":"XVI–XIX века. Принудительное перемещение около 12–15 миллионов африканцев в Америку; оно опустошило африканские общества и определило демографический облик современного мира.","zh":"16至19世纪。约1200至1500万非洲人被强制运往美洲；这对非洲社会造成了毁灭性影响，并塑造了现代世界的人口格局。","pt_BR":"Séculos XVI–XIX. O transporte forçado de aproximadamente 12–15 milhões de africanos para as Américas; teve efeitos devastadores sobre as sociedades africanas e moldou a demografia do mundo moderno.","pt_PT":"Séculos XVI–XIX. O transporte forçado de aproximadamente 12–15 milhões de africanos para as Américas; teve efeitos devastadores sobre as sociedades africanas e moldou a demografia do mundo moderno."}},
  { id: 'dc-history-0041', deck_id: 'deck-history', front: 'English Civil War', back: '1642–1651. A conflict between Royalists and Parliamentarians ending in the execution of King Charles I and establishing parliamentary supremacy in England.', sort_order: 41 , front_translations: {"es":"Guerra Civil Inglesa","de":"Englischer Bürgerkrieg","fr":"Guerre civile anglaise","tr":"İngiliz İç Savaşı","nl":"Engelse Burgeroorlog","ru":"Английская гражданская война","zh":"英国内战","pt_BR":"Guerra Civil Inglesa","pt_PT":"Guerra Civil Inglesa"}, back_translations: {"es":"1642–1651. Un conflito entre Realistas y Parlamentaristas que terminou con a execución del Rey Carlos I y el estabelecimento de la supremacia parlamentar en la Inglaterra.","de":"1642–1651. Ein Konflikt zwischen Royalisten und Parlamentariern, der mit der Hinrichtung von König Karl I. endete und die parlamentarische Vorherrschaft in England begründete.","fr":"1642–1651. Un conflit entre les Royalistes et les Parlementaires qui s'acheva par l'exécution du roi Charles Ier et l'établissement de la suprématie parlementaire en Angleterre.","tr":"1642–1651. Kraliyet taraftarları ile Parlamentocular arasındaki çatışma, Kral I. Charles'ın idam edilmesiyle sona erdi ve İngiltere'de parlamenter üstünlüğü tesis etti.","nl":"1642–1651. Een conflict tussen Royalisten en Parlementariërs dat eindigde met de executie van Koning Karel I en de parlementaire suprematie in Engeland vestigde.","ru":"1642–1651. Конфликт между роялистами и парламентариями, завершившийся казнью короля Карла I и установлением парламентского верховенства в Англии.","zh":"1642–1651年。保王党与议会派之间的冲突，最终以国王查理一世被处决告终，确立了英国的议会至上原则。","pt_BR":"1642–1651. Um conflito entre Realistas e Parlamentaristas que terminou com a execução do Rei Carlos I e o estabelecimento da supremacia parlamentar na Inglaterra.","pt_PT":"1642–1651. Um conflito entre Realistas e Parlamentaristas que terminou com a execução do Rei Carlos I e o estabelecimento da supremacia parlamentar em Inglaterra."}},
  { id: 'dc-history-0042', deck_id: 'deck-history', front: 'Glorious Revolution', back: '1688. The overthrow of King James II of England and the installation of William III and Mary II, establishing a constitutional monarchy and parliamentary supremacy.', sort_order: 42 , front_translations: {"es":"Revolución Gloriosa","de":"Glorreiche Revolution","fr":"Glorieuse Révolution","tr":"Şanlı Devrim","nl":"Glorieuze Revolutie","ru":"Славная революция","zh":"光荣革命","pt_BR":"Revolução Gloriosa","pt_PT":"Revolução Gloriosa"}, back_translations: {"es":"1688. La derrubada del Rey Jaime II de la Inglaterra y a instalación de Guilherme III y Maria II estabeleceram una monarquía constitucional y a supremacia parlamentar.","de":"1688. Der Sturz König Jakobs II. von England und die Einsetzung von Wilhelm III. und Maria II. begründeten eine konstitutionelle Monarchie und die parlamentarische Vorherrschaft.","fr":"1688. Le renversement du roi Jacques II d'Angleterre et l'installation de Guillaume III et Marie II établirent une monarchie constitutionnelle et la suprématie parlementaire.","tr":"1688. İngiltere Kralı II. James'in devrilmesi ve III. William ile II. Mary'nin tahta geçirilmesi, anayasal bir monarşi ve parlamenter üstünlük tesis etti.","nl":"1688. De omverwerping van Koning James II van Engeland en de installatie van Willem III en Maria II vestigde een constitutionele monarchie en parlementaire suprematie.","ru":"1688. Свержение короля Якова II и воцарение Вильгельма III и Марии II установили конституционную монархию и парламентское верховенство.","zh":"1688年。英格兰国王詹姆斯二世被推翻，威廉三世和玛丽二世登基，确立了君主立宪制和议会至上原则。","pt_BR":"1688. A derrubada do Rei Jaime II da Inglaterra e a instalação de Guilherme III e Maria II estabeleceram uma monarquia constitucional e a supremacia parlamentar.","pt_PT":"1688. A derrubada do Rei Jaime II de Inglaterra e a instalação de Guilherme III e Maria II estabeleceram uma monarquia constitucional e a supremacia parlamentar."}},
  { id: 'dc-history-0043', deck_id: 'deck-history', front: 'The Enlightenment', back: '17th–18th centuries. An intellectual movement emphasizing reason, individualism, and skepticism of authority; its thinkers (Locke, Voltaire, Rousseau) influenced democratic revolutions worldwide.', sort_order: 43 , front_translations: {"es":"El Iluminismo","de":"Die Aufklärung","fr":"Le Siècle des Lumières","tr":"Aydınlanma Çağı","nl":"De Verlichting","ru":"Эпоха Просвещения","zh":"启蒙运动","pt_BR":"O Iluminismo","pt_PT":"O Iluminismo"}, back_translations: {"es":"Siglos XVII–XVIII. Un movimiento intelectual que enfatizava a razão, el individualismo y el ceticismo en relación con la autoridad; sus pensadores (Locke, Voltaire, Rousseau) influenciaram revoluciones democráticas en todo el mundo.","de":"17.–18. Jahrhundert. Eine intellektuelle Bewegung, die Vernunft, Individualismus und Skepsis gegenüber Autoritäten betonte; ihre Denker (Locke, Voltaire, Rousseau) beeinflussten demokratische Revolutionen weltweit.","fr":"XVIIe–XVIIIe siècles. Un mouvement intellectuel mettant l'accent sur la raison, l'individualisme et le scepticisme envers l'autorité ; ses penseurs (Locke, Voltaire, Rousseau) ont influencé les révolutions démocratiques dans le monde entier.","tr":"17.–18. yüzyıllar. Akıl, bireycilik ve otoriteye kuşkuyla yaklaşmayı ön plana çıkaran entelektüel bir hareket; düşünürleri (Locke, Voltaire, Rousseau) dünya genelindeki demokratik devrimleri etkiledi.","nl":"17e–18e eeuw. Een intellectuele beweging die de nadruk legde op rede, individualisme en scepsis ten aanzien van autoriteit; haar denkers (Locke, Voltaire, Rousseau) beïnvloedden democratische revoluties wereldwijd.","ru":"XVII–XVIII века. Интеллектуальное движение, ставившее во главу угла разум, индивидуализм и скептицизм по отношению к власти; его мыслители (Локк, Вольтер, Руссо) оказали влияние на демократические революции по всему миру.","zh":"17至18世纪。一场强调理性、个人主义和质疑权威的思想运动；其思想家（洛克、伏尔泰、卢梭）影响了全球的民主革命。","pt_BR":"Séculos XVII–XVIII. Um movimento intelectual que enfatizava a razão, o individualismo e o ceticismo em relação à autoridade; seus pensadores (Locke, Voltaire, Rousseau) influenciaram revoluções democráticas em todo o mundo.","pt_PT":"Séculos XVII–XVIII. Um movimento intelectual que enfatizava a razão, o individualismo e o ceticismo em relação à autoridade; os seus pensadores (Locke, Voltaire, Rousseau) influenciaram revoluções democráticas em todo o mundo."}},
  { id: 'dc-history-0044', deck_id: 'deck-history', front: 'American Revolutionary War', back: '1775–1783. The thirteen American colonies fought and won independence from Britain, establishing the United States of America as the first modern constitutional republic.', sort_order: 44 , front_translations: {"es":"Guerra Revolucionária Americana","de":"Amerikanischer Unabhängigkeitskrieg","fr":"Guerre d'indépendance américaine","tr":"Amerikan Bağımsızlık Savaşı","nl":"Amerikaanse Onafhankelijkheidsoorlog","ru":"Война за независимость США","zh":"美国独立战争","pt_BR":"Guerra Revolucionária Americana","pt_PT":"Guerra Revolucionária Americana"}, back_translations: {"es":"1775–1783. As treze colonias americanas lutaram y conquistaram a independencia de la Grã-Bretanha, estableciendo los Estados Unidos de la América como a primera república constitucional moderna.","de":"1775–1783. Die dreizehn amerikanischen Kolonien erkämpften ihre Unabhängigkeit von Großbritannien und gründeten die Vereinigten Staaten von Amerika als erste moderne Verfassungsrepublik.","fr":"1775–1783. Les treize colonies américaines combattirent et remportèrent leur indépendance vis-à-vis de la Grande-Bretagne, établissant les États-Unis d'Amérique comme la première république constitutionnelle moderne.","tr":"1775–1783. On üç Amerikan kolonisi, Britanya'dan bağımsızlıklarını kazanarak Amerika Birleşik Devletleri'ni ilk modern anayasal cumhuriyet olarak kurdu.","nl":"1775–1783. De dertien Amerikaanse koloniën vochten voor en wonnen de onafhankelijkheid van Groot-Brittannië, waarmee de Verenigde Staten van Amerika als de eerste moderne constitutionele republiek werden gevestigd.","ru":"1775–1783. Тринадцать американских колоний в вооружённой борьбе завоевали независимость от Великобритании, основав Соединённые Штаты Америки как первую современную конституционную республику.","zh":"1775–1783年。十三个美洲殖民地与英国战争并赢得独立，建立了美利坚合众国，成为第一个现代宪政共和国。","pt_BR":"1775–1783. As treze colônias americanas lutaram e conquistaram a independência da Grã-Bretanha, estabelecendo os Estados Unidos da América como a primeira república constitucional moderna.","pt_PT":"1775–1783. As treze colónias americanas lutaram e conquistaram a independência da Grã-Bretanha, estabelecendo os Estados Unidos da América como a primeira república constitucional moderna."}},
  { id: 'dc-history-0045', deck_id: 'deck-history', front: 'George Washington', back: '1732–1799. Commander of the Continental Army during the American Revolution and the first President of the United States, setting precedents for the office including the two-term tradition.', sort_order: 45 , front_translations: {"es":"George Washington","de":"George Washington","fr":"George Washington","tr":"George Washington","nl":"George Washington","ru":"Джордж Вашингтон","zh":"乔治·华盛顿","pt_BR":"George Washington","pt_PT":"George Washington"}, back_translations: {"es":"1732–1799. Comandante del Exército Continental durante a Revolución Americana y el primero Presidente de los Estados Unidos, estableciendo precedentes para el cargo, incluyendo a tradición de de los mandatos.","de":"1732–1799. Oberbefehlshaber der Kontinentalarmee während der Amerikanischen Revolution und erster Präsident der Vereinigten Staaten; er setzte Präzedenzfälle für das Amt, einschließlich der Zwei-Amtszeiten-Tradition.","fr":"1732–1799. Commandant de l'armée continentale pendant la Révolution américaine et premier président des États-Unis, il établit des précédents pour la fonction, notamment la tradition des deux mandats.","tr":"1732–1799. Amerikan Devrimi sırasında Kıta Ordusu Komutanı ve Amerika Birleşik Devletleri'nin ilk Başkanı; iki dönem geleneği de dahil olmak üzere bu makam için emsaller belirledi.","nl":"1732–1799. Opperbevelhebber van het Continentale Leger tijdens de Amerikaanse Revolutie en de eerste President van de Verenigde Staten; hij schiep precedenten voor het ambt, waaronder de traditie van twee termijnen.","ru":"1732–1799. Главнокомандующий Континентальной армией в годы Американской революции и первый президент Соединённых Штатов; он заложил прецеденты для этого поста, в том числе традицию двух сроков.","zh":"1732–1799年。美国独立战争期间大陆军总司令，美国第一任总统，为总统职位树立了先例，包括两届任期传统。","pt_BR":"1732–1799. Comandante do Exército Continental durante a Revolução Americana e o primeiro Presidente dos Estados Unidos, estabelecendo precedentes para o cargo, incluindo a tradição de dois mandatos.","pt_PT":"1732–1799. Comandante do Exército Continental durante a Revolução Americana e o primeiro Presidente dos Estados Unidos, estabelecendo precedentes para o cargo, incluindo a tradição de dois mandatos."}},
  { id: 'dc-history-0046', deck_id: 'deck-history', front: 'Storming of the Bastille', back: '14 July 1789. Parisian revolutionaries stormed the Bastille prison, a symbol of royal tyranny, marking the start of the French Revolution; Bastille Day is now France\'s national holiday.', sort_order: 46 , front_translations: {"es":"Tomada de la Bastilha","de":"Sturm auf die Bastille","fr":"Prise de la Bastille","tr":"Bastille'in Ele Geçirilmesi","nl":"Bestorming van de Bastille","ru":"Взятие Бастилии","zh":"攻占巴士底狱","pt_BR":"Tomada da Bastilha","pt_PT":"Tomada da Bastilha"}, back_translations: {"es":"14 de julho de 1789. Revolucionários parisienses invadiram a prisão de la Bastilha, símbolo de la tirania real, marcando el início de la Revolución Francesa; el Dia de la Bastilha es hoy el feriado nacional de la França.","de":"14. Juli 1789. Pariser Revolutionäre stürmten das Bastille-Gefängnis, ein Symbol königlicher Tyrannei, und markierten damit den Beginn der Französischen Revolution; der Bastille-Tag ist heute Frankreichs Nationalfeiertag.","fr":"14 juillet 1789. Des révolutionnaires parisiens prirent d'assaut la prison de la Bastille, symbole de la tyrannie royale, marquant le début de la Révolution française ; le 14 Juillet est aujourd'hui la fête nationale française.","tr":"14 Temmuz 1789. Parisli devrimciler, kraliyet zorbalığının simgesi olan Bastille Hapishanesi'ni ele geçirerek Fransız Devrimi'nin başlangıcına işaret etti; Bastille Günü artık Fransa'nın ulusal bayramıdır.","nl":"14 juli 1789. Parijse revolutionairen bestormden de Bastille-gevangenis, een symbool van koninklijke tirannie, wat het begin van de Franse Revolutie markeerde; Bastille-dag is nu de nationale feestdag van Frankrijk.","ru":"14 июля 1789 г. Парижские революционеры захватили крепость Бастилию — символ королевского деспотизма, — ознаменовав начало Французской революции; День взятия Бастилии стал национальным праздником Франции.","zh":"1789年7月14日。巴黎革命者攻占了象征王权暴政的巴士底狱，标志着法国大革命的开始；巴士底日现已成为法国国庆节。","pt_BR":"14 de julho de 1789. Revolucionários parisienses invadiram a prisão da Bastilha, símbolo da tirania real, marcando o início da Revolução Francesa; o Dia da Bastilha é hoje o feriado nacional da França.","pt_PT":"14 de julho de 1789. Revolucionários parisienses invadiram a prisão da Bastilha, símbolo da tirania real, marcando o início da Revolução Francesa; o Dia da Bastilha é hoje o feriado nacional de França."}},
  { id: 'dc-history-0047', deck_id: 'deck-history', front: 'Battle of Waterloo', back: '1815. Napoleon\'s final defeat by British and Prussian forces ended his rule and the Napoleonic Wars, reshaping Europe at the Congress of Vienna.', sort_order: 47 , front_translations: {"es":"Batalla de Waterloo","de":"Schlacht bei Waterloo","fr":"Bataille de Waterloo","tr":"Waterloo Muharebesi","nl":"Slag bij Waterloo","ru":"Битва при Ватерлоо","zh":"滑铁卢战役","pt_BR":"Batalha de Waterloo","pt_PT":"Batalha de Waterloo"}, back_translations: {"es":"1815. La derrota final de Napoleão por las fuerzas britanicas y prussianas encerrou su gobierno y las Guerras Napoleonicas, remodelando a Europa en el Congresso de Viena.","de":"1815. Napoleons endgültige Niederlage gegen britische und preußische Streitkräfte beendete seine Herrschaft und die Napoleonischen Kriege und gestaltete Europa auf dem Wiener Kongress neu.","fr":"1815. La défaite finale de Napoléon face aux forces britanniques et prussiennes mit fin à son règne et aux guerres napoléoniennes, redessinant l'Europe lors du congrès de Vienne.","tr":"1815. Napolyon'un İngiliz ve Prusya kuvvetlerine karşı aldığı son yenilgi, onun iktidarını ve Napolyon Savaşları'nı sona erdirerek Avrupa'yı Viyana Kongresi'nde yeniden şekillendirdi.","nl":"1815. Napoleons definitieve nederlaag tegen Britse en Pruisische troepen beëindigde zijn heerschappij en de Napoleontische Oorlogen, waarbij Europa op het Congres van Wenen werd hervormd.","ru":"1815. Окончательное поражение Наполеона от британских и прусских войск положило конец его власти и наполеоновским войнам, а Венский конгресс перекроил карту Европы.","zh":"1815年。拿破仑在英国和普鲁士军队的联合打击下遭受最终失败，终结了他的统治和拿破仑战争，维也纳会议重新划定了欧洲格局。","pt_BR":"1815. A derrota final de Napoleão pelas forças britânicas e prussianas encerrou seu governo e as Guerras Napoleônicas, remodelando a Europa no Congresso de Viena.","pt_PT":"1815. A derrota final de Napoleão pelas forças britânicas e prussianas encerrou o seu governo e as Guerras Napoleónicas, remodelando a Europa no Congresso de Viena."}},
  { id: 'dc-history-0048', deck_id: 'deck-history', front: 'Haitian Revolution', back: '1791–1804. The only successful slave revolt in history; led by Toussaint Louverture, enslaved people overthrew French colonial rule to establish Haiti as the first Black republic.', sort_order: 48 , front_translations: {"es":"Revolución Haitiana","de":"Haitianische Revolution","fr":"Révolution haïtienne","tr":"Haiti Devrimi","nl":"Haïtiaanse Revolutie","ru":"Гаитянская революция","zh":"海地革命","pt_BR":"Revolução Haitiana","pt_PT":"Revolução Haitiana"}, back_translations: {"es":"1791–1804. La única revolta escrava bem-sucedida de la historia; liderada por Toussaint Louverture, los escravizados derrubaram el domínio colonial frances para estabelecer el Haiti como a primera república negra.","de":"1791–1804. Der einzige erfolgreiche Sklavenaufstand der Geschichte; angeführt von Toussaint Louverture, stürzten versklavte Menschen die französische Kolonialherrschaft und gründeten Haiti als erste Schwarze Republik.","fr":"1791–1804. La seule révolte d'esclaves réussie de l'histoire ; menée par Toussaint Louverture, les esclaves renversèrent la domination coloniale française pour établir Haïti comme la première République noire.","tr":"1791–1804. Tarihteki tek başarılı köle isyanı; Toussaint Louverture önderliğinde köleler, Fransız sömürge yönetimini devirdi ve Haiti'yi ilk Siyah cumhuriyet olarak kurdu.","nl":"1791–1804. De enige succesvolle slavenopstand in de geschiedenis; geleid door Toussaint Louverture, versloegen tot slaaf gemaakte mensen het Franse koloniale bestuur om Haïti te stichten als de eerste Zwarte republiek.","ru":"1791–1804. Единственное успешное восстание рабов в истории; под руководством Туссена Лувертюра порабощённые люди свергли французское колониальное господство и основали Гаити как первую Чёрную республику.","zh":"1791–1804年。历史上唯一成功的奴隶起义；在杜桑·卢维杜尔的领导下，被奴役的人们推翻了法国殖民统治，建立了第一个黑人共和国——海地。","pt_BR":"1791–1804. A única revolta escrava bem-sucedida da história; liderada por Toussaint Louverture, os escravizados derrubaram o domínio colonial francês para estabelecer o Haiti como a primeira república negra.","pt_PT":"1791–1804. A única revolta escrava bem-sucedida da história; liderada por Toussaint Louverture, os escravizados derrubaram o domínio colonial francês para estabelecer o Haiti como a primeira república negra."}},
  { id: 'dc-history-0049', deck_id: 'deck-history', front: 'Abolition of Slavery in the USA', back: '1865. The 13th Amendment to the US Constitution formally abolished slavery following the Civil War; Lincoln\'s Emancipation Proclamation of 1863 had been a critical step.', sort_order: 49 , front_translations: {"es":"Abolición de la Esclavitud en los EUA","de":"Abschaffung der Sklaverei in den USA","fr":"Abolition de l'esclavage aux États-Unis","tr":"ABD'de Köleliğin Kaldırılması","nl":"Afschaffing van de slavernij in de VS","ru":"Отмена рабства в США","zh":"美国废除奴隶制","pt_BR":"Abolição da Escravidão nos EUA","pt_PT":"Abolição da Escravatura nos EUA"}, back_translations: {"es":"1865. La 13ª Emenda a la Constitución de los EUA aboliu formalmente a esclavitud após a Guerra Civil; a Proclamación de Emancipación de Lincoln de 1863 había sido un passo fundamental.","de":"1865. Der 13. Zusatzartikel zur US-Verfassung schaffte die Sklaverei nach dem Bürgerkrieg offiziell ab; Lincolns Emanzipationsproklamation von 1863 war ein entscheidender Schritt gewesen.","fr":"1865. Le 13e amendement à la Constitution américaine abolit officiellement l'esclavage à la suite de la guerre de Sécession ; la Proclamation d'émancipation de Lincoln en 1863 avait été une étape cruciale.","tr":"1865. ABD Anayasası'na eklenen 13. Değişiklik, İç Savaş'ın ardından köleliği resmen kaldırdı; Lincoln'ün 1863 tarihli Özgürlük Bildirisi kritik bir adım olmuştu.","nl":"1865. Het 13e Amendement op de Amerikaanse grondwet schafte formeel de slavernij af na de Burgeroorlog; Lincolns Emancipatieproclamatie van 1863 was een cruciale stap geweest.","ru":"1865. 13-я поправка к Конституции США официально отменила рабство по окончании Гражданской войны; важным шагом на этом пути стала Прокламация об освобождении рабов Линкольна в 1863 году.","zh":"1865年。内战后，美国宪法第十三条修正案正式废除了奴隶制；林肯1863年颁布的《解放奴隶宣言》是这一进程中的关键步骤。","pt_BR":"1865. A 13ª Emenda à Constituição dos EUA aboliu formalmente a escravidão após a Guerra Civil; a Proclamação de Emancipação de Lincoln de 1863 havia sido um passo fundamental.","pt_PT":"1865. A 13.ª Emenda à Constituição dos EUA aboliu formalmente a escravatura após a Guerra Civil; a Proclamação de Emancipação de Lincoln de 1863 havia sido um passo fundamental."}},
  { id: 'dc-history-0050', deck_id: 'deck-history', front: 'American Civil War', back: '1861–1865. A war between the Union and Confederate states over slavery and states\' rights; it resulted in over 600,000 deaths and the abolition of slavery.', sort_order: 50 , front_translations: {"es":"Guerra Civil Americana","de":"Amerikanischer Bürgerkrieg","fr":"Guerre de Sécession","tr":"Amerikan İç Savaşı","nl":"Amerikaanse Burgeroorlog","ru":"Гражданская война в США","zh":"美国内战","pt_BR":"Guerra Civil Americana","pt_PT":"Guerra Civil Americana"}, back_translations: {"es":"1861–1865. Una guerra entre los estados de la União y los estados Confederados sobre esclavitud y derechos de los estados; resultou en más de 600.000 mortes y en la abolición de la esclavitud.","de":"1861–1865. Ein Krieg zwischen den Unions- und Konföderationsstaaten über Sklaverei und Staatsrechte; er forderte über 600.000 Todesopfer und führte zur Abschaffung der Sklaverei.","fr":"1861–1865. Une guerre entre les États de l'Union et les États confédérés portant sur l'esclavage et les droits des États ; elle fit plus de 600 000 morts et aboutit à l'abolition de l'esclavage.","tr":"1861–1865. Kölelik ve eyalet hakları üzerine Birlik ile Konfederasyon eyaletleri arasında yaşanan savaş; 600.000'den fazla ölüme yol açtı ve köleliğin kaldırılmasıyla sonuçlandı.","nl":"1861–1865. Een oorlog tussen de Unie en de Confederale staten over slavernij en staatsrechten; het resulteerde in meer dan 600.000 doden en de afschaffing van de slavernij.","ru":"1861–1865. Война между Союзом и Конфедерацией по вопросам рабства и прав штатов; она унесла более 600 000 жизней и привела к отмене рабства.","zh":"1861–1865年。联邦与邦联各州就奴隶制和州权问题爆发的战争；造成超过60万人死亡，最终导致奴隶制的废除。","pt_BR":"1861–1865. Uma guerra entre os estados da União e os estados Confederados sobre escravidão e direitos dos estados; resultou em mais de 600.000 mortes e na abolição da escravidão.","pt_PT":"1861–1865. Uma guerra entre os estados da União e os estados Confederados sobre escravidão e direitos dos estados; resultou em mais de 600.000 mortes e na abolição da escravatura."}},
  { id: 'dc-history-0051', deck_id: 'deck-history', front: 'Abraham Lincoln', back: '1809–1865. The 16th US President who led the Union through the Civil War, issued the Emancipation Proclamation, and was assassinated shortly after the war\'s end.', sort_order: 51 , front_translations: {"es":"Abraham Lincoln","de":"Abraham Lincoln","fr":"Abraham Lincoln","tr":"Abraham Lincoln","nl":"Abraham Lincoln","ru":"Авраам Линкольн","zh":"亚伯拉罕·林肯","pt_BR":"Abraham Lincoln","pt_PT":"Abraham Lincoln"}, back_translations: {"es":"1809–1865. El 16º presidente de los EUA que liderou a União durante a Guerra Civil, emitiu a Proclamación de Emancipación y fue assassinado pouco después del fin de la guerra.","de":"1809–1865. Der 16. US-Präsident, der die Union durch den Bürgerkrieg führte, die Emanzipationsproklamation erließ und kurz nach Kriegsende ermordet wurde.","fr":"1809–1865. Le 16e président des États-Unis qui mena l’Union à travers la guerre de Sécession, publia la Proclamation d’émancipation et fut assassiné peu après la fin de la guerre.","tr":"1809–1865. Birliği İç Savaş boyunca yöneten, Kurtuluş Bildirisi’ni yayımlayan ve savaşın bitiminden kısa süre sonra suikaste kurban giden 16. ABD Başkanı.","nl":"1809–1865. De 16e president van de VS die de Unie door de Burgeroorlog leidde, de Emancipatieproclamatie uitvaardigde en kort na het einde van de oorlog werd vermoord.","ru":"1809–1865. 16-й президент США, который провёл Союз через Гражданскую войну, издал Прокламацию об освобождении рабов и был убит вскоре после окончания войны.","zh":"1809–1865年。美国第16任总统，领导联邦度过内战，颁布了《解放奴隶宣言》，在战争结束后不久遇刺身亡。","pt_BR":"1809–1865. O 16º presidente dos EUA que liderou a União durante a Guerra Civil, emitiu a Proclamação de Emancipação e foi assassinado pouco depois do fim da guerra.","pt_PT":"1809–1865. O 16.º presidente dos EUA que liderou a União durante a Guerra Civil, emitiu a Proclamação de Emancipação e foi assassinado pouco depois do fim da guerra."}},
  { id: 'dc-history-0052', deck_id: 'deck-history', front: 'Unification of Germany', back: '1871. Otto von Bismarck unified the German states under Prussian leadership after victories in wars against Austria and France, creating the German Empire.', sort_order: 52 , front_translations: {"es":"Unificación de la Alemanha","de":"Vereinigung Deutschlands","fr":"Unification de l’Allemagne","tr":"Almanya’nın Birleşmesi","nl":"Eenwording van Duitsland","ru":"Объединение Германии","zh":"德国统一","pt_BR":"Unificação da Alemanha","pt_PT":"Unificação da Alemanha"}, back_translations: {"es":"1871. Otto von Bismarck unificou los estados alemães sob a liderazgo prussiana após vitórias en guerras contra a Áustria y a França, creando el Imperio Alemão.","de":"1871. Otto von Bismarck vereinigte die deutschen Staaten unter preußischer Führung nach Siegen in Kriegen gegen Österreich und Frankreich und schuf das Deutsche Kaiserreich.","fr":"1871. Otto von Bismarck unifia les États allemands sous la direction de la Prusse après des victoires dans les guerres contre l’Autriche et la France, créant l’Empire allemand.","tr":"1871. Otto von Bismarck, Avusturya ve Fransa’ya karşı kazanılan savaşların ardından Alman devletlerini Prusya liderliğinde birleştirerek Alman İmparatorluğu’nu kurdu.","nl":"1871. Otto von Bismarck verenigde de Duitse staten onder Pruisisch leiderschap na overwinningen in oorlogen tegen Oostenrijk en Frankrijk, en richtte het Duitse Keizerrijk op.","ru":"1871. Отто фон Бисмарк объединил германские государства под прусским руководством после побед в войнах против Австрии и Франции, создав Германскую империю.","zh":"1871年。奥托·冯·俳斯麦在击败奥地利和法国后，在普鲁士领导下统一了德意志各邦，建立了德意志帝国。","pt_BR":"1871. Otto von Bismarck unificou os estados alemães sob a liderança prussiana após vitórias em guerras contra a Áustria e a França, criando o Império Alemão.","pt_PT":"1871. Otto von Bismarck unificou os estados alemães sob a liderança prussiana após vitórias em guerras contra a Áustria e a França, criando o Império Alemão."}},
  { id: 'dc-history-0053', deck_id: 'deck-history', front: 'Unification of Italy', back: '1861. The Risorgimento movement, led by figures like Garibaldi and Cavour, unified the Italian peninsula into the Kingdom of Italy.', sort_order: 53 , front_translations: {"es":"Unificación de la Itália","de":"Vereinigung Italiens","fr":"Unification de l’Italie","tr":"İtalya’nın Birleşmesi","nl":"Eenwording van Italië","ru":"Объединение Италии","zh":"意大利统一","pt_BR":"Unificação da Itália","pt_PT":"Unificação de Itália"}, back_translations: {"es":"1861. El movimiento del Risorgimento, liderado por figuras como Garibaldi y Cavour, unificou a península italiana en el Reino de la Itália.","de":"1861. Die Risorgimento-Bewegung, angeführt von Persönlichkeiten wie Garibaldi und Cavour, vereinigte die italienische Halbinsel zum Königreich Italien.","fr":"1861. Le mouvement du Risorgimento, mené par des figures comme Garibaldi et Cavour, unifia la péninsule italienne en Royaume d’Italie.","tr":"1861. Garibaldi ve Cavour gibi isimlerin öncülük ettiği Risorgimento hareketi, İtalyan yarımadasını İtalya Krallığı olarak birleştirdi.","nl":"1861. De Risorgimento-beweging, geleid door figuren als Garibaldi en Cavour, verenigde het Italiaanse schiereiland tot het Koninkrijk Italië.","ru":"1861. Движение Рисорджименто под руководством таких деятелей, как Гарибальди и Кавур, объединило Апеннинский полуостров в Королевство Италия.","zh":"1861年。由加里波第和加富尔等人领导的复兴运动将意大利半岛统一为意大利王国。","pt_BR":"1861. O movimento do Risorgimento, liderado por figuras como Garibaldi e Cavour, unificou a península italiana no Reino da Itália.","pt_PT":"1861. O movimento do Risorgimento, liderado por figuras como Garibaldi e Cavour, unificou a península italiana no Reino de Itália."}},
  { id: 'dc-history-0054', deck_id: 'deck-history', front: 'Meiji Restoration', back: '1868. The restoration of imperial rule in Japan led to rapid modernization and industrialization, transforming Japan from a feudal society to a modern world power.', sort_order: 54 , front_translations: {"es":"Restauración Meiji","de":"Meiji-Restauration","fr":"Restauration Meiji","tr":"Meiji Restorasyonu","nl":"Meiji-restauratie","ru":"Реставрация Мэйдзи","zh":"明治维新","pt_BR":"Restauração Meiji","pt_PT":"Restauração Meiji"}, back_translations: {"es":"1868. La restauración del gobierno imperial en el Japão levou a la rápida modernización y industrialización, transformando el Japão de una sociedad feudal en una potencia mundial moderna.","de":"1868. Die Wiederherstellung der kaiserlichen Herrschaft in Japan führte zu einer raschen Modernisierung und Industrialisierung und verwandelte Japan von einer feudalen Gesellschaft in eine moderne Weltmacht.","fr":"1868. La restauration du pouvoir impérial au Japon entraîna une modernisation et une industrialisation rapides, transformant le Japon d’une société féodale en une puissance mondiale moderne.","tr":"1868. Japonya’da imparatorluk yönetiminin yeniden tesisi, hızlı modernleşme ve sanayileşmeye yol açarak Japonya’yı feodal bir toplumdan modern bir dünya gücüne dönüştürdü.","nl":"1868. Het herstel van het keizerlijk gezag in Japan leidde tot snelle modernisering en industrialisatie, waardoor Japan van een feodale samenleving werd omgevormd tot een moderne wereldmacht.","ru":"1868. Восстановление императорской власти в Японии привело к стремительной модернизации и индустриализации, превратив Японию из феодального общества в современную мировую державу.","zh":"1868年。日本恢复天皇统治，推动了快速的现代化和工业化，将日本从封建社会转变为现代世界强国。","pt_BR":"1868. A restauração do governo imperial no Japão levou à rápida modernização e industrialização, transformando o Japão de uma sociedade feudal em uma potência mundial moderna.","pt_PT":"1868. A restauração do governo imperial no Japão levou à rápida modernização e industrialização, transformando o Japão de uma sociedade feudal numa potência mundial moderna."}},
  { id: 'dc-history-0055', deck_id: 'deck-history', front: 'Scramble for Africa', back: '1881–1914. European powers rapidly colonized nearly all of Africa; by 1914 only Ethiopia and Liberia remained independent. This era shaped modern African borders and politics.', sort_order: 55 , front_translations: {"es":"Partilha de la África","de":"Wettlauf um Afrika","fr":"Partage de l’Afrique","tr":"Afrika’nın Paylaşılması","nl":"Wedloop om Afrika","ru":"Раздел Африки","zh":"瓜分非洲","pt_BR":"Partilha da África","pt_PT":"Partilha de África"}, back_translations: {"es":"1881–1914. As potencias europeias colonizaram rápidamente casi toda a África; hasta 1914, solo a Etiópia y a Libéria permaneciam independentes. Essa era moldou las fronteras y a política africanas modernas.","de":"1881–1914. Europäische Mächte kolonisierten in rasantem Tempo nahezu ganz Afrika; bis 1914 blieben nur Äthiopien und Liberia unabhängig. Diese Ära prägte die modernen Grenzen und die Politik Afrikas.","fr":"1881–1914. Les puissances européennes colonisèrent rapidement la quasi-totalité de l’Afrique ; en 1914, seules l’Éthiopie et le Libéria restaient indépendants. Cette époque façonna les frontières et la politique africaines modernes.","tr":"1881–1914. Avrupalı güçler Afrika’nın neredeyse tamamını hızla sömürgeleştirdi; 1914’e kadar yalnızca Etiyopya ve Liberya bağımsız kaldı. Bu dönem modern Afrika sınırlarını ve siyasetini şekillendirdi.","nl":"1881–1914. Europese mogendheden koloniseerden in snel tempo vrijwel heel Afrika; tegen 1914 waren alleen Ethiopië en Liberia nog onafhankelijk. Dit tijdperk vormde de moderne Afrikaanse grenzen en politiek.","ru":"1881–1914. Европейские державы стремительно колонизировали почти всю Африку; к 1914 году независимыми оставались лишь Эфиопия и Либерия. Эта эпоха определила современные границы и политику Африки.","zh":"1881–1914年。欧洲列强迅速殖民了几乎整个非洲；到1914年，只有埃塞俄比亚和利比里亚保持独立。这一时期塑造了现代非洲的边界和政治格局。","pt_BR":"1881–1914. As potências europeias colonizaram rapidamente quase toda a África; até 1914, apenas a Etiópia e a Libéria permaneciam independentes. Essa era moldou as fronteiras e a política africanas modernas.","pt_PT":"1881–1914. As potências europeias colonizaram rapidamente quase toda a África; até 1914, apenas a Etiópia e a Libéria permaneciam independentes. Esta era moldou as fronteiras e a política africanas modernas."}},
  { id: 'dc-history-0056', deck_id: 'deck-history', front: 'Assassination of Archduke Franz Ferdinand', back: '1914. The assassination of the heir to the Austro-Hungarian throne in Sarajevo by Gavrilo Princip triggered the chain of alliances and declarations of war that started WWI.', sort_order: 56 , front_translations: {"es":"Assassinato del Arquiduque Francisco Ferdinando","de":"Ermordung von Erzherzog Franz Ferdinand","fr":"Assassinat de l’archiduc François-Ferdinand","tr":"Arşidük Franz Ferdinand Suikasti","nl":"Moord op aartshertog Franz Ferdinand","ru":"Убийство эрцгерцога Франца Фердинанда","zh":"弗朗茨·斐迪南大公遇刺","pt_BR":"Assassinato do Arquiduque Francisco Ferdinando","pt_PT":"Assassinato do Arquiduque Francisco Fernando"}, back_translations: {"es":"1914. El assassinato del herdero del trono austro-húngaro en Sarajevo por Gavrilo Princip desencadeou a cadeia de alianzas y declaraciones de guerra que iniciou a Primera Guerra Mundial.","de":"1914. Die Ermordung des Thronfolgers von Österreich-Ungarn in Sarajevo durch Gavrilo Princip löste die Kette von Bündnissen und Kriegserklärungen aus, die den Ersten Weltkrieg einleiteten.","fr":"1914. L’assassinat de l’héritier du trône austro-hongrois à Sarajevo par Gavrilo Princip déclencha l’enchaînement d’alliances et de déclarations de guerre qui provoqua la Première Guerre mondiale.","tr":"1914. Gavrilo Princip tarafından Saraybosna’da Avusturya-Macaristan taht varisinin öldürülmesi, I. Dünya Savaşı’nı başlatan ittifaklar ve savaş ilanları zincirine yol açtı.","nl":"1914. De moord op de troonopvolger van Oostenrijk-Hongarije in Sarajevo door Gavrilo Princip zette de keten van bondgenootschappen en oorlogsverklaringen in gang die leidde tot de Eerste Wereldoorlog.","ru":"1914. Убийство наследника австро-венгерского престола в Сараево Гаврилой Принципом запустило цепочку союзов и объявлений войны, которые привели к началу Первой мировой войны.","zh":"1914年。加夫里洛·普林西普在萨拉热窝刺杀了奥匈帝国王储，引发了一系列同盟关系和宣战行动，导致第一次世界大战爆发。","pt_BR":"1914. O assassinato do herdeiro do trono austro-húngaro em Sarajevo por Gavrilo Princip desencadeou a cadeia de alianças e declarações de guerra que iniciou a Primeira Guerra Mundial.","pt_PT":"1914. O assassinato do herdeiro do trono austro-húngaro em Sarajevo por Gavrilo Princip desencadeou a cadeia de alianças e declarações de guerra que deu início à Primeira Guerra Mundial."}},
  { id: 'dc-history-0057', deck_id: 'deck-history', front: 'Treaty of Versailles', back: '1919. The peace treaty ending WWI that imposed harsh reparations and territorial losses on Germany; its punitive terms are widely cited as a factor contributing to WWII.', sort_order: 57 , front_translations: {"es":"Tratado de Versalhes","de":"Vertrag von Versailles","fr":"Traité de Versailles","tr":"Versay Antlaşması","nl":"Verdrag van Versailles","ru":"Версальский договор","zh":"凡尔赛条约","pt_BR":"Tratado de Versalhes","pt_PT":"Tratado de Versalhes"}, back_translations: {"es":"1919. El tratado de paz que encerrou a Primera Guerra Mundial y impos severas reparaciones y perdas territoriais a la Alemanha; sus termos punitivos son amplamente citados como un fator que contribuiu para a Segunda Guerra Mundial.","de":"1919. Der Friedensvertrag zur Beendigung des Ersten Weltkriegs, der Deutschland harte Reparationen und Gebietsverluste auferlegte; seine Strafbedingungen werden weithin als Faktor angesehen, der zum Zweiten Weltkrieg beitrug.","fr":"1919. Le traité de paix mettant fin à la Première Guerre mondiale qui imposa à l’Allemagne de lourdes réparations et des pertes territoriales ; ses conditions punitives sont largement citées comme un facteur ayant contribué à la Seconde Guerre mondiale.","tr":"1919. I. Dünya Savaşı’nı sona erdiren ve Almanya’ya ağır tazminatlar ile toprak kayıpları dayatan barış antlaşması; cezalandırıcı koşulları, II. Dünya Savaşı’na katkıda bulunan bir faktör olarak yaygın biçimde gösterilir.","nl":"1919. Het vredesverdrag dat een einde maakte aan de Eerste Wereldoorlog en Duitsland zware herstelbetalingen en gebiedsverliezen oplegde; de strenge voorwaarden worden algemeen beschouwd als een factor die bijdroeg aan de Tweede Wereldoorlog.","ru":"1919. Мирный договор, завершивший Первую мировую войну, наложивший на Германию тяжёлые репарации и территориальные потери; его карательные условия широко считаются фактором, способствовавшим Второй мировой войне.","zh":"1919年。结束第一次世界大战的和平条约，对德国施加了严厉的赔款和领土损失；其惩罚性条款被广泛认为是导致第二次世界大战的因素之一。","pt_BR":"1919. O tratado de paz que encerrou a Primeira Guerra Mundial e impôs severas reparações e perdas territoriais à Alemanha; seus termos punitivos são amplamente citados como um fator que contribuiu para a Segunda Guerra Mundial.","pt_PT":"1919. O tratado de paz que pôs fim à Primeira Guerra Mundial e impôs severas reparações e perdas territoriais à Alemanha; os seus termos punitivos são amplamente citados como um fator que contribuiu para a Segunda Guerra Mundial."}},
  { id: 'dc-history-0058', deck_id: 'deck-history', front: 'Great Depression', back: '1929–1939. A severe global economic downturn triggered by the 1929 Wall Street Crash; it caused mass unemployment and contributed to political instability that enabled fascist rise.', sort_order: 58 , front_translations: {"es":"Grande Depresión","de":"Weltwirtschaftskrise","fr":"Grande Dépression","tr":"Büyük Buhran","nl":"Grote Depressie","ru":"Великая депрессия","zh":"大萧条","pt_BR":"Grande Depressão","pt_PT":"Grande Depressão"}, back_translations: {"es":"1929–1939. Una grave recesión económica global desencadeada por el crash de la Bolsa de Wall Street en 1929; causou desemprego en masa y contribuiu para a instabilidad política que possibilitou a ascensão del fascismo.","de":"1929–1939. Ein schwerer globaler Wirtschaftsabschwung, ausgelöst durch den Börsencrash von 1929 an der Wall Street; er verursachte Massenarbeitslosigkeit und trug zur politischen Instabilität bei, die den Aufstieg des Faschismus ermöglichte.","fr":"1929–1939. Une grave dépression économique mondiale déclenchée par le krach de Wall Street en 1929 ; elle provoqua un chômage massif et contribua à l’instabilité politique qui permit la montée du fascisme.","tr":"1929–1939. 1929 Wall Street Çöküşü’nün tetiklediği ciddi bir küresel ekonomik gerileme; kitlesel işsizliğe yol açtı ve faşizmin yükselşine zemin hazırlayan siyasi istikrarsızlığa katkıda bulundu.","nl":"1929–1939. Een ernstige wereldwijde economische neergang veroorzaakt door de Wall Street-crash van 1929; het veroorzaakte massale werkloosheid en droeg bij aan de politieke instabiliteit die de opkomst van het fascisme mogelijk maakte.","ru":"1929–1939. Тяжёлый мировой экономический кризис, вызванный крахом на Уолл-стрит в 1929 году; он привёл к массовой безработице и способствовал политической нестабильности, позволившей фашизму прийти к власти.","zh":"1929–1939年。由1929年华尔街股灾引发的严重全球经济衰退；造成大规模失业，并助长了使法西斯主义崛起的政治动荡。","pt_BR":"1929–1939. Uma grave recessão econômica global desencadeada pelo crash da Bolsa de Wall Street em 1929; causou desemprego em massa e contribuiu para a instabilidade política que possibilitou a ascensão do fascismo.","pt_PT":"1929–1939. Uma grave recessão económica global desencadeada pelo crash da Bolsa de Wall Street em 1929; causou desemprego em massa e contribuiu para a instabilidade política que possibilitou a ascensão do fascismo."}},
  { id: 'dc-history-0059', deck_id: 'deck-history', front: 'Rise of Adolf Hitler', back: '1933. Hitler became Chancellor of Germany and rapidly consolidated power, establishing a totalitarian Nazi state that pursued aggressive expansion and led to WWII.', sort_order: 59 , front_translations: {"es":"Ascensão de Adolf Hitler","de":"Aufstieg Adolf Hitlers","fr":"Montée d’Adolf Hitler","tr":"Adolf Hitler’in Yükselisi","nl":"Opkomst van Adolf Hitler","ru":"Приход Адольфа Гитлера к власти","zh":"阿道夫·希特勒的崛起","pt_BR":"Ascensão de Adolf Hitler","pt_PT":"Ascensão de Adolf Hitler"}, back_translations: {"es":"1933. Hitler tornou-se chanceler de la Alemanha y rápidamente consolidou el poder, estableciendo un Estado nazista totalitário que buscou expansão agressiva y levou a la Segunda Guerra Mundial.","de":"1933. Hitler wurde Reichskanzler und konsolidierte rasch seine Macht, indem er einen totalitären NS-Staat errichtete, der eine aggressive Expansion verfolgte und zum Zweiten Weltkrieg führte.","fr":"1933. Hitler devint chancelier d’Allemagne et consolida rapidement son pouvoir, établissant un État nazi totalitaire qui poursuivit une expansion agressive et mena à la Seconde Guerre mondiale.","tr":"1933. Hitler Almanya Şansölyesi oldu ve hızla iktidarını pekiştirerek saldırgan yayılma politikası izleyen ve II. Dünya Savaşı’na yol açan totaliter bir Nazi devleti kurdu.","nl":"1933. Hitler werd Rijkskanselier van Duitsland en consolideerde snel de macht door een totalitaire nazistaat te vestigen die agressieve expansie nastreefde en leidde tot de Tweede Wereldoorlog.","ru":"1933. Гитлер стал канцлером Германии и быстро сосредоточил власть, создав тоталитарное нацистское государство, проводившее агрессивную экспансию и приведшее ко Второй мировой войне.","zh":"1933年。希特勒成为德国总理并迅速巩固权力，建立了追求侵略性扩张的极权纳粹国家，最终导致了第二次世界大战。","pt_BR":"1933. Hitler tornou-se chanceler da Alemanha e rapidamente consolidou o poder, estabelecendo um Estado nazista totalitário que buscou expansão agressiva e levou à Segunda Guerra Mundial.","pt_PT":"1933. Hitler tornou-se chanceler da Alemanha e rapidamente consolidou o poder, estabelecendo um Estado nazi totalitário que prosseguiu uma expansão agressiva e conduziu à Segunda Guerra Mundial."}},
  { id: 'dc-history-0060', deck_id: 'deck-history', front: 'D-Day (Operation Overlord)', back: '6 June 1944. Allied forces launched the largest seaborne invasion in history on the beaches of Normandy, France, opening the western front against Nazi Germany.', sort_order: 60 , front_translations: {"es":"Dia D (Operación Overlord)","de":"D-Day (Operation Overlord)","fr":"Jour J (Opération Overlord)","tr":"D-Day (Overlord Harekâtı)","nl":"D-Day (Operatie Overlord)","ru":"День «Д» (Операция «Оверлорд»)","zh":"诺曼底登陆日（霸王行动）","pt_BR":"Dia D (Operação Overlord)","pt_PT":"Dia D (Operação Overlord)"}, back_translations: {"es":"6 de junho de 1944. As fuerzas aliadas lançaram a mayor invasão marítima de la historia en las praias de la Normandia, França, abrindo a frente ocidental contra a Alemanha nazista.","de":"6. Juni 1944. Die Alliierten starteten die größte Seelandung der Geschichte an den Stränden der Normandie, Frankreich, und eröffneten die Westfront gegen Nazi-Deutschland.","fr":"6 juin 1944. Les forces alliées lancèrent la plus grande invasion maritime de l’histoire sur les plages de Normandie, en France, ouvrant le front occidental contre l’Allemagne nazie.","tr":"6 Haziran 1944. Müttefik kuvvetler, tarihin en büyük denizden çıkarma operasyonunu Fransa’nın Normandiya kıyılarında başlatarak Nazi Almanyası’na karşı batı cephesini açtı.","nl":"6 juni 1944. Geallieerde troepen lanceerden de grootste amfibische invasie in de geschiedenis op de stranden van Normandië, Frankrijk, en openden het westelijk front tegen nazi-Duitsland.","ru":"6 июня 1944 года. Союзные войска провели крупнейшую морскую десантную операцию в истории на побережье Нормандии, Франция, открыв западный фронт против нацистской Германии.","zh":"1944年6月6日。盟军在法国诺曼底海滩发动了历史上规模最大的两栖登陆行动，开辟了对抗纳粹德国的西线战场。","pt_BR":"6 de junho de 1944. As forças aliadas lançaram a maior invasão marítima da história nas praias da Normandia, França, abrindo a frente ocidental contra a Alemanha nazista.","pt_PT":"6 de junho de 1944. As forças aliadas lançaram a maior invasão marítima da história nas praias da Normandia, França, abrindo a frente ocidental contra a Alemanha nazi."}},
  { id: 'dc-history-0061', deck_id: 'deck-history', front: 'Atomic Bombings of Hiroshima and Nagasaki', back: '6 and 9 August 1945. The US dropped atomic bombs on two Japanese cities, killing ~200,000 people and precipitating Japan\'s surrender, ending WWII in the Pacific.', sort_order: 61 , front_translations: {"es":"Bombardeios Atomicos de Hiroshima y Nagasaki","de":"Atombombenabwürfe auf Hiroshima und Nagasaki","fr":"Bombardements atomiques d’Hiroshima et Nagasaki","tr":"Hiroşima ve Nagazaki Atom Bombaları","nl":"Atoombombardementen op Hiroshima en Nagasaki","ru":"Атомные бомбардировки Хиросимы и Нагасаки","zh":"广岛和长崎原子弹轰炸","pt_BR":"Bombardeios Atômicos de Hiroshima e Nagasaki","pt_PT":"Bombardeamentos Atómicos de Hiroshima e Nagasaki"}, back_translations: {"es":"6 y 9 de agosto de 1945. Los EUA lançaram bombas atomicas sobre de los cidades japonesas, matando cerca de 200.000 personas y precipitando a rendición del Japão, encerrando a Segunda Guerra Mundial en el Pacífico.","de":"6. und 9. August 1945. Die USA warfen Atombomben auf zwei japanische Städte, töteten ca. 200.000 Menschen und beschleunigten die Kapitulation Japans, wodurch der Zweite Weltkrieg im Pazifik endete.","fr":"6 et 9 août 1945. Les États-Unis larguèrent des bombes atomiques sur deux villes japonaises, tuant environ 200 000 personnes et précipitant la capitulation du Japon, mettant fin à la Seconde Guerre mondiale dans le Pacifique.","tr":"6 ve 9 Ağustos 1945. ABD iki Japon şehrine atom bombası attı, yaklaşık 200.000 kişiyi öldürdü ve Japonya’nın teslim olmasını hızlandırarak Pasifik’teki II. Dünya Savaşı’nı sona erdirdi.","nl":"6 en 9 augustus 1945. De VS dropten atoombommen op twee Japanse steden, doodden ongeveer 200.000 mensen en bespoedigden de overgave van Japan, waarmee de Tweede Wereldoorlog in de Stille Oceaan eindigde.","ru":"6 и 9 августа 1945 года. США сбросили атомные бомбы на два японских города, убив около 200 000 человек и ускорив капитуляцию Японии, что положило конец Второй мировой войне на Тихом океане.","zh":"1945年8月6日和9日。美国向两座日本城市投下原子弹，造成约20万人死亡，促使日本投降，结束了太平洋战争。","pt_BR":"6 e 9 de agosto de 1945. Os EUA lançaram bombas atômicas sobre duas cidades japonesas, matando cerca de 200.000 pessoas e precipitando a rendição do Japão, encerrando a Segunda Guerra Mundial no Pacífico.","pt_PT":"6 e 9 de agosto de 1945. Os EUA lançaram bombas atómicas sobre duas cidades japonesas, matando cerca de 200.000 pessoas e precipitando a rendição do Japão, pondo fim à Segunda Guerra Mundial no Pacífico."}},
  { id: 'dc-history-0062', deck_id: 'deck-history', front: 'United Nations Founded', back: '1945. Founded after WWII to promote international peace, security, and cooperation; replaced the failed League of Nations with 51 original member states.', sort_order: 62 , front_translations: {"es":"Fundación de las Naciones Unidas","de":"Gründung der Vereinten Nationen","fr":"Fondation des Nations unies","tr":"Birleşmiş Milletler’in Kuruluşu","nl":"Oprichting van de Verenigde Naties","ru":"Основание Организации Объединённых Наций","zh":"联合国成立","pt_BR":"Fundação das Nações Unidas","pt_PT":"Fundação das Nações Unidas"}, back_translations: {"es":"1945. Fundada após a Segunda Guerra Mundial para promover a paz internacional, a seguridad y a cooperación; substituiu a fracassada Liga de las Naciones con 51 estados-membros originais.","de":"1945. Nach dem Zweiten Weltkrieg gegründet, um internationalen Frieden, Sicherheit und Zusammenarbeit zu fördern; ersetzte den gescheiterten Völkerbund mit 51 Gründungsmitgliedern.","fr":"1945. Fondée après la Seconde Guerre mondiale pour promouvoir la paix internationale, la sécurité et la coopération ; elle remplaça la Société des Nations, qui avait échoué, avec 51 États membres fondateurs.","tr":"1945. II. Dünya Savaşı’nın ardından uluslararası barış, güvenlik ve iş birliğini teşvik etmek amacıyla kuruldu; başarısız olan Milletler Cemiyeti’nin yerini 51 kurucu üye devletle aldı.","nl":"1945. Opgericht na de Tweede Wereldoorlog om internationale vrede, veiligheid en samenwerking te bevorderen; verving de mislukte Volkenbond met 51 oorspronkelijke lidstaten.","ru":"1945. Основана после Второй мировой войны для содействия международному миру, безопасности и сотрудничеству; заменила потерпевшую неудачу Лигу Наций с 51 государством-основателем.","zh":"1945年。第二次世界大战后成立，旨在促进国际和平、安全与合作；以51个创始会员国取代了失败的国际联盟。","pt_BR":"1945. Fundada após a Segunda Guerra Mundial para promover a paz internacional, a segurança e a cooperação; substituiu a fracassada Liga das Nações com 51 estados-membros originais.","pt_PT":"1945. Fundada após a Segunda Guerra Mundial para promover a paz internacional, a segurança e a cooperação; substituiu a fracassada Sociedade das Nações com 51 estados-membros originais."}},
  { id: 'dc-history-0063', deck_id: 'deck-history', front: 'Indian Independence', back: '1947. India gained independence from British colonial rule through a nonviolent movement led by Mahatma Gandhi; the partition simultaneously created Pakistan.', sort_order: 63 , front_translations: {"es":"Independencia de la Índia","de":"Indische Unabhängigkeit","fr":"Indépendance de l’Inde","tr":"Hindistan’ın Bağımsızlığı","nl":"Indiase onafhankelijkheid","ru":"Независимость Индии","zh":"印度独立","pt_BR":"Independência da Índia","pt_PT":"Independência da Índia"}, back_translations: {"es":"1947. La Índia conquistou a independencia del domínio colonial británico por medio de un movimiento no violento liderado por Mahatma Gandhi; a partición criou simultáneamente el Paquistão.","de":"1947. Indien erlangte durch eine gewaltfreie Bewegung unter der Führung von Mahatma Gandhi die Unabhängigkeit von der britischen Kolonialherrschaft; die Teilung schuf gleichzeitig Pakistan.","fr":"1947. L’Inde obtint son indépendance de la domination coloniale britannique grâce à un mouvement non violent mené par le Mahatma Gandhi ; la partition créa simultanément le Pakistan.","tr":"1947. Hindistan, Mahatma Gandhi’nin öncülük ettiği şiddetsiz bir hareketle İngiliz sömürge yönetiminden bağımsızlığını kazandı; bölünme aynı anda Pakistan’ı yarattı.","nl":"1947. India verwierf onafhankelijkheid van het Britse koloniale bestuur door een geweldloze beweging onder leiding van Mahatma Gandhi; de verdeling creëerde tegelijkertijd Pakistan.","ru":"1947. Индия обрела независимость от британского колониального правления благодаря ненасильственному движению во главе с Махатмой Ганди; раздел одновременно создал Пакистан.","zh":"1947年。印度通过圣雄甘地领导的非暴力运动从英国殖民统治下获得独立；分治同时创建了巴基斯坦。","pt_BR":"1947. A Índia conquistou a independência do domínio colonial britânico por meio de um movimento não violento liderado por Mahatma Gandhi; a partição criou simultaneamente o Paquistão.","pt_PT":"1947. A Índia conquistou a independência do domínio colonial britânico através de um movimento não violento liderado por Mahatma Gandhi; a partição criou simultaneamente o Paquistão."}},
  { id: 'dc-history-0064', deck_id: 'deck-history', front: 'Mahatma Gandhi', back: '1869–1948. Indian independence leader who pioneered nonviolent civil disobedience (satyagraha) to achieve India\'s freedom from British rule.', sort_order: 64 , front_translations: {"es":"Mahatma Gandhi","de":"Mahatma Gandhi","fr":"Mahatma Gandhi","tr":"Mahatma Gandhi","nl":"Mahatma Gandhi","ru":"Махатма Ганди","zh":"圣雄甘地","pt_BR":"Mahatma Gandhi","pt_PT":"Mahatma Gandhi"}, back_translations: {"es":"1869–1948. Líder de la independencia indiana que fue pionero en la desobediencia civil no violenta (satyagraha) para conquistar a liberdad de la Índia del domínio británico.","de":"1869–1948. Indischer Unabhängigkeitsführer, der den gewaltfreien zivilen Ungehorsam (Satyagraha) als Mittel zur Befreiung Indiens von der britischen Herrschaft entwickelte.","fr":"1869–1948. Leader de l’indépendance indienne qui fut le pionnier de la désobéissance civile non violente (satyagraha) pour obtenir la liberté de l’Inde vis-à-vis de la domination britannique.","tr":"1869–1948. Hindistan’ın İngiliz yönetiminden bağımsızlığını kazanmak için şiddetsiz sivil itaatsizliğe (satyagraha) öncülük eden Hint bağımsızlık lideri.","nl":"1869–1948. Indiase onafhankelijkheidsleider die geweldloos burgerlijk verzet (satyagraha) als methode introduceerde om India’s vrijheid van het Britse bestuur te bereiken.","ru":"1869–1948. Лидер индийского движения за независимость, ставший первопроходцем ненасильственного гражданского неповиновения (сатьяграха) для достижения свободы Индии от британского правления.","zh":"1869–1948年。印度独立运动领袖，开创了非暴力不合作运动（真理坚持），以争取印度摆脱英国殖民统治。","pt_BR":"1869–1948. Líder da independência indiana que foi pioneiro na desobediência civil não violenta (satyagraha) para conquistar a liberdade da Índia do domínio britânico.","pt_PT":"1869–1948. Líder da independência indiana que foi pioneiro na desobediência civil não violenta (satyagraha) para alcançar a liberdade da Índia do domínio britânico."}},
  { id: 'dc-history-0065', deck_id: 'deck-history', front: 'Korean War', back: '1950–1953. A conflict between communist North Korea (backed by China and the USSR) and South Korea (backed by UN forces); ended in armistice with the peninsula still divided.', sort_order: 65 , front_translations: {"es":"Guerra de la Coreia","de":"Koreakrieg","fr":"Guerre de Corée","tr":"Kore Savaşı","nl":"Koreaanse Oorlog","ru":"Корейская война","zh":"朝鲜战争","pt_BR":"Guerra da Coreia","pt_PT":"Guerra da Coreia"}, back_translations: {"es":"1950–1953. Un conflito entre a Coreia del Norte comunista (apoiada por la China y por la URSS) y a Coreia del Sul (apoiada por fuerzas de la ONU); terminou en armistício con a península aún dividida.","de":"1950–1953. Ein Konflikt zwischen dem kommunistischen Nordkorea (unterstützt von China und der UdSSR) und Südkorea (unterstützt von UN-Truppen); endete mit einem Waffenstillstand, wobei die Halbinsel weiterhin geteilt ist.","fr":"1950–1953. Un conflit entre la Corée du Nord communiste (soutenue par la Chine et l’URSS) et la Corée du Sud (soutenue par les forces de l’ONU) ; il se termina par un armistice, la péninsule restant divisée.","tr":"1950–1953. Komünist Kuzey Kore (Çin ve SSCБ destekli) ile Güney Kore (BM kuvvetleri destekli) arasındaki çatışma; yarımadanın hâlâ bölünmüş olduğu bir ateşkesle sona erdi.","nl":"1950–1953. Een conflict tussen het communistische Noord-Korea (gesteund door China en de Sovjet-Unie) en Zuid-Korea (gesteund door VN-troepen); eindigde in een wapenstilstand waarbij het schiereiland nog steeds verdeeld is.","ru":"1950–1953. Конфликт между коммунистической Северной Кореей (при поддержке Китая и СССР) и Южной Кореей (при поддержке войск ООН); завершился перемирием, а полуостров остаётся разделённым.","zh":"1950–1953年。共产主义朝鲜（由中国和苏联支持）与韩国（由联合国军支持）之间的冲突；以停战协定告终，半岛至今仍处于分裂状态。","pt_BR":"1950–1953. Um conflito entre a Coreia do Norte comunista (apoiada pela China e pela URSS) e a Coreia do Sul (apoiada por forças da ONU); terminou em armistício com a península ainda dividida.","pt_PT":"1950–1953. Um conflito entre a Coreia do Norte comunista (apoiada pela China e pela URSS) e a Coreia do Sul (apoiada por forças da ONU); terminou em armistício com a península ainda dividida."}},
  { id: 'dc-history-0066', deck_id: 'deck-history', front: 'Cuban Missile Crisis', back: '1962. A 13-day standoff between the US and USSR over Soviet nuclear missiles in Cuba; the closest the Cold War came to nuclear conflict, resolved through diplomacy.', sort_order: 66 , front_translations: {"es":"Crise de los Mísseis de Cuba","de":"Kubakrise","fr":"Crise des missiles de Cuba","tr":"Küba Füze Krizi","nl":"Cubacrisis","ru":"Карибский кризис","zh":"古巴导弹危机","pt_BR":"Crise dos Mísseis de Cuba","pt_PT":"Crise dos Mísseis de Cuba"}, back_translations: {"es":"1962. Un confronto de 13 dias entre los EUA y a URSS sobre mísseis nucleares soviéticos en Cuba; el momento en que a Guerra Fría más se aproximou de un conflito nuclear, resolvido por medio de la diplomacia.","de":"1962. Ein 13-tägiger Konflikt zwischen den USA und der UdSSR über sowjetische Atomraketen auf Kuba; der Moment, in dem der Kalte Krieg einem Atomkrieg am nächsten kam, wurde durch Diplomatie gelöst.","fr":"1962. Un bras de fer de 13 jours entre les États-Unis et l’URSS au sujet de missiles nucléaires soviétiques à Cuba ; le moment où la guerre froide fut le plus proche d’un conflit nucléaire, résolu par la diplomatie.","tr":"1962. ABD ile SSCB arasında Küba’daki Sovyet nükleer füzeler nedeniyle yaşanan 13 günlük gerginlik; Soğuk Savaş’ın nükleer çatışmaya en çok yaklaştığı an olup diplomasi yoluyla çözüldü.","nl":"1962. Een 13 dagen durende confrontatie tussen de VS en de Sovjet-Unie over Sovjet-kernraketten op Cuba; het dichtst dat de Koude Oorlog bij een nucleair conflict kwam, opgelost door diplomatie.","ru":"1962. 13-дневное противостояние между США и СССР из-за советских ядерных ракет на Кубе; ближайший к ядерному конфликту момент холодной войны, разрешённый дипломатическим путём.","zh":"1962年。美国与苏联因苏联在古巴部署核导弹而对峝13天；这是冷战最接近核冲突的时刻，最终通过外交途径解决。","pt_BR":"1962. Um confronto de 13 dias entre os EUA e a URSS sobre mísseis nucleares soviéticos em Cuba; o momento em que a Guerra Fria mais se aproximou de um conflito nuclear, resolvido por meio da diplomacia.","pt_PT":"1962. Um confronto de 13 dias entre os EUA e a URSS sobre mísseis nucleares soviéticos em Cuba; o momento em que a Guerra Fria mais se aproximou de um conflito nuclear, resolvido pela via diplomática."}},
  { id: 'dc-history-0067', deck_id: 'deck-history', front: 'Vietnam War', back: '1955–1975. A prolonged conflict between communist North Vietnam and US-backed South Vietnam; ended with North Vietnamese victory and Vietnam\'s unification under communist rule.', sort_order: 67 , front_translations: {"es":"Guerra del Vietnã","de":"Vietnamkrieg","fr":"Guerre du Viêt Nam","tr":"Vietnam Savaşı","nl":"Vietnamoorlog","ru":"Вьетнамская война","zh":"越南战争","pt_BR":"Guerra do Vietnã","pt_PT":"Guerra do Vietname"}, back_translations: {"es":"1955–1975. Un conflito prolongado entre el Vietnã del Norte comunista y el Vietnã del Sul apoiado por los EUA; terminou con a vitória norte-vietnamita y a unificación del Vietnã sob regime comunista.","de":"1955–1975. Ein langwieriger Konflikt zwischen dem kommunistischen Nordvietnam und dem von den USA unterstützten Südvietnam; endete mit dem Sieg Nordvietnams und der Wiedervereinigung Vietnams unter kommunistischer Herrschaft.","fr":"1955–1975. Un conflit prolongé entre le Nord-Vietnam communiste et le Sud-Vietnam soutenu par les États-Unis ; il se termina par la victoire nord-vietnamienne et la réunification du Vietnam sous régime communiste.","tr":"1955–1975. Komünist Kuzey Vietnam ile ABD destekli Güney Vietnam arasındaki uzun süreli çatışma; Kuzey Vietnam’ın zaferi ve Vietnam’ın komünist yönetim altında birleşmesiyle sona erdi.","nl":"1955–1975. Een langdurig conflict tussen het communistische Noord-Vietnam en het door de VS gesteunde Zuid-Vietnam; eindigde met de Noord-Vietnamese overwinning en de hereniging van Vietnam onder communistisch bestuur.","ru":"1955–1975. Затяжной конфликт между коммунистическим Северным Вьетнамом и Южным Вьетнамом при поддержке США; завершился победой Северного Вьетнама и объединением страны под коммунистическим правлением.","zh":"1955–1975年。共产主义北越与美国支持的南越之间的长期冲突；以北越胜利和越南在共产主义统治下统一而告终。","pt_BR":"1955–1975. Um conflito prolongado entre o Vietnã do Norte comunista e o Vietnã do Sul apoiado pelos EUA; terminou com a vitória norte-vietnamita e a unificação do Vietnã sob regime comunista.","pt_PT":"1955–1975. Um conflito prolongado entre o Vietname do Norte comunista e o Vietname do Sul apoiado pelos EUA; terminou com a vitória norte-vietnamita e a unificação do Vietname sob regime comunista."}},
  { id: 'dc-history-0068', deck_id: 'deck-history', front: 'Martin Luther King Jr.', back: '1929–1968. A leader of the American Civil Rights Movement who advocated nonviolent protest; his "I Have a Dream" speech and campaigns helped secure landmark civil rights legislation.', sort_order: 68 , front_translations: {"es":"Martin Luther King Jr.","de":"Martin Luther King Jr.","fr":"Martin Luther King Jr.","tr":"Martin Luther King Jr.","nl":"Martin Luther King Jr.","ru":"Мартин Лютер Кинг — младший","zh":"马丁·路德·金","pt_BR":"Martin Luther King Jr.","pt_PT":"Martin Luther King Jr."}, back_translations: {"es":"1929–1968. Un líder del Movimiento de los Derechos Civis americano que defendeu el protesto no violento; su discurso “I Have a Dream” y sus campanhas ajudaram a garantir legislación histórica de derechos civis.","de":"1929–1968. Ein Anführer der amerikanischen Bürgerrechtsbewegung, der gewaltfreien Protest befürwortete; seine Rede „I Have a Dream“ und seine Kampagnen trugen dazu bei, wegweisende Bürgerrechtsgesetze durchzusetzen.","fr":"1929–1968. Un leader du mouvement américain des droits civiques qui prôna la protestation non violente ; son discours « I Have a Dream » et ses campagnes contribuèrent à obtenir des lois historiques sur les droits civiques.","tr":"1929–1968. Şiddetsiz protestoyu savunan Amerikan Sivil Haklar Hareketi’nin bir lideri; “I Have a Dream” konuşması ve kampanyaları, dönüm noktası niteliğindeki sivil haklar yasalarının çıkarılmasına yardımcı oldu.","nl":"1929–1968. Een leider van de Amerikaanse burgerrechtenbeweging die geweldloos protest bepleitte; zijn “I Have a Dream”-toespraak en campagnes hielpen baanbrekende burgerrechtenwetgeving te realiseren.","ru":"1929–1968. Лидер американского движения за гражданские права, выступавший за ненасильственный протест; его речь «У меня есть мечта» и кампании помогли добиться принятия исторических законов о гражданских правах.","zh":"1929–1968年。美国民权运动领袖，倡导非暴力抗议；他的“我有一个梦想”演讲和运动推动了具有里程碑意义的民权立法。","pt_BR":"1929–1968. Um líder do Movimento dos Direitos Civis americano que defendeu o protesto não violento; seu discurso “I Have a Dream” e suas campanhas ajudaram a garantir legislação histórica de direitos civis.","pt_PT":"1929–1968. Um líder do Movimento dos Direitos Civis americano que defendeu o protesto não violento; o seu discurso “I Have a Dream” e as suas campanhas ajudaram a garantir legislação histórica de direitos civis."}},
  { id: 'dc-history-0069', deck_id: 'deck-history', front: 'Civil Rights Act of 1964', back: 'US legislation that outlawed discrimination based on race, color, religion, sex, or national origin; a landmark achievement of the American Civil Rights Movement.', sort_order: 69 , front_translations: {"es":"Ley de los Derechos Civis de 1964","de":"Bürgerrechtsgesetz von 1964","fr":"Loi sur les droits civiques de 1964","tr":"1964 Sivil Haklar Yasası","nl":"Burgerrechtenwet van 1964","ru":"Закон о гражданских правах 1964 года","zh":"1964年民权法案","pt_BR":"Lei dos Direitos Civis de 1964","pt_PT":"Lei dos Direitos Civis de 1964"}, back_translations: {"es":"Legislación de los EUA que proibiu a discriminación con base en raza, cor, religión, sexo o origem nacional; una conquista marcante del Movimiento de los Derechos Civis americano.","de":"US-Gesetzgebung, die Diskriminierung aufgrund von Rasse, Hautfarbe, Religion, Geschlecht oder nationaler Herkunft verbot; ein bahnbrechendes Ergebnis der amerikanischen Bürgerrechtsbewegung.","fr":"Législation américaine interdisant la discrimination fondée sur la race, la couleur, la religion, le sexe ou l'origine nationale ; une réalisation historique du mouvement américain des droits civiques.","tr":"Irk, renk, din, cinsiyet veya ulusal kökene dayalı ayrımcılığı yasaklayan ABD yasası; Amerikan Sivil Haklar Hareketi'nin dönüm noktası niteliğinde bir başarısı.","nl":"Amerikaanse wetgeving die discriminatie op basis van ras, huidskleur, religie, geslacht of nationale afkomst verbood; een mijlpaal van de Amerikaanse burgerrechtenbeweging.","ru":"Законодательство США, запретившее дискриминацию по признаку расы, цвета кожи, вероисповедания, пола или национального происхождения; знаковое достижение американского движения за гражданские права.","zh":"美国立法禁止基于种族、肤色、宗教、性别或国籍的歧视；是美国民权运动的里程碑式成就。","pt_BR":"Legislação dos EUA que proibiu a discriminação com base em raça, cor, religião, sexo ou origem nacional; uma conquista marcante do Movimento dos Direitos Civis americano.","pt_PT":"Legislação dos EUA que proibiu a discriminação com base na raça, cor, religião, sexo ou origem nacional; uma conquista marcante do Movimento dos Direitos Civis americano."}},
  { id: 'dc-history-0070', deck_id: 'deck-history', front: 'Nelson Mandela', back: '1918–2013. South African anti-apartheid revolutionary who spent 27 years in prison; became the first democratically elected President of South Africa in 1994.', sort_order: 70 , front_translations: {"es":"Nelson Mandela","de":"Nelson Mandela","fr":"Nelson Mandela","tr":"Nelson Mandela","nl":"Nelson Mandela","ru":"Нельсон Мандела","zh":"纳尔逊·曼德拉","pt_BR":"Nelson Mandela","pt_PT":"Nelson Mandela"}, back_translations: {"es":"1918–2013. Revolucionário sul-africano antiapartheid que passou 27 anos en la prisão; tornou-se el primero presidente democraticamente eleito de la África del Sul en 1994.","de":"1918–2013. Südafrikanischer Anti-Apartheid-Revolutionär, der 27 Jahre im Gefängnis verbrachte; wurde 1994 der erste demokratisch gewählte Präsident Südafrikas.","fr":"1918–2013. Révolutionnaire sud-africain anti-apartheid qui passa 27 ans en prison ; devint le premier président démocratiquement élu d'Afrique du Sud en 1994.","tr":"1918–2013. 27 yıl cezaevinde kalan Güney Afrikalı apartheid karşıtı devrimci; 1994'te Güney Afrika'nın demokratik yollarla seçilen ilk cumhurbaşkanı oldu.","nl":"1918–2013. Zuid-Afrikaanse anti-apartheidsrevolutionair die 27 jaar in de gevangenis doorbracht; werd in 1994 de eerste democratisch gekozen president van Zuid-Afrika.","ru":"1918–2013. Южноафриканский борец против апартеида, проведший 27 лет в тюрьме; в 1994 году стал первым демократически избранным президентом ЮАР.","zh":"1918–2013年。南非反种族隔离革命家，曾入狱27年；1994年成为南非首位民主选举产生的总统。","pt_BR":"1918–2013. Revolucionário sul-africano antiapartheid que passou 27 anos na prisão; tornou-se o primeiro presidente democraticamente eleito da África do Sul em 1994.","pt_PT":"1918–2013. Revolucionário sul-africano anti-apartheid que passou 27 anos na prisão; tornou-se o primeiro presidente democraticamente eleito da África do Sul em 1994."}},
  { id: 'dc-history-0071', deck_id: 'deck-history', front: 'End of Apartheid', back: '1994. South Africa held its first multiracial democratic elections, ending the apartheid system of racial segregation; Nelson Mandela was elected President.', sort_order: 71 , front_translations: {"es":"Fin del Apartheid","de":"Ende der Apartheid","fr":"Fin de l'apartheid","tr":"Apartheid'in Sonu","nl":"Einde van de apartheid","ru":"Конец апартеида","zh":"种族隔离制度的终结","pt_BR":"Fim do Apartheid","pt_PT":"Fim do Apartheid"}, back_translations: {"es":"1994. La África del Sul realizou sus primeras eleiciones democráticas multirraciais, encerrando el sistema de segregación racial del apartheid; Nelson Mandela fue eleito presidente.","de":"1994. Südafrika hielt seine ersten multiethnischen demokratischen Wahlen ab und beendete damit das Apartheid-System der Rassentrennung; Nelson Mandela wurde zum Präsidenten gewählt.","fr":"1994. L'Afrique du Sud a tenu ses premières élections démocratiques multiraciales, mettant fin au système d'apartheid de ségrégation raciale ; Nelson Mandela a été élu président.","tr":"1994. Güney Afrika, ırk ayrımcılığı sistemini sona erdiren ilk çok ırklı demokratik seçimlerini gerçekleştirdi; Nelson Mandela cumhurbaşkanı seçildi.","nl":"1994. Zuid-Afrika hield zijn eerste multiraciale democratische verkiezingen, waarmee het apartheidssysteem van rassenscheiding eindigde; Nelson Mandela werd tot president gekozen.","ru":"1994. В ЮАР прошли первые многорасовые демократические выборы, положившие конец системе расовой сегрегации — апартеиду; Нельсон Мандела был избран президентом.","zh":"1994年。南非举行了首次多种族民主选举，结束了种族隔离制度；纳尔逊·曼德拉当选总统。","pt_BR":"1994. A África do Sul realizou suas primeiras eleições democráticas multirraciais, encerrando o sistema de segregação racial do apartheid; Nelson Mandela foi eleito presidente.","pt_PT":"1994. A África do Sul realizou as suas primeiras eleições democráticas multirraciais, pondo fim ao sistema de segregação racial do apartheid; Nelson Mandela foi eleito presidente."}},
  { id: 'dc-history-0072', deck_id: 'deck-history', front: 'Mesopotamia', back: 'Often called the "cradle of civilization"; located between the Tigris and Euphrates rivers (modern Iraq), it was home to the world\'s first cities, writing (cuneiform), and legal codes.', sort_order: 72 , front_translations: {"es":"Mesopotamia","de":"Mesopotamien","fr":"Mésopotamie","tr":"Mezopotamya","nl":"Mesopotamië","ru":"Месопотамия","zh":"美索不达米亚","pt_BR":"Mesopotâmia","pt_PT":"Mesopotâmia"}, back_translations: {"es":"Frecuentemente llamada de “berço de la civilización”; localizada entre los rios Tigre y Eufrates (atual Iraque), fue el lar de las primeras cidades, de la escrita (cuneiforme) y de los primeros códigos legais del mundo.","de":"Oft als „Wiege der Zivilisation“ bezeichnet; zwischen Tigris und Euphrat gelegen (heutiger Irak), war sie Heimat der ersten Städte, der Schrift (Keilschrift) und der ersten Gesetzeswerke der Welt.","fr":"Souvent appelée le « berceau de la civilisation » ; située entre le Tigre et l’Euphrate (Irak actuel), elle abritait les premières villes, l’écriture (cunéiforme) et les premiers codes juridiques au monde.","tr":"Sıklıkla “uygarlığın beşiği” olarak adlandırılır; Dicle ve Fırat nehirleri arasında (bugünkü Irak) yer alan bu bölge, dünyanın ilk şehirlerine, yazıya (çivi yazısı) ve hukuk kurallarına ev sahipliği yaptı.","nl":"Vaak de “bakermat van de beschaving” genoemd; gelegen tussen de Tigris en de Eufraat (het huidige Irak), was het de thuisbasis van ’s werelds eerste steden, schrift (spijkerschrift) en wetboeken.","ru":"Часто называемая «колыбелью цивилизации»; расположенная между реками Тигр и Евфрат (современный Ирак), она была родиной первых в мире городов, письменности (клинописи) и сводов законов.","zh":"常被称为“文明的摇篮”；位于底格里斯河和幼发拉底河之间（今伊拉克），是世界上最早的城市、文字（楔形文字）和法典的发源地。","pt_BR":"Frequentemente chamada de “berço da civilização”; localizada entre os rios Tigre e Eufrates (atual Iraque), foi o lar das primeiras cidades, da escrita (cuneiforme) e dos primeiros códigos legais do mundo.","pt_PT":"Frequentemente chamada de “berço da civilização”; localizada entre os rios Tigre e Eufrates (atual Iraque), foi o lar das primeiras cidades, da escrita (cuneiforme) e dos primeiros códigos legais do mundo."}},
  { id: 'dc-history-0073', deck_id: 'deck-history', front: 'Code of Hammurabi', back: 'c. 1754 BCE. One of the oldest and most complete legal codes from ancient Babylonia; it established the principle of lex talionis ("an eye for an eye").', sort_order: 73 , front_translations: {"es":"Código de Hamurabi","de":"Codex Hammurabi","fr":"Code de Hammurabi","tr":"Hammurabi Kanunları","nl":"Codex van Hammurabi","ru":"Кодекс Хаммурапи","zh":"汉谟拉比法典","pt_BR":"Código de Hamurabi","pt_PT":"Código de Hamurabi"}, back_translations: {"es":"c. 1754 a.C. Un de los más antigos y completos códigos legais de la antiga Babilonia; estabeleceu el principio de la lex talionis (\"ojo por ojo\").","de":"Ca. 1754 v. Chr. Einer der ältesten und vollständigsten Gesetzeskodizes aus dem antiken Babylonien; er etablierte das Prinzip der Lex talionis (\"Auge um Auge\").","fr":"Vers 1754 av. J.-C. L'un des codes juridiques les plus anciens et les plus complets de l'ancienne Babylonie ; il a établi le principe du lex talionis (\"œil pour œil\").","tr":"MÖ yaklaşık 1754. Antik Babil'den günümüze ulaşan en eski ve en eksiksiz hukuk kodlarından biri; kısas ilkesini (\"göze göz\") belirlemiştir.","nl":"Ca. 1754 v.Chr. Een van de oudste en meest volledige wetboeken uit het oude Babylonië; het vestigde het principe van lex talionis (\"oog om oog\").","ru":"Ок. 1754 г. до н. э. Один из древнейших и наиболее полных сводов законов Древнего Вавилона; он установил принцип талиона (\"око за око\").","zh":"约公元前1754年。古巴比伦最古老、最完整的法典之一；确立了同态复仇原则（\"以眼还眼\"）。","pt_BR":"c. 1754 a.C. Um dos mais antigos e completos códigos legais da antiga Babilônia; estabeleceu o princípio da lex talionis (\"olho por olho\").","pt_PT":"c. 1754 a.C. Um dos mais antigos e completos códigos legais da antiga Babilónia; estabeleceu o princípio da lex talionis (\"olho por olho\")."}},
  { id: 'dc-history-0074', deck_id: 'deck-history', front: 'Ancient Egyptian Civilization', back: 'c. 3100–30 BCE. One of the longest-lasting civilizations in history, known for pharaonic rule, hieroglyphic writing, pyramids, and the Nile River agricultural system.', sort_order: 74 , front_translations: {"es":"Civilización del Antigo Egito","de":"Altägyptische Zivilisation","fr":"Civilisation de l'Égypte antique","tr":"Antik Mısır Uygarlığı","nl":"Oud-Egyptische beschaving","ru":"Древнеегипетская цивилизация","zh":"古埃及文明","pt_BR":"Civilização do Antigo Egito","pt_PT":"Civilização do Antigo Egito"}, back_translations: {"es":"c. 3100–30 a.C. Una de las civilizaciones más duradouras de la historia, conocida por el gobierno faraonico, escrita hieroglífica, piramides y el sistema agrícola del Rio Nilo.","de":"Ca. 3100–30 v. Chr. Eine der langlebigsten Zivilisationen der Geschichte, bekannt für pharaonische Herrschaft, Hieroglyphenschrift, Pyramiden und das landwirtschaftliche System am Nil.","fr":"Vers 3100–30 av. J.-C. L'une des civilisations les plus durables de l'histoire, connue pour le règne pharaonique, l'écriture hiéroglyphique, les pyramides et le système agricole du Nil.","tr":"MÖ yaklaşık 3100–30. Tarihin en uzun süren uygarlıklarından biri; firavun yönetimi, hiyeroglif yazısı, piramitler ve Nil Nehri tarım sistemiyle tanınır.","nl":"Ca. 3100–30 v.Chr. Een van de langstdurende beschavingen in de geschiedenis, bekend om het faraonisch bestuur, hiëroglifisch schrift, piramides en het landbouwsysteem van de Nijl.","ru":"Ок. 3100–30 гг. до н. э. Одна из самых долговечных цивилизаций в истории, известная властью фараонов, иероглифическим письмом, пирамидами и сельскохозяйственной системой долины Нила.","zh":"约公元前3100–30年。历史上最持久的文明之一，以法老统治、象形文字、金字塔和尼罗河农业系统闻名。","pt_BR":"c. 3100–30 a.C. Uma das civilizações mais duradouras da história, conhecida pelo governo faraônico, escrita hieroglífica, pirâmides e o sistema agrícola do Rio Nilo.","pt_PT":"c. 3100–30 a.C. Uma das civilizações mais duradouras da história, conhecida pelo governo faraónico, escrita hieroglífica, pirâmides e o sistema agrícola do Rio Nilo."}},
  { id: 'dc-history-0075', deck_id: 'deck-history', front: 'Cleopatra VII', back: '69–30 BCE. The last active ruler of the Ptolemaic Kingdom of Egypt; formed alliances with Julius Caesar and Mark Antony before dying as Octavian conquered Egypt for Rome.', sort_order: 75 , front_translations: {"es":"Cleópatra VII","de":"Kleopatra VII.","fr":"Cléopâtre VII","tr":"VII. Kleopatra","nl":"Cleopatra VII","ru":"Клеопатра VII","zh":"克利奥帕特拉七世","pt_BR":"Cleópatra VII","pt_PT":"Cleópatra VII"}, back_translations: {"es":"69–30 a.C. La última governante ativa del Reino Ptolemaico del Egito; formou alianzas con Júlio César y Marco Antonio antes de morrer cuando Otaviano conquistou el Egito para Roma.","de":"69–30 v. Chr. Die letzte aktive Herrscherin des ptolemäischen Königreichs Ägypten; ging Bündnisse mit Julius Cäsar und Marcus Antonius ein, bevor sie starb, als Octavian Ägypten für Rom eroberte.","fr":"69–30 av. J.-C. La dernière souveraine active du royaume ptolémaïque d'Égypte ; elle forma des alliances avec Jules César et Marc Antoine avant de mourir lors de la conquête de l'Égypte par Octave pour Rome.","tr":"MÖ 69–30. Ptolemaios Krallığı'nın son aktif hükümdarı; Jül Sezar ve Marcus Antonius ile ittifaklar kurdu, Octavianus Mısır'ı Roma adına fethettiğinde hayatını kaybetti.","nl":"69–30 v.Chr. De laatste actieve heerseres van het Ptolemaeïsche Koninkrijk van Egypte; sloot allianties met Julius Caesar en Marcus Antonius voordat ze stierf toen Octavianus Egypte voor Rome veroverde.","ru":"69–30 гг. до н. э. Последняя правительница Птолемеевского царства в Египте; заключала союзы с Юлием Цезарем и Марком Антонием и погибла, когда Октавиан завоевал Египет для Рима.","zh":"公元前69–30年。托勒密王国最后一位实际统治者；先后与尤利乌斯·凯撒和马克·安东尼结盟，在屋大维征服埃及归于罗马后去世。","pt_BR":"69–30 a.C. A última governante ativa do Reino Ptolemaico do Egito; formou alianças com Júlio César e Marco Antônio antes de morrer quando Otaviano conquistou o Egito para Roma.","pt_PT":"69–30 a.C. A última governante ativa do Reino Ptolemaico do Egito; formou alianças com Júlio César e Marco António antes de morrer quando Otaviano conquistou o Egito para Roma."}},
  { id: 'dc-history-0076', deck_id: 'deck-history', front: 'Athenian Democracy', back: 'c. 508 BCE. Cleisthenes introduced democratic reforms in Athens, creating the world\'s first democracy where male citizens voted on legislation and policy.', sort_order: 76 , front_translations: {"es":"Democracia Ateniense","de":"Athenische Demokratie","fr":"Démocratie athénienne","tr":"Atina Demokrasisi","nl":"Atheense democratie","ru":"Афинская демократия","zh":"雅典民主制","pt_BR":"Democracia Ateniense","pt_PT":"Democracia Ateniense"}, back_translations: {"es":"c. 508 a.C. Clístenes introduziu reformas democráticas en Atenas, creando a primera democracia del mundo, donde cidadãos hombres votavam en legislación y políticas.","de":"Um 508 v. Chr. Kleisthenes führte demokratische Reformen in Athen ein und schuf die erste Demokratie der Welt, in der männliche Bürger über Gesetze und Politik abstimmten.","fr":"Vers 508 av. J.-C. Clisthène introduisit des réformes démocratiques à Athènes, créant la première démocratie au monde où les citoyens masculins votaient les lois et les politiques.","tr":"MÖ yaklaşık 508. Kleisthenes, Atina’da demokratik reformlar başlatarak erkek vatandaşların yasama ve politika üzerinde oy kullandığı dünyanın ilk demokrasisini oluşturdu.","nl":"Ca. 508 v.Chr. Cleisthenes voerde democratische hervormingen door in Athene en creëerde ’s werelds eerste democratie waarin mannelijke burgers stemden over wetgeving en beleid.","ru":"Ок. 508 г. до н. э. Клисфен провёл демократические реформы в Афинах, создав первую в мире демократию, в которой граждане-мужчины голосовали по вопросам законодательства и политики.","zh":"约公元前508年。克利斯提尼在雅典推行民主改革，创建了世界上第一个民主制度，男性公民可以对立法和政策进行投票。","pt_BR":"c. 508 a.C. Clístenes introduziu reformas democráticas em Atenas, criando a primeira democracia do mundo, onde cidadãos homens votavam em legislação e políticas.","pt_PT":"c. 508 a.C. Clístenes introduziu reformas democráticas em Atenas, criando a primeira democracia do mundo, na qual os cidadãos masculinos votavam sobre legislação e políticas."}},
  { id: 'dc-history-0077', deck_id: 'deck-history', front: 'Socrates', back: '470–399 BCE. Athenian philosopher who developed the Socratic method of inquiry; he was tried and executed for impiety and corrupting the youth, his ideas preserved by Plato.', sort_order: 77 , front_translations: {"es":"Sócrates","de":"Sokrates","fr":"Socrate","tr":"Sokrates","nl":"Socrates","ru":"Сократ","zh":"苏格拉底","pt_BR":"Sócrates","pt_PT":"Sócrates"}, back_translations: {"es":"470–399 a.C. Filósofo ateniense que desenvolveu el método socrático de investigación; fue julgado y executado por impiedad y corrupción de la juventude, sus ideias fueron preservadas por Platão.","de":"470–399 v. Chr. Athenischer Philosoph, der die sokratische Methode der Befragung entwickelte; er wurde wegen Gottlosigkeit und Verführung der Jugend verurteilt und hingerichtet, seine Ideen wurden von Platon überliefert.","fr":"470–399 av. J.-C. Philosophe athénien qui a développé la méthode socratique d'interrogation ; il fut jugé et exécuté pour impiété et corruption de la jeunesse, ses idées furent préservées par Platon.","tr":"MÖ 470–399. Sokratik sorgulama yöntemini geliştiren Atinalı filozof; dinsizlik ve gençliği yozlaştırma suçlamasıyla yargılanıp idam edildi, fikirleri Platon tarafından korundu.","nl":"470–399 v.Chr. Atheense filosoof die de socratische methode van ondervraging ontwikkelde; hij werd berecht en ter dood gebracht wegens goddeloosheid en het bederven van de jeugd, zijn ideeën werden bewaard door Plato.","ru":"470–399 гг. до н. э. Афинский философ, разработавший сократический метод; был осуждён и казнён за безбожие и развращение молодёжи, его идеи сохранены Платоном.","zh":"公元前470–399年。雅典哲学家，创立了苏格拉底式提问法；因不敬神和腐蚀青年之罪被审判处死，其思想由柏拉图记录保存。","pt_BR":"470–399 a.C. Filósofo ateniense que desenvolveu o método socrático de investigação; foi julgado e executado por impiedade e corrupção da juventude, suas ideias foram preservadas por Platão.","pt_PT":"470–399 a.C. Filósofo ateniense que desenvolveu o método socrático de investigação; foi julgado e executado por impiedade e corrupção da juventude, as suas ideias foram preservadas por Platão."}},
  { id: 'dc-history-0078', deck_id: 'deck-history', front: 'Aristotle', back: '384–322 BCE. Greek philosopher who tutored Alexander the Great and wrote foundational works on logic, biology, politics, ethics, and physics that shaped Western thought for millennia.', sort_order: 78 , front_translations: {"es":"Aristóteles","de":"Aristoteles","fr":"Aristote","tr":"Aristoteles","nl":"Aristoteles","ru":"Аристотель","zh":"亚里士多德","pt_BR":"Aristóteles","pt_PT":"Aristóteles"}, back_translations: {"es":"384–322 a.C. Filósofo grego que fue tutor de Alexandre, el Grande, y escreveu obras fundamentales sobre lógica, biologia, política, ética y física que moldaram el pensamiento ocidental por milenios.","de":"384–322 v. Chr. Griechischer Philosoph, der Alexander den Großen unterrichtete und grundlegende Werke über Logik, Biologie, Politik, Ethik und Physik verfasste, die das westliche Denken über Jahrtausende prägten.","fr":"384–322 av. J.-C. Philosophe grec qui fut le précepteur d'Alexandre le Grand et rédigea des œuvres fondamentales sur la logique, la biologie, la politique, l'éthique et la physique qui ont façonné la pensée occidentale pendant des millénaires.","tr":"MÖ 384–322. Büyük İskender'in hocası olan ve mantık, biyoloji, siyaset, etik ve fizik üzerine temel eserler yazan Yunan filozof; Batı düşüncesini bin yıllar boyunca şekillendirmiştir.","nl":"384–322 v.Chr. Griekse filosoof die Alexander de Grote onderwees en fundamentele werken schreef over logica, biologie, politiek, ethiek en natuurkunde die het westerse denken millennia lang vormden.","ru":"384–322 гг. до н. э. Греческий философ, наставник Александра Македонского, автор основополагающих трудов по логике, биологии, политике, этике и физике, определивших западную мысль на тысячелетия.","zh":"公元前384–322年。希腊哲学家，曾担任亚历山大大帝的老师，撰写了逻辑学、生物学、政治学、伦理学和物理学的奠基性著作，影响了西方思想数千年。","pt_BR":"384–322 a.C. Filósofo grego que foi tutor de Alexandre, o Grande, e escreveu obras fundamentais sobre lógica, biologia, política, ética e física que moldaram o pensamento ocidental por milênios.","pt_PT":"384–322 a.C. Filósofo grego que foi tutor de Alexandre, o Grande, e escreveu obras fundamentais sobre lógica, biologia, política, ética e física que moldaram o pensamento ocidental durante milénios."}},
  { id: 'dc-history-0079', deck_id: 'deck-history', front: 'Battle of Hastings', back: '1066. William the Conqueror defeated King Harold II of England, beginning Norman rule and fundamentally transforming English language, culture, and feudal institutions.', sort_order: 79 , front_translations: {"es":"Batalla de Hastings","de":"Schlacht bei Hastings","fr":"Bataille de Hastings","tr":"Hastings Muharebesi","nl":"Slag bij Hastings","ru":"Битва при Гастингсе","zh":"黑斯廷斯战役","pt_BR":"Batalha de Hastings","pt_PT":"Batalha de Hastings"}, back_translations: {"es":"1066. Guilherme, el Conquistador, derrotou el rey Haroldo II de la Inglaterra, iniciando el domínio normando y transformando profundamente a língua, cultura y instituciones feudais inglesas.","de":"1066. Wilhelm der Eroberer besiegte König Harold II. von England und leitete die normannische Herrschaft ein, die die englische Sprache, Kultur und das Feudalwesen grundlegend veränderte.","fr":"1066. Guillaume le Conquérant vainquit le roi Harold II d'Angleterre, inaugurant la domination normande et transformant profondément la langue, la culture et les institutions féodales anglaises.","tr":"1066. Fatih William, İngiltere Kralı II. Harold'u yenerek Norman yönetimini başlattı ve İngiliz dilini, kültürünü ve feodal kurumlarını köklü biçimde dönüştürdü.","nl":"1066. Willem de Veroveraar versloeg koning Harold II van Engeland, wat het begin markeerde van de Normandische heerschappij en de Engelse taal, cultuur en feodale instellingen ingrijpend veranderde.","ru":"1066. Вильгельм Завоеватель разгромил короля Гарольда II, положив начало нормандскому правлению и коренным образом изменив английский язык, культуру и феодальные институты.","zh":"1066年。征服者威廉击败英格兰国王哈罗德二世，开启了诺曼统治，从根本上改变了英语、英国文化和封建制度。","pt_BR":"1066. Guilherme, o Conquistador, derrotou o rei Haroldo II da Inglaterra, iniciando o domínio normando e transformando profundamente a língua, cultura e instituições feudais inglesas.","pt_PT":"1066. Guilherme, o Conquistador, derrotou o rei Haroldo II de Inglaterra, iniciando o domínio normando e transformando profundamente a língua, cultura e instituições feudais inglesas."}},
  { id: 'dc-history-0080', deck_id: 'deck-history', front: 'The Silk Road', back: '2nd century BCE–15th century CE. A network of trade routes connecting China, Central Asia, India, the Middle East, and Europe; it facilitated exchange of goods, ideas, and diseases.', sort_order: 80 , front_translations: {"es":"La Rota de la Seda","de":"Die Seidenstraße","fr":"La Route de la soie","tr":"İpek Yolu","nl":"De Zijderoute","ru":"Великий шёлковый путь","zh":"丝绸之路","pt_BR":"A Rota da Seda","pt_PT":"A Rota da Seda"}, back_translations: {"es":"Siglo II a.C.–siglo XV d.C. Una red de rotas comerciais conectando China, Ásia Central, Índia, Oriente Médio y Europa; facilitou el intercambio de mercadorias, ideias y enfermedades.","de":"2. Jh. v. Chr.–15. Jh. n. Chr. Ein Netzwerk von Handelsrouten, das China, Zentralasien, Indien, den Nahen Osten und Europa verband; es erleichterte den Austausch von Waren, Ideen und Krankheiten.","fr":"IIe siècle av. J.-C.–XVe siècle apr. J.-C. Un réseau de routes commerciales reliant la Chine, l'Asie centrale, l'Inde, le Moyen-Orient et l'Europe ; il facilita l'échange de marchandises, d'idées et de maladies.","tr":"MÖ 2. yüzyıl–MS 15. yüzyıl. Çin, Orta Asya, Hindistan, Orta Doğu ve Avrupa'yı birbirine bağlayan ticaret yolları ağı; mal, fikir ve hastalıkların alışverişini kolaylaştırmıştır.","nl":"2e eeuw v.Chr.–15e eeuw n.Chr. Een netwerk van handelsroutes dat China, Centraal-Azië, India, het Midden-Oosten en Europa verbond; het vergemakkelijkte de uitwisseling van goederen, ideeën en ziekten.","ru":"II в. до н. э.–XV в. н. э. Сеть торговых путей, связывавших Китай, Центральную Азию, Индию, Ближний Восток и Европу; способствовала обмену товарами, идеями и болезнями.","zh":"公元前2世纪–公元15世纪。连接中国、中亚、印度、中东和欧洲的贸易路线网络；促进了商品、思想和疾病的传播交流。","pt_BR":"Século II a.C.–século XV d.C. Uma rede de rotas comerciais conectando China, Ásia Central, Índia, Oriente Médio e Europa; facilitou o intercâmbio de mercadorias, ideias e doenças.","pt_PT":"Século II a.C.–século XV d.C. Uma rede de rotas comerciais que ligava a China, a Ásia Central, a Índia, o Médio Oriente e a Europa; facilitou o intercâmbio de mercadorias, ideias e doenças."}},
  { id: 'dc-history-0081', deck_id: 'deck-history', front: 'Genghis Khan', back: 'c. 1162–1227. Founded and led the Mongol Empire, the largest contiguous empire in history; his conquests killed millions but unified trade routes across Eurasia.', sort_order: 81 , front_translations: {"es":"Gengis Khan","de":"Dschingis Khan","fr":"Gengis Khan","tr":"Cengiz Han","nl":"Dzjengis Khan","ru":"Чингисхан","zh":"成吉思汗","pt_BR":"Gêngis Khan","pt_PT":"Gêngis Khan"}, back_translations: {"es":"c. 1162–1227. Fundou y liderou el Imperio Mongol, el mayor imperio contiguo de la historia; sus conquistas mataram milhões, pero unificaram rotas comerciais por toda a Eurásia.","de":"Ca. 1162–1227. Gründete und führte das Mongolenreich, das größte zusammenhängende Reich der Geschichte; seine Eroberungen töteten Millionen, vereinten aber Handelsrouten über ganz Eurasien.","fr":"Vers 1162–1227. Fonda et dirigea l'Empire mongol, le plus grand empire continental de l'histoire ; ses conquêtes firent des millions de morts mais unifièrent les routes commerciales à travers l'Eurasie.","tr":"Yaklaşık 1162–1227. Tarihin en büyük kesintisiz kara imparatorluğu olan Moğol İmparatorluğu'nu kurdu ve yönetti; fetihleri milyonlarca insanı öldürdü ancak Avrasya genelinde ticaret yollarını birleştirdi.","nl":"Ca. 1162–1227. Stichtte en leidde het Mongoolse Rijk, het grootste aaneengesloten rijk in de geschiedenis; zijn veroveringen kostten miljoenen levens maar verenigden handelsroutes door heel Eurazië.","ru":"Ок. 1162–1227. Основал и возглавил Монгольскую империю — крупнейшую сухопутную империю в истории; его завоевания унесли миллионы жизней, но объединили торговые пути через всю Евразию.","zh":"约1162–1227年。建立并领导了蒙古帝国，这是历史上最大的连续陆地帝国；他的征服杀死了数百万人，但统一了欧亚大陆的贸易路线。","pt_BR":"c. 1162–1227. Fundou e liderou o Império Mongol, o maior império contíguo da história; suas conquistas mataram milhões, mas unificaram rotas comerciais por toda a Eurásia.","pt_PT":"c. 1162–1227. Fundou e liderou o Império Mongol, o maior império contíguo da história; as suas conquistas mataram milhões, mas unificaram rotas comerciais por toda a Eurásia."}},
  { id: 'dc-history-0082', deck_id: 'deck-history', front: 'Gutenberg Bible', back: '1455. The first major book printed using movable type in Europe, marking the beginning of the age of mass book production and transforming literacy and knowledge distribution.', sort_order: 82 , front_translations: {"es":"Bíblia de Gutenberg","de":"Gutenberg-Bibel","fr":"Bible de Gutenberg","tr":"Gutenberg İncili","nl":"Gutenbergbijbel","ru":"Библия Гутенберга","zh":"古腾堡圣经","pt_BR":"Bíblia de Gutenberg","pt_PT":"Bíblia de Gutenberg"}, back_translations: {"es":"1455. El primero grande livro impresso con tipos móveis en la Europa, marcando el início de la era de la producción en masa de livros y transformando a alfabetización y a distribución del conocimiento.","de":"1455. Das erste bedeutende Buch, das in Europa mit beweglichen Lettern gedruckt wurde; es markierte den Beginn des Zeitalters der Massenproduktion von Büchern und veränderte die Alphabetisierung und Wissensverbreitung.","fr":"1455. Le premier livre majeur imprimé à l'aide de caractères mobiles en Europe, marquant le début de l'ère de la production de livres en masse et transformant l'alphabétisation et la diffusion du savoir.","tr":"1455. Avrupa'da hareketli harflerle basılan ilk büyük kitap; kitapların seri üretim çağını başlattı ve okuryazarlığı ile bilginin yayılmasını dönüştürdü.","nl":"1455. Het eerste grote boek dat in Europa met losse letters werd gedrukt, wat het begin markeerde van het tijdperk van massale boekproductie en een transformatie teweegbracht in geletterdheid en kennisverspreiding.","ru":"1455. Первая крупная книга, напечатанная с помощью подвижного шрифта в Европе; ознаменовала начало эпохи массового книгопечатания и преобразила грамотность и распространение знаний.","zh":"1455年。欧洲第一部使用活字印刷术印制的重要书籍，标志着大规模书籍生产时代的开始，改变了识字率和知识传播方式。","pt_BR":"1455. O primeiro grande livro impresso com tipos móveis na Europa, marcando o início da era da produção em massa de livros e transformando a alfabetização e a distribuição do conhecimento.","pt_PT":"1455. O primeiro grande livro impresso com tipos móveis na Europa, marcando o início da era da produção em massa de livros e transformando a literacia e a distribuição do conhecimento."}},
  { id: 'dc-history-0083', deck_id: 'deck-history', front: 'Spanish Inquisition', back: '1478–1834. Established by Ferdinand and Isabella of Spain to enforce Catholic orthodoxy; it used torture and execution, expelling or forcibly converting Jews and Muslims.', sort_order: 83 , front_translations: {"es":"Inquisición Espanhola","de":"Spanische Inquisition","fr":"Inquisition espagnole","tr":"İspanyol Engizisyonu","nl":"Spaanse Inquisitie","ru":"Испанская инквизиция","zh":"西班牙宗教裁判所","pt_BR":"Inquisição Espanhola","pt_PT":"Inquisição Espanhola"}, back_translations: {"es":"1478–1834. Estabelecida por Fernando y Isabel de la Espanha para impor a ortodoxia católica; utilizou tortura y execución, expulsando o convirtiendo a la fuerza judeus y musulmanes.","de":"1478–1834. Von Ferdinand und Isabella von Spanien gegründet, um die katholische Orthodoxie durchzusetzen; sie setzte Folter und Hinrichtungen ein und vertrieb oder zwangsbekehrte Juden und Muslime.","fr":"1478–1834. Établie par Ferdinand et Isabelle d'Espagne pour imposer l'orthodoxie catholique ; elle recourut à la torture et à l'exécution, expulsant ou convertissant de force juifs et musulmans.","tr":"1478–1834. Katolik ortodoksluğu dayatmak için İspanya'nın Ferdinand ve Isabella'sı tarafından kuruldu; işkence ve idam kullandı, Yahudileri ve Müslümanları sürgün etti veya zorla din değiştirtti.","nl":"1478–1834. Opgericht door Ferdinand en Isabella van Spanje om de katholieke orthodoxie te handhaven; gebruikte marteling en executie, en verdreef of dwong joden en moslims tot bekering.","ru":"1478–1834. Учреждена Фердинандом и Изабеллой Испанскими для утверждения католической ортодоксии; применяла пытки и казни, изгоняла или насильственно обращала евреев и мусульман.","zh":"1478–1834年。由西班牙的费迪南和伊莎贝拉设立，以维护天主教正统；使用酷刑和处决手段，驱逐或强制转化犹太人和穆斯林。","pt_BR":"1478–1834. Estabelecida por Fernando e Isabel da Espanha para impor a ortodoxia católica; utilizou tortura e execução, expulsando ou convertendo à força judeus e muçulmanos.","pt_PT":"1478–1834. Estabelecida por Fernando e Isabel de Espanha para impor a ortodoxia católica; utilizou tortura e execução, expulsando ou convertendo à força judeus e muçulmanos."}},
  { id: 'dc-history-0084', deck_id: 'deck-history', front: 'Thirty Years\' War', back: '1618–1648. A devastating European conflict beginning as a religious war between Protestants and Catholics that killed up to one-third of Germany\'s population; ended by the Peace of Westphalia.', sort_order: 84 , front_translations: {"es":"Guerra de los Trinta Anos","de":"Dreißigjähriger Krieg","fr":"Guerre de Trente Ans","tr":"Otuz Yıl Savaşları","nl":"Dertigjarige Oorlog","ru":"Тридцатилетняя война","zh":"三十年战争","pt_BR":"Guerra dos Trinta Anos","pt_PT":"Guerra dos Trinta Anos"}, back_translations: {"es":"1618–1648. Un conflito europeu devastador que começou como una guerra religiosa entre protestantes y católicos y matou hasta un terço de la población de la Alemanha; encerrado por la Paz de Vestfália.","de":"1618–1648. Ein verheerender europäischer Konflikt, der als Religionskrieg zwischen Protestanten und Katholiken begann und bis zu einem Drittel der deutschen Bevölkerung tötete; beendet durch den Westfälischen Frieden.","fr":"1618–1648. Un conflit européen dévastateur commencé comme une guerre de religion entre protestants et catholiques qui tua jusqu’à un tiers de la population allemande ; terminé par la paix de Westphalie.","tr":"1618–1648. Protestanlar ile Katolikler arasında bir din savaşı olarak başlayan ve Almanya nüfusunun üçte birini öldüren yıkıcı bir Avrupa çatışması; Vestfalya Barışı ile sona erdi.","nl":"1618–1648. Een verwoestend Europees conflict dat begon als een godsdienstoorlog tussen protestanten en katholieken en tot een derde van de Duitse bevolking doodde; beëindigd door de Vrede van Westfalen.","ru":"1618–1648. Разрушительный европейский конфликт, начавшийся как религиозная война между протестантами и католиками, унёсший до трети населения Германии; завершился Вестфальским миром.","zh":"1618–1648年。一场毁灭性的欧洲冲突，始于新教徒与天主教徒之间的宗教战争，造成德国多达三分之一的人口死亡；以《威斯特伐利亚和约》告终。","pt_BR":"1618–1648. Um conflito europeu devastador que começou como uma guerra religiosa entre protestantes e católicos e matou até um terço da população da Alemanha; encerrado pela Paz de Vestfália.","pt_PT":"1618–1648. Um conflito europeu devastador que começou como uma guerra religiosa entre protestantes e católicos e matou até um terço da população da Alemanha; terminado pela Paz de Vestfália."}},
  { id: 'dc-history-0085', deck_id: 'deck-history', front: 'Peace of Westphalia', back: '1648. Treaties ending the Thirty Years\' War that established the modern concept of state sovereignty and are considered the foundation of the modern international system.', sort_order: 85 , front_translations: {"es":"Paz de Vestfália","de":"Westfälischer Frieden","fr":"Paix de Westphalie","tr":"Vestfalya Barışı","nl":"Vrede van Westfalen","ru":"Вестфальский мир","zh":"威斯特伐利亚和约","pt_BR":"Paz de Vestfália","pt_PT":"Paz de Vestfália"}, back_translations: {"es":"1648. Tratados que encerraram a Guerra de los Trinta Anos y estabeleceram el concepto moderno de soberania estatal; son considerados a base del sistema internacional moderno.","de":"1648. Verträge zur Beendigung des Dreißigjährigen Krieges, die das moderne Konzept der Staatssouveränität begründeten und als Grundlage des modernen internationalen Systems gelten.","fr":"1648. Traités mettant fin à la guerre de Trente Ans qui établirent le concept moderne de souveraineté étatique et sont considérés comme le fondement du système international moderne.","tr":"1648. Otuz Yıl Savaşları’nı sona erdiren ve modern devlet egemenliği kavramını ortaya koyan antlaşmalar; modern uluslararası sistemin temeli olarak kabul edilir.","nl":"1648. Verdragen die de Dertigjarige Oorlog beëindigden en het moderne concept van staatssoevereiniteit vestigden; worden beschouwd als de grondslag van het moderne internationale systeem.","ru":"1648. Договоры, завершившие Тридцатилетнюю войну, установившие современную концепцию государственного суверенитета и считающиеся основой современной международной системы.","zh":"1648年。结束三十年战争的条约，确立了现代国家主权概念，被视为现代国际体系的基础。","pt_BR":"1648. Tratados que encerraram a Guerra dos Trinta Anos e estabeleceram o conceito moderno de soberania estatal; são considerados a base do sistema internacional moderno.","pt_PT":"1648. Tratados que puseram fim à Guerra dos Trinta Anos e estabeleceram o conceito moderno de soberania estatal; são considerados a base do sistema internacional moderno."}},
  { id: 'dc-history-0086', deck_id: 'deck-history', front: 'Isaac Newton', back: '1643–1727. English mathematician and physicist who formulated laws of motion and universal gravitation, invented calculus, and is widely regarded as one of the greatest scientists in history.', sort_order: 86 , front_translations: {"es":"Isaac Newton","de":"Isaac Newton","fr":"Isaac Newton","tr":"Isaac Newton","nl":"Isaac Newton","ru":"Исаак Ньютон","zh":"艾萨克·牛顿","pt_BR":"Isaac Newton","pt_PT":"Isaac Newton"}, back_translations: {"es":"1643–1727. Matemático y físico ingles que formulou las leyes del movimiento y de la gravitación universal, inventou el cálculo y es amplamente considerado un de los mayores cientistas de la historia.","de":"1643–1727. Englischer Mathematiker und Physiker, der die Gesetze der Bewegung und der universellen Gravitation formulierte, die Infinitesimalrechnung erfand und weithin als einer der größten Wissenschaftler der Geschichte gilt.","fr":"1643–1727. Mathématicien et physicien anglais qui formula les lois du mouvement et de la gravitation universelle, inventa le calcul infinitésimal et est largement considéré comme l'un des plus grands scientifiques de l'histoire.","tr":"1643–1727. Hareket yasalarını ve evrensel çekim yasasını formüle eden, kalkülüsü icat eden ve tarihin en büyük bilim insanlarından biri olarak kabul edilen İngiliz matematikçi ve fizikçi.","nl":"1643–1727. Engelse wiskundige en natuurkundige die de bewegingswetten en de universele gravitatiewet formuleerde, de calculus uitvond en algemeen wordt beschouwd als een van de grootste wetenschappers in de geschiedenis.","ru":"1643–1727. Английский математик и физик, сформулировавший законы движения и всемирного тяготения, изобретатель математического анализа; считается одним из величайших учёных в истории.","zh":"1643–1727年。英国数学家和物理学家，提出了运动定律和万有引力定律，发明了微积分，被广泛认为是历史上最伟大的科学家之一。","pt_BR":"1643–1727. Matemático e físico inglês que formulou as leis do movimento e da gravitação universal, inventou o cálculo e é amplamente considerado um dos maiores cientistas da história.","pt_PT":"1643–1727. Matemático e físico inglês que formulou as leis do movimento e da gravitação universal, inventou o cálculo e é amplamente considerado um dos maiores cientistas da história."}},
  { id: 'dc-history-0087', deck_id: 'deck-history', front: 'Seven Years\' War', back: '1756–1763. Often considered the first "world war," fought across five continents; it reshaped colonial empires, with Britain gaining vast territories from France in North America and India.', sort_order: 87 , front_translations: {"es":"Guerra de los Siete Anos","de":"Siebenjähriger Krieg","fr":"Guerre de Sept Ans","tr":"Yedi Yıl Savaşları","nl":"Zevenjarige Oorlog","ru":"Семилетняя война","zh":"七年战争","pt_BR":"Guerra dos Sete Anos","pt_PT":"Guerra dos Sete Anos"}, back_translations: {"es":"1756–1763. Frecuentemente considerada a primera “guerra mundial”, travada en cinco continentes; remodelou los imperios coloniais, con a Grã-Bretanha adquirindo vastos territorios de la França en la América del Norte y en la Índia.","de":"1756–1763. Oft als erster „Weltkrieg“ betrachtet, auf fünf Kontinenten geführt; er gestaltete die Kolonialreiche um, wobei Großbritannien von Frankreich riesige Gebiete in Nordamerika und Indien gewann.","fr":"1756–1763. Souvent considérée comme la première « guerre mondiale », menée sur cinq continents ; elle remodela les empires coloniaux, la Grande-Bretagne acquérant de vastes territoires de la France en Amérique du Nord et en Inde.","tr":"1756–1763. Genellikle ilk “dünya savaşı” olarak kabul edilen, beş kıtada sürdürülen savaş; sömürge imparatorluklarını yeniden şekillendirdi ve Britanya, Kuzey Amerika ve Hindistan’da Fransa’dan geniş topraklar kazandı.","nl":"1756–1763. Vaak beschouwd als de eerste “wereldoorlog”, uitgevochten op vijf continenten; het vormde koloniale rijken opnieuw, waarbij Groot-Brittannië uitgestrekte gebieden van Frankrijk verwierf in Noord-Amerika en India.","ru":"1756–1763. Часто считается первой «мировой войной», велась на пяти континентах; она перекроила колониальные империи — Великобритания получила обширные территории Франции в Северной Америке и Индии.","zh":"1756–1763年。常被视为第一场“世界大战”，战火遍及五大洲；它重塑了殖民帝国格局，英国从法国手中夺取了北美和印度的大片领土。","pt_BR":"1756–1763. Frequentemente considerada a primeira “guerra mundial”, travada em cinco continentes; remodelou os impérios coloniais, com a Grã-Bretanha adquirindo vastos territórios da França na América do Norte e na Índia.","pt_PT":"1756–1763. Frequentemente considerada a primeira “guerra mundial”, travada em cinco continentes; remodelou os impérios coloniais, com a Grã-Bretanha a adquirir vastos territórios da França na América do Norte e na Índia."}},
  { id: 'dc-history-0088', deck_id: 'deck-history', front: 'Boston Tea Party', back: '1773. American colonists protesting taxation without representation dumped British tea into Boston Harbor, a pivotal act of defiance leading to the American Revolution.', sort_order: 88 , front_translations: {"es":"Festa del Chá de Boston","de":"Boston Tea Party","fr":"Boston Tea Party","tr":"Boston Çay Partisi","nl":"Boston Tea Party","ru":"Бостонское чаепитие","zh":"波士顿倾茶事件","pt_BR":"Festa do Chá de Boston","pt_PT":"Festa do Chá de Boston"}, back_translations: {"es":"1773. Colonos americanos protestando contra a tributación sin representación despejaram chá británico en el porto de Boston, un ato decisivo de desafio que levou a la Revolución Americana.","de":"1773. Amerikanische Kolonisten, die gegen Besteuerung ohne Vertretung protestierten, warfen britischen Tee in den Hafen von Boston – ein entscheidender Akt des Widerstands, der zur Amerikanischen Revolution führte.","fr":"1773. Des colons américains protestant contre la taxation sans représentation jetèrent du thé britannique dans le port de Boston, un acte de défi décisif menant à la Révolution américaine.","tr":"1773. Temsil edilmeden vergilendirilmeyi protesto eden Amerikan koloniciler, Boston Limanı'na İngiliz çaylarını döktü; bu olay Amerikan Devrimi'ne giden yolda kritik bir başkaldırı eylemi oldu.","nl":"1773. Amerikaanse kolonisten die protesteerden tegen belasting zonder vertegenwoordiging gooiden Britse thee in de haven van Boston, een cruciale daad van verzet die leidde tot de Amerikaanse Revolutie.","ru":"1773. Американские колонисты, протестовавшие против налогообложения без представительства, сбросили британский чай в Бостонскую гавань — ключевой акт неповиновения, приведший к Американской революции.","zh":"1773年。抗议\"无代表不纳税\"的美国殖民者将英国茶叶倾倒入波士顿港，这一关键性的反抗行为最终促成了美国独立革命。","pt_BR":"1773. Colonos americanos protestando contra a tributação sem representação despejaram chá britânico no porto de Boston, um ato decisivo de desafio que levou à Revolução Americana.","pt_PT":"1773. Colonos americanos que protestavam contra a tributação sem representação despejaram chá britânico no porto de Boston, um ato decisivo de desafio que conduziu à Revolução Americana."}},
  { id: 'dc-history-0089', deck_id: 'deck-history', front: 'Reign of Terror', back: '1793–1794. The most radical phase of the French Revolution under Robespierre, during which ~17,000 people were executed by guillotine in the name of the Republic.', sort_order: 89 , front_translations: {"es":"Reinado del Terror","de":"Schreckensherrschaft","fr":"La Terreur","tr":"Terör Dönemi","nl":"Schrikbewind","ru":"Якобинский террор","zh":"恐怖统治时期","pt_BR":"Reinado do Terror","pt_PT":"Reino do Terror"}, back_translations: {"es":"1793–1794. La fase más radical de la Revolución Francesa sob Robespierre, durante a qual cerca de 17.000 personas fueron executadas por la guilhotina en nombre de la República.","de":"1793–1794. Die radikalste Phase der Französischen Revolution unter Robespierre, in der etwa 17.000 Menschen im Namen der Republik durch die Guillotine hingerichtet wurden.","fr":"1793–1794. La phase la plus radicale de la Révolution française sous Robespierre, au cours de laquelle environ 17 000 personnes furent exécutées par la guillotine au nom de la République.","tr":"1793–1794. Fransız Devrimi'nin Robespierre yönetimindeki en radikal dönemi; Cumhuriyet adına yaklaşık 17.000 kişi giyotinle idam edildi.","nl":"1793–1794. De meest radicale fase van de Franse Revolutie onder Robespierre, waarin ~17.000 mensen werden geëxecuteerd met de guillotine in naam van de Republiek.","ru":"1793–1794. Наиболее радикальный этап Французской революции при Робеспьере, когда около 17 000 человек были казнены на гильотине во имя Республики.","zh":"1793–1794年。法国大革命中罗伯斯庇尔领导下最激进的阶段，约17,000人以共和国之名被送上断头台处决。","pt_BR":"1793–1794. A fase mais radical da Revolução Francesa sob Robespierre, durante a qual cerca de 17.000 pessoas foram executadas pela guilhotina em nome da República.","pt_PT":"1793–1794. A fase mais radical da Revolução Francesa sob Robespierre, durante a qual cerca de 17.000 pessoas foram executadas pela guilhotina em nome da República."}},
  { id: 'dc-history-0090', deck_id: 'deck-history', front: 'Congress of Vienna', back: '1814–1815. A conference of European powers after Napoleon\'s defeat that reestablished conservative monarchies and created a balance of power that maintained relative European peace for decades.', sort_order: 90 , front_translations: {"es":"Congresso de Viena","de":"Wiener Kongress","fr":"Congrès de Vienne","tr":"Viyana Kongresi","nl":"Congres van Wenen","ru":"Венский конгресс","zh":"维也纳会议","pt_BR":"Congresso de Viena","pt_PT":"Congresso de Viena"}, back_translations: {"es":"1814–1815. Una conferencia de las potencias europeias após a derrota de Napoleão que restabeleceu monarquias conservadoras y criou un equilíbrio de poder que manteve relativa paz europeia por décadas.","de":"1814–1815. Eine Konferenz europäischer Mächte nach Napoleons Niederlage, die konservative Monarchien wiederherstellte und ein Gleichgewicht der Kräfte schuf, das über Jahrzehnte relativen Frieden in Europa sicherte.","fr":"1814–1815. Une conférence des puissances européennes après la défaite de Napoléon qui rétablit les monarchies conservatrices et créa un équilibre des pouvoirs maintenant une paix relative en Europe pendant des décennies.","tr":"1814–1815. Napolyon'un yenilgisinin ardından toplanan Avrupa güçleri konferansı; muhafazakâr monarşileri yeniden kurdu ve onlarca yıl Avrupa'da görece barışı sürdüren bir güç dengesi oluşturdu.","nl":"1814–1815. Een conferentie van Europese mogendheden na de nederlaag van Napoleon die conservatieve monarchieën herstelde en een machtsevenwicht creëerde dat decennialang relatieve vrede in Europa handhaafde.","ru":"1814–1815 годы. Конференция европейских держав после поражения Наполеона, восстановившая консервативные монархии и создавшая баланс сил, обеспечивший относительный мир в Европе на десятилетия.","zh":"1814–1815年。拿破仑战败后欧洲列强召开的会议，恢复了保守君主制并建立了力量均衡，维持了欧洲数十年的相对和平。","pt_BR":"1814–1815. Uma conferência das potências europeias após a derrota de Napoleão que restabeleceu monarquias conservadoras e criou um equilíbrio de poder que manteve relativa paz europeia por décadas.","pt_PT":"1814–1815. Uma conferência das potências europeias após a derrota de Napoleão que restabeleceu monarquias conservadoras e criou um equilíbrio de poder que manteve uma relativa paz europeia durante décadas."}},
  { id: 'dc-history-0091', deck_id: 'deck-history', front: 'Opium Wars', back: '1839–1842 and 1856–1860. Britain forced China to open trade ports and legalize opium imports; these wars revealed China\'s weakness and began the "century of humiliation."', sort_order: 91 , front_translations: {"es":"Guerras del Ópio","de":"Opiumkriege","fr":"Guerres de l'opium","tr":"Afyon Savaşları","nl":"Opiumoorlogen","ru":"Опиумные войны","zh":"鸦片战争","pt_BR":"Guerras do Ópio","pt_PT":"Guerras do Ópio"}, back_translations: {"es":"1839–1842 y 1856–1860. La Grã-Bretanha forçou a China a abrir portos comerciais y legalizar importaciones de ópio; essas guerras revelaram a fraqueza de la China y deram início al \"siglo de humilhación\".","de":"1839–1842 und 1856–1860. Großbritannien zwang China, Handelshäfen zu öffnen und Opiumimporte zu legalisieren; diese Kriege offenbarten Chinas Schwäche und leiteten das „Jahrhundert der Demütigung“ ein.","fr":"1839–1842 et 1856–1860. La Grande-Bretagne força la Chine à ouvrir des ports commerciaux et à légaliser les importations d'opium ; ces guerres révélèrent la faiblesse de la Chine et inaugurèrent le « siècle d'humiliation ».","tr":"1839–1842 ve 1856–1860. İngiltere, Çin'i ticaret limanlarını açmaya ve afyon ithalatını yasallaştırmaya zorladı; bu savaşlar Çin'in zayıflığını ortaya koydu ve \"yüzyıllık aşağılanma\" dönemini başlattı.","nl":"1839–1842 en 1856–1860. Groot-Brittannië dwong China handelshavens te openen en opiumimport te legaliseren; deze oorlogen onthulden China's zwakte en luidden de \"eeuw van vernedering\" in.","ru":"1839–1842 и 1856–1860 годы. Великобритания вынудила Китай открыть торговые порты и легализовать импорт опиума; эти войны обнажили слабость Китая и положили начало «столетию унижений».","zh":"1839–1842年和1856–1860年。英国迫使中国开放通商口岸并允许鸦片进口；这些战争暴露了中国的衰弱，开启了\"百年屈辱\"时代。","pt_BR":"1839–1842 e 1856–1860. A Grã-Bretanha forçou a China a abrir portos comerciais e legalizar importações de ópio; essas guerras revelaram a fraqueza da China e deram início ao \"século de humilhação\".","pt_PT":"1839–1842 e 1856–1860. A Grã-Bretanha forçou a China a abrir portos comerciais e a legalizar as importações de ópio; estas guerras revelaram a fraqueza da China e deram início ao \"século de humilhação\"."}},
  { id: 'dc-history-0092', deck_id: 'deck-history', front: 'Charles Darwin and Natural Selection', back: '1859. Darwin published "On the Origin of Species," arguing all species evolved through natural selection; it revolutionized biology and challenged religious accounts of human origins.', sort_order: 92 , front_translations: {"es":"Charles Darwin y a Seleción Natural","de":"Charles Darwin und die natürliche Selektion","fr":"Charles Darwin et la sélection naturelle","tr":"Charles Darwin ve Doğal Seçilim","nl":"Charles Darwin en natuurlijke selectie","ru":"Чарлз Дарвин и естественный отбор","zh":"查尔斯·达尔文与自然选择","pt_BR":"Charles Darwin e a Seleção Natural","pt_PT":"Charles Darwin e a Seleção Natural"}, back_translations: {"es":"1859. Darwin publicou \"A Origem de las Especies\", argumentando que todas las especies evoluíram por seleción natural; eso revolucionou a biologia y desafiou relatos religiosos sobre las origens humanas.","de":"1859. Darwin veröffentlichte \"Die Entstehung der Arten\" und argumentierte, dass alle Arten durch natürliche Selektion entstanden seien; dies revolutionierte die Biologie und stellte religiöse Erklärungen zur Herkunft des Menschen in Frage.","fr":"1859. Darwin publia \"De l'origine des espèces\", soutenant que toutes les espèces ont évolué par sélection naturelle ; cela révolutionna la biologie et remit en question les récits religieux sur les origines humaines.","tr":"1859. Darwin \"Türlerin Kökeni\" adlı eserini yayımladı ve tüm türlerin doğal seçilim yoluyla evrildiğini savundu; bu, biyolojide devrim yarattı ve insanın kökenine dair dinî anlatıları sorguladı.","nl":"1859. Darwin publiceerde \"Over het ontstaan der soorten\" en betoogde dat alle soorten door natuurlijke selectie zijn geëvolueerd; het revolutioneerde de biologie en daagde religieuze verklaringen over de oorsprong van de mens uit.","ru":"1859. Дарвин опубликовал «Происхождение видов», утверждая, что все виды возникли путём естественного отбора; это произвело революцию в биологии и поставило под сомнение религиозные представления о происхождении человека.","zh":"1859年。达尔文发表《物种起源》，论证所有物种都通过自然选择进化而来；此书革新了生物学，并挑战了关于人类起源的宗教叙述。","pt_BR":"1859. Darwin publicou \"A Origem das Espécies\", argumentando que todas as espécies evoluíram por seleção natural; isso revolucionou a biologia e desafiou relatos religiosos sobre as origens humanas.","pt_PT":"1859. Darwin publicou \"A Origem das Espécies\", argumentando que todas as espécies evoluíram por seleção natural; isto revolucionou a biologia e desafiou os relatos religiosos sobre as origens humanas."}},
  { id: 'dc-history-0093', deck_id: 'deck-history', front: 'Suez Canal Opens', back: '1869. The canal connecting the Mediterranean to the Red Sea opened, dramatically shortening sea routes between Europe and Asia and increasing strategic importance of Egypt.', sort_order: 93 , front_translations: {"es":"Abertura del Canal de Suez","de":"Eröffnung des Suezkanals","fr":"Ouverture du canal de Suez","tr":"Süveyş Kanalı'nın Açılışı","nl":"Opening van het Suezkanaal","ru":"Открытие Суэцкого канала","zh":"苏伊士运河通航","pt_BR":"Abertura do Canal de Suez","pt_PT":"Abertura do Canal de Suez"}, back_translations: {"es":"1869. El canal conectando el Mediterraneo al Mar Rojo fue inaugurado, encurtando drasticamente las rotas marítimas entre Europa y Ásia y aumentando a importancia estratégica del Egito.","de":"1869. Der Kanal, der das Mittelmeer mit dem Roten Meer verbindet, wurde eröffnet und verkürzte die Seewege zwischen Europa und Asien drastisch, was die strategische Bedeutung Ägyptens erhöhte.","fr":"1869. Le canal reliant la Méditerranée à la mer Rouge fut inauguré, raccourcissant considérablement les routes maritimes entre l'Europe et l'Asie et augmentant l'importance stratégique de l'Égypte.","tr":"1869. Akdeniz'i Kızıldeniz'e bağlayan kanal açıldı; Avrupa ile Asya arasındaki deniz yollarını büyük ölçüde kısalttı ve Mısır'ın stratejik önemini artırdı.","nl":"1869. Het kanaal dat de Middellandse Zee met de Rode Zee verbindt werd geopend, waardoor zeeroutes tussen Europa en Azië drastisch werden verkort en het strategisch belang van Egypte toenam.","ru":"1869. Канал, соединивший Средиземное и Красное моря, был открыт, резко сократив морские пути между Европой и Азией и повысив стратегическое значение Египта.","zh":"1869年。连接地中海和红海的运河通航，大幅缩短了欧洲与亚洲之间的海上航线，提升了埃及的战略重要性。","pt_BR":"1869. O canal conectando o Mediterrâneo ao Mar Vermelho foi inaugurado, encurtando drasticamente as rotas marítimas entre Europa e Ásia e aumentando a importância estratégica do Egito.","pt_PT":"1869. O canal que liga o Mediterrâneo ao Mar Vermelho foi inaugurado, encurtando drasticamente as rotas marítimas entre a Europa e a Ásia e aumentando a importância estratégica do Egito."}},
  { id: 'dc-history-0094', deck_id: 'deck-history', front: 'Boxer Rebellion', back: '1899–1901. A Chinese nationalist uprising against foreign imperialism and Christian missionaries; defeated by an eight-nation alliance, it further weakened the Qing Dynasty.', sort_order: 94 , front_translations: {"es":"Revolta de los Boxers","de":"Boxeraufstand","fr":"Révolte des Boxers","tr":"Boxer Ayaklanması","nl":"Bokseropstand","ru":"Боксёрское восстание","zh":"义和团运动","pt_BR":"Revolta dos Boxers","pt_PT":"Revolta dos Boxers"}, back_translations: {"es":"1899–1901. Una revolta nacionalista chinesa contra el imperialismo estrangero y missionários cristianos; derrotada por una alianza de ocho naciones, enfraqueceu aún más a Dinastia Qing.","de":"1899–1901. Ein chinesischer nationalistischer Aufstand gegen ausländischen Imperialismus und christliche Missionare; von einer Allianz aus acht Nationen niedergeschlagen, schwächte er die Qing-Dynastie weiter.","fr":"1899–1901. Un soulèvement nationaliste chinois contre l'impérialisme étranger et les missionnaires chrétiens ; vaincu par une alliance de huit nations, il affaiblit davantage la dynastie Qing.","tr":"1899–1901. Yabancı emperyalizme ve Hristiyan misyonerlere karşı Çin milliyetçi ayaklanması; sekiz devletin ittifakı tarafından yenilgiye uğratıldı ve Qing Hanedanlığı'nı daha da zayıflattı.","nl":"1899–1901. Een Chinese nationalistische opstand tegen buitenlands imperialisme en christelijke missionarissen; verslagen door een alliantie van acht naties, wat de Qing-dynastie verder verzwakte.","ru":"1899–1901. Китайское националистическое восстание против иностранного империализма и христианских миссионеров; подавлено альянсом восьми держав, что ещё больше ослабило династию Цин.","zh":"1899–1901年。中国民族主义者反对外国帝国主义和基督教传教士的起义；被八国联军击败，进一步削弱了清朝统治。","pt_BR":"1899–1901. Uma revolta nacionalista chinesa contra o imperialismo estrangeiro e missionários cristãos; derrotada por uma aliança de oito nações, enfraqueceu ainda mais a Dinastia Qing.","pt_PT":"1899–1901. Uma revolta nacionalista chinesa contra o imperialismo estrangeiro e missionários cristãos; derrotada por uma aliança de oito nações, enfraqueceu ainda mais a Dinastia Qing."}},
  { id: 'dc-history-0095', deck_id: 'deck-history', front: 'Russo-Japanese War', back: '1904–1905. Japan\'s surprising victory over Russia was the first time an Asian nation defeated a major European power in modern warfare, signaling Japan\'s emergence as a world power.', sort_order: 95 , front_translations: {"es":"Guerra Russo-Japonesa","de":"Russisch-Japanischer Krieg","fr":"Guerre russo-japonaise","tr":"Rus-Japon Savaşı","nl":"Russisch-Japanse Oorlog","ru":"Русско-японская война","zh":"日俄战争","pt_BR":"Guerra Russo-Japonesa","pt_PT":"Guerra Russo-Japonesa"}, back_translations: {"es":"1904–1905. La surpreendente vitória del Japão sobre a Rússia fue a primera vez que una nación asiática derrotou una grande potencia europeia en guerra moderna, sinalizando a emergencia del Japão como potencia mundial.","de":"1904–1905. Japans überraschender Sieg über Russland war das erste Mal, dass eine asiatische Nation eine europäische Großmacht in einem modernen Krieg besiegte, und signalisierte Japans Aufstieg zur Weltmacht.","fr":"1904–1905. La victoire surprenante du Japon sur la Russie fut la première fois qu'une nation asiatique vainquit une grande puissance européenne dans une guerre moderne, signalant l'émergence du Japon comme puissance mondiale.","tr":"1904–1905. Japonya'nın Rusya'ya karşı şaşırtıcı zaferi, modern savaşta bir Asya ulusunun büyük bir Avrupa gücünü yendiği ilk olaydı ve Japonya'nın dünya gücü olarak yükselişinin habercisi oldu.","nl":"1904–1905. Japans verrassende overwinning op Rusland was de eerste keer dat een Aziatische natie een grote Europese mogendheid versloeg in moderne oorlogsvoering, wat Japans opkomst als wereldmacht signaleerde.","ru":"1904–1905 годы. Неожиданная победа Японии над Россией стала первым случаем, когда азиатская страна одержала верх над крупной европейской державой в современной войне, ознаменовав выход Японии на мировую арену.","zh":"1904–1905年。日本出人意料地击败俄罗斯，这是近代战争中亚洲国家首次战胜欧洲大国，标志着日本崛起为世界强国。","pt_BR":"1904–1905. A surpreendente vitória do Japão sobre a Rússia foi a primeira vez que uma nação asiática derrotou uma grande potência europeia em guerra moderna, sinalizando a emergência do Japão como potência mundial.","pt_PT":"1904–1905. A surpreendente vitória do Japão sobre a Rússia foi a primeira vez que uma nação asiática derrotou uma grande potência europeia em guerra moderna, assinalando a emergência do Japão como potência mundial."}},
  { id: 'dc-history-0096', deck_id: 'deck-history', front: 'Titanic Sinks', back: '1912. The RMS Titanic sank on its maiden voyage after striking an iceberg, killing ~1,500 people; it led to major reforms in maritime safety regulations.', sort_order: 96 , front_translations: {"es":"Naufrágio del Titanic","de":"Untergang der Titanic","fr":"Naufrage du Titanic","tr":"Titanik'in Batışı","nl":"Ondergang van de Titanic","ru":"Гибель «Титаника»","zh":"泰坦尼克号沉没","pt_BR":"Naufrágio do Titanic","pt_PT":"Naufrágio do Titanic"}, back_translations: {"es":"1912. El RMS Titanic naufragou en su viaje inaugural após colidir con un iceberg, matando cerca de 1.500 personas; eso levou a grandes reformas en las regulamentaciones de seguridad marítima.","de":"1912. Die RMS Titanic sank auf ihrer Jungfernfahrt nach der Kollision mit einem Eisberg; etwa 1.500 Menschen kamen ums Leben. Das Unglück führte zu grundlegenden Reformen der Seefahrtssicherheit.","fr":"1912. Le RMS Titanic a coulé lors de son voyage inaugural après avoir heurté un iceberg, tuant environ 1 500 personnes ; cela a conduit à des réformes majeures des réglementations de sécurité maritime.","tr":"1912. RMS Titanic ilk seferinde bir buzdağına çarparak battı ve yaklaşık 1.500 kişi hayatını kaybetti; bu olay deniz güvenliği düzenlemelerinde büyük reformlara yol açtı.","nl":"1912. De RMS Titanic zonk op haar eerste reis na een aanvaring met een ijsberg, waarbij ~1.500 mensen omkwamen; het leidde tot ingrijpende hervormingen van de maritieme veiligheidsvoorschriften.","ru":"1912. «Титаник» затонул в своём первом рейсе после столкновения с айсбергом; погибло около 1 500 человек. Катастрофа привела к масштабным реформам в области морской безопасности.","zh":"1912年。泰坦尼克号在首航中撞上冰山后沉没，约1,500人遇难；此事件促成了海上安全法规的重大改革。","pt_BR":"1912. O RMS Titanic naufragou em sua viagem inaugural após colidir com um iceberg, matando cerca de 1.500 pessoas; isso levou a grandes reformas nas regulamentações de segurança marítima.","pt_PT":"1912. O RMS Titanic naufragou na sua viagem inaugural após colidir com um icebergue, matando cerca de 1.500 pessoas; isto levou a grandes reformas nos regulamentos de segurança marítima."}},
  { id: 'dc-history-0097', deck_id: 'deck-history', front: 'Spanish Civil War', back: '1936–1939. A conflict between the Republican government and Nationalist forces under Franco; it served as a prelude to WWII with Nazi Germany and Fascist Italy aiding Franco.', sort_order: 97 , front_translations: {"es":"Guerra Civil Espanhola","de":"Spanischer Bürgerkrieg","fr":"Guerre civile espagnole","tr":"İspanya İç Savaşı","nl":"Spaanse Burgeroorlog","ru":"Гражданская война в Испании","zh":"西班牙内战","pt_BR":"Guerra Civil Espanhola","pt_PT":"Guerra Civil Espanhola"}, back_translations: {"es":"1936–1939. Un conflito entre el gobierno republicano y las fuerzas nacionalistas sob Franco; serviu como prelúdio de la Segunda Guerra Mundial, con a Alemanha Nazista y a Itália Fascista apoiando Franco.","de":"1936–1939. Ein Konflikt zwischen der republikanischen Regierung und den nationalistischen Truppen unter Franco; er diente als Vorspiel zum Zweiten Weltkrieg, wobei NS-Deutschland und das faschistische Italien Franco unterstützten.","fr":"1936–1939. Un conflit entre le gouvernement républicain et les forces nationalistes de Franco ; il servit de prélude à la Seconde Guerre mondiale, l'Allemagne nazie et l'Italie fasciste soutenant Franco.","tr":"1936–1939. Cumhuriyet hükümeti ile Franco liderliğindeki Milliyetçi güçler arasındaki çatışma; Nazi Almanyası ve Faşist İtalya'nın Franco'yu desteklemesiyle İkinci Dünya Savaşı'nın habercisi oldu.","nl":"1936–1939. Een conflict tussen de republikeinse regering en de nationalistische troepen onder Franco; het diende als opmaat naar de Tweede Wereldoorlog, waarbij nazi-Duitsland en fascistisch Italië Franco steunden.","ru":"1936–1939. Конфликт между республиканским правительством и националистами под командованием Франко; стал прелюдией ко Второй мировой войне — нацистская Германия и фашистская Италия поддержали Франко.","zh":"1936–1939年。共和政府与弗朗哥领导的民族主义势力之间的冲突；纳粹德国和法西斯意大利援助弗朗哥，此战成为二战的前奏。","pt_BR":"1936–1939. Um conflito entre o governo republicano e as forças nacionalistas sob Franco; serviu como prelúdio da Segunda Guerra Mundial, com a Alemanha Nazista e a Itália Fascista apoiando Franco.","pt_PT":"1936–1939. Um conflito entre o governo republicano e as forças nacionalistas sob Franco; serviu como prelúdio da Segunda Guerra Mundial, com a Alemanha Nazi e a Itália Fascista a apoiarem Franco."}},
  { id: 'dc-history-0098', deck_id: 'deck-history', front: 'Marshall Plan', back: '1948–1952. The American program providing economic aid to rebuild Western European economies after WWII; it helped prevent the spread of communism and restored prosperity.', sort_order: 98 , front_translations: {"es":"Plano Marshall","de":"Marshallplan","fr":"Plan Marshall","tr":"Marshall Planı","nl":"Marshallplan","ru":"План Маршалла","zh":"马歇尔计划","pt_BR":"Plano Marshall","pt_PT":"Plano Marshall"}, back_translations: {"es":"1948–1952. El programa americano de ayuda económica para reconstruir las economias de la Europa Ocidental após a Segunda Guerra Mundial; ajudou a prevenir a expansão del comunismo y restaurar a prosperidad.","de":"1948–1952. Das amerikanische Programm zur wirtschaftlichen Hilfe für den Wiederaufbau westeuropäischer Volkswirtschaften nach dem Zweiten Weltkrieg; es half, die Ausbreitung des Kommunismus zu verhindern und den Wohlstand wiederherzustellen.","fr":"1948–1952. Le programme américain d'aide économique pour reconstruire les économies d'Europe occidentale après la Seconde Guerre mondiale ; il contribua à empêcher la propagation du communisme et à restaurer la prospérité.","tr":"1948–1952. İkinci Dünya Savaşı sonrası Batı Avrupa ekonomilerini yeniden inşa etmek için ekonomik yardım sağlayan Amerikan programı; komünizmin yayılmasını önlemeye ve refahı yeniden sağlamaya yardımcı oldu.","nl":"1948–1952. Het Amerikaanse programma dat economische hulp bood om West-Europese economieën na de Tweede Wereldoorlog te herbouwen; het hielp de verspreiding van het communisme te voorkomen en de welvaart te herstellen.","ru":"1948–1952. Американская программа экономической помощи для восстановления западноевропейских экономик после Второй мировой войны; помогла предотвратить распространение коммунизма и возродить процветание.","zh":"1948–1952年。美国为重建二战后西欧经济而提供经济援助的计划；帮助阻止了共产主义的蔓延并恢复了繁荣。","pt_BR":"1948–1952. O programa americano de ajuda econômica para reconstruir as economias da Europa Ocidental após a Segunda Guerra Mundial; ajudou a prevenir a expansão do comunismo e restaurar a prosperidade.","pt_PT":"1948–1952. O programa americano de ajuda económica para reconstruir as economias da Europa Ocidental após a Segunda Guerra Mundial; ajudou a prevenir a expansão do comunismo e a restaurar a prosperidade."}},
  { id: 'dc-history-0099', deck_id: 'deck-history', front: 'NATO Founded', back: '1949. The North Atlantic Treaty Organization established a mutual defense alliance among Western nations in response to Soviet expansionism in Eastern Europe.', sort_order: 99 , front_translations: {"es":"Fundación de la OTAN","de":"Gründung der NATO","fr":"Fondation de l'OTAN","tr":"NATO'nun Kuruluşu","nl":"Oprichting van de NAVO","ru":"Основание НАТО","zh":"北约成立","pt_BR":"Fundação da OTAN","pt_PT":"Fundação da NATO"}, back_translations: {"es":"1949. La Organización del Tratado del Atlántico Norte estabeleceu una alianza de defesa mútua entre naciones ocidentais en respuesta al expansionismo soviético en la Europa Oriental.","de":"1949. Die Nordatlantikvertragsorganisation schuf ein gegenseitiges Verteidigungsbündnis westlicher Nationen als Reaktion auf die sowjetische Expansion in Osteuropa.","fr":"1949. L'Organisation du traité de l'Atlantique Nord établit une alliance de défense mutuelle entre les nations occidentales en réponse à l'expansionnisme soviétique en Europe de l'Est.","tr":"1949. Kuzey Atlantik Antlaşması Örgütü, Doğu Avrupa'daki Sovyet yayılmacılığına karşı Batılı uluslar arasında bir karşılıklı savunma ittifakı kurdu.","nl":"1949. De Noord-Atlantische Verdragsorganisatie richtte een wederzijds defensieverbond op tussen westerse naties als reactie op de Sovjet-expansie in Oost-Europa.","ru":"1949. Организация Североатлантического договора создала союз коллективной обороны западных стран в ответ на советскую экспансию в Восточной Европе.","zh":"1949年。北大西洋公约组织建立了西方国家之间的共同防御联盟，以应对苏联在东欧的扩张。","pt_BR":"1949. A Organização do Tratado do Atlântico Norte estabeleceu uma aliança de defesa mútua entre nações ocidentais em resposta ao expansionismo soviético na Europa Oriental.","pt_PT":"1949. A Organização do Tratado do Atlântico Norte estabeleceu uma aliança de defesa mútua entre nações ocidentais em resposta ao expansionismo soviético na Europa de Leste."}},
  { id: 'dc-history-0100', deck_id: 'deck-history', front: 'Chinese Communist Revolution', back: '1949. Mao Zedong\'s Communist forces defeated the Nationalist government, establishing the People\'s Republic of China and beginning decades of communist rule.', sort_order: 100 , front_translations: {"es":"Revolución Comunista Chinesa","de":"Chinesische Kommunistische Revolution","fr":"Révolution communiste chinoise","tr":"Çin Komünist Devrimi","nl":"Chinese Communistische Revolutie","ru":"Китайская коммунистическая революция","zh":"中国共产主义革命","pt_BR":"Revolução Comunista Chinesa","pt_PT":"Revolução Comunista Chinesa"}, back_translations: {"es":"1949. As fuerzas comunistas de Mao Zedong derrotaram el gobierno nacionalista, estableciendo a República Popular de la China y iniciando décadas de regime comunista.","de":"1949. Mao Zedongs kommunistische Streitkräfte besiegten die nationalistische Regierung und gründeten die Volksrepublik China, womit Jahrzehnte kommunistischer Herrschaft begannen.","fr":"1949. Les forces communistes de Mao Zedong ont vaincu le gouvernement nationaliste, établissant la République populaire de Chine et inaugurant des décennies de régime communiste.","tr":"1949. Mao Zedong'un komünist güçleri Milliyetçi hükümeti yenerek Çin Halk Cumhuriyeti'ni kurdu ve onlarca yıl sürecek komünist yönetimi başlattı.","nl":"1949. Mao Zedongs communistische troepen versloegen de nationalistische regering en stichtten de Volksrepubliek China, waarmee decennia van communistisch bestuur begonnen.","ru":"1949 год. Коммунистические силы Мао Цзэдуна разгромили националистическое правительство, основав Китайскую Народную Республику и положив начало десятилетиям коммунистического правления.","zh":"1949年。毛泽东领导的共产党军队击败了国民党政府，建立了中华人民共和国，开启了数十年的共产主义统治。","pt_BR":"1949. As forças comunistas de Mao Zedong derrotaram o governo nacionalista, estabelecendo a República Popular da China e iniciando décadas de regime comunista.","pt_PT":"1949. As forças comunistas de Mao Zedong derrotaram o governo nacionalista, estabelecendo a República Popular da China e dando início a décadas de regime comunista."}},
  { id: 'dc-history-0101', deck_id: 'deck-history', front: 'Sputnik Launch', back: '1957. The Soviet Union launched Sputnik 1, the first artificial satellite, shocking the West and launching the Space Race between the US and USSR.', sort_order: 101 , front_translations: {"es":"Lançamento del Sputnik","de":"Start des Sputnik","fr":"Lancement de Spoutnik","tr":"Sputnik'in Fırlatılması","nl":"Lancering van Spoetnik","ru":"Запуск спутника","zh":"斯普特尼克号发射","pt_BR":"Lançamento do Sputnik","pt_PT":"Lançamento do Sputnik"}, back_translations: {"es":"1957. La União Soviética lançou el Sputnik 1, el primero satélite artificial, chocando el Occidente y dando início a la Corrida Espacial entre los EUA y a URSS.","de":"1957. Die Sowjetunion startete Sputnik 1, den ersten künstlichen Satelliten, was den Westen schockierte und das Weltraumrennen zwischen den USA und der UdSSR auslöste.","fr":"1957. L'Union soviétique lança Spoutnik 1, le premier satellite artificiel, choquant l'Occident et déclenchant la course à l'espace entre les États-Unis et l'URSS.","tr":"1957. Sovyetler Birliği ilk yapay uydu olan Sputnik 1'i fırlattı; bu olay Batı'yı şok etti ve ABD ile SSCB arasındaki Uzay Yarışı'nı başlattı.","nl":"1957. De Sovjet-Unie lanceerde Spoetnik 1, de eerste kunstmatige satelliet, wat het Westen schokte en de ruimtewedloop tussen de VS en de USSR ontketende.","ru":"1957. Советский Союз запустил «Спутник-1» — первый искусственный спутник Земли, потрясший Запад и положивший начало космической гонке между США и СССР.","zh":"1957年。苏联发射了人类第一颗人造卫星斯普特尼克1号，震惊了西方世界，引发了美苏之间的太空竞赛。","pt_BR":"1957. A União Soviética lançou o Sputnik 1, o primeiro satélite artificial, chocando o Ocidente e dando início à Corrida Espacial entre os EUA e a URSS.","pt_PT":"1957. A União Soviética lançou o Sputnik 1, o primeiro satélite artificial, chocando o Ocidente e dando início à Corrida Espacial entre os EUA e a URSS."}},
  { id: 'dc-history-0102', deck_id: 'deck-history', front: 'Bay of Pigs Invasion', back: '1961. A failed CIA-backed attempt to overthrow Fidel Castro\'s Cuban government; it humiliated the Kennedy administration and strengthened Castro\'s position and Soviet ties.', sort_order: 102 , front_translations: {"es":"Invasão de la Baía de los Porcos","de":"Invasion in der Schweinebucht","fr":"Invasion de la baie des Cochons","tr":"Domuzlar Körfezi Çıkarması","nl":"Invasie van de Varkensbaai","ru":"Вторжение в залив Свиней","zh":"猪湾入侵","pt_BR":"Invasão da Baía dos Porcos","pt_PT":"Invasão da Baía dos Porcos"}, back_translations: {"es":"1961. Una tentativa fracassada, apoiada por la CIA, de derrubar el gobierno cubano de Fidel Castro; humilhou el gobierno Kennedy y fortaleceu a posición de Castro y los laços con a União Soviética.","de":"1961. Ein gescheiterter, von der CIA unterstützter Versuch, Fidel Castros kubanische Regierung zu stürzen; er blamierte die Kennedy-Regierung und stärkte Castros Position und die Beziehungen zur Sowjetunion.","fr":"1961. Une tentative ratée, soutenue par la CIA, de renverser le gouvernement cubain de Fidel Castro ; elle humilia l'administration Kennedy et renforça la position de Castro et ses liens avec l'Union soviétique.","tr":"1961. CIA destekli, Fidel Castro'nun Küba hükümetini devirmeye yönelik başarısız bir girişim; Kennedy yönetimini utandırdı ve Castro'nun konumunu ve Sovyet bağlarını güçlendirdi.","nl":"1961. Een mislukte, door de CIA gesteunde poging om de Cubaanse regering van Fidel Castro omver te werpen; het vernederde de Kennedy-regering en versterkte Castro's positie en Sovjet-banden.","ru":"1961 год. Провалившаяся попытка свержения кубинского правительства Фиделя Кастро при поддержке ЦРУ; она унизила администрацию Кеннеди и укрепила позиции Кастро и его связи с Советским Союзом.","zh":"1961年。一次由中央情报局支持的推翻菲德尔·卡斯特罗古巴政府的失败企图；此事令肯尼迪政府蒙羞，反而巩固了卡斯特罗的地位及其与苏联的关系。","pt_BR":"1961. Uma tentativa fracassada, apoiada pela CIA, de derrubar o governo cubano de Fidel Castro; humilhou o governo Kennedy e fortaleceu a posição de Castro e os laços com a União Soviética.","pt_PT":"1961. Uma tentativa falhada, apoiada pela CIA, de derrubar o governo cubano de Fidel Castro; humilhou a administração Kennedy e reforçou a posição de Castro e os laços com a União Soviética."}},
  { id: 'dc-history-0103', deck_id: 'deck-history', front: 'Construction of the Berlin Wall', back: '1961. East Germany built a wall dividing Berlin to stop the mass exodus of citizens to the West; it stood until 1989 as the defining symbol of the Iron Curtain.', sort_order: 103 , front_translations: {"es":"Construcción del Muro de Berlim","de":"Bau der Berliner Mauer","fr":"Construction du mur de Berlin","tr":"Berlin Duvarı'nın İnşası","nl":"Bouw van de Berlijnse Muur","ru":"Строительство Берлинской стены","zh":"柏林墙的修建","pt_BR":"Construção do Muro de Berlim","pt_PT":"Construção do Muro de Berlim"}, back_translations: {"es":"1961. La Alemanha Oriental construiu un muro dividindo Berlim para impedir el exodo en masa de cidadãos para el Occidente; permaneceu de pie hasta 1989 como el símbolo definidor de la Cortina de Ferro.","de":"1961. Die DDR errichtete eine Mauer, die Berlin teilte, um die Massenflucht von Bürgern in den Westen zu stoppen; sie stand bis 1989 als das bestimmende Symbol des Eisernen Vorhangs.","fr":"1961. L'Allemagne de l'Est construisit un mur divisant Berlin pour stopper l'exode massif de citoyens vers l'Ouest ; il resta debout jusqu'en 1989 comme symbole emblématique du rideau de fer.","tr":"1961. Doğu Almanya, vatandaşların Batı'ya toplu göçünü durdurmak için Berlin'i ikiye bölen bir duvar inşa etti; 1989'a kadar Demir Perde'nin simgesi olarak ayakta kaldı.","nl":"1961. Oost-Duitsland bouwde een muur die Berlijn verdeelde om de massale uittocht van burgers naar het Westen te stoppen; de muur stond tot 1989 als het bepalende symbool van het IJzeren Gordijn.","ru":"1961. Восточная Германия возвела стену, разделившую Берлин, чтобы остановить массовый исход граждан на Запад; стена простояла до 1989 года как главный символ «железного занавеса».","zh":"1961年。东德修建了一道墙将柏林一分为二，以阻止公民大规模逃往西方；这道墙直到1989年才被拆除，是铁幕的标志性象征。","pt_BR":"1961. A Alemanha Oriental construiu um muro dividindo Berlim para impedir o êxodo em massa de cidadãos para o Ocidente; permaneceu de pé até 1989 como o símbolo definidor da Cortina de Ferro.","pt_PT":"1961. A Alemanha Oriental construiu um muro dividindo Berlim para impedir o êxodo em massa de cidadãos para o Ocidente; manteve-se de pé até 1989 como o símbolo definidor da Cortina de Ferro."}},
  { id: 'dc-history-0104', deck_id: 'deck-history', front: 'Assassination of JFK', back: '22 November 1963. President John F. Kennedy was assassinated in Dallas, Texas; Lee Harvey Oswald was charged but killed before trial, spawning lasting conspiracy theories.', sort_order: 104 , front_translations: {"es":"Assassinato de JFK","de":"Ermordung von JFK","fr":"Assassinat de JFK","tr":"JFK Suikastı","nl":"Moord op JFK","ru":"Убийство Кеннеди","zh":"肯尼迪遇刺","pt_BR":"Assassinato de JFK","pt_PT":"Assassinato de JFK"}, back_translations: {"es":"22 de novembro de 1963. El presidente John F. Kennedy fue assassinado en Dallas, Texas; Lee Harvey Oswald fue acusado, pero morto antes del julgamento, generando teorías de la conspiración duradouras.","de":"22. November 1963. Präsident John F. Kennedy wurde in Dallas, Texas, ermordet; Lee Harvey Oswald wurde angeklagt, aber vor dem Prozess getötet, was dauerhafte Verschwörungstheorien auslöste.","fr":"22 novembre 1963. Le président John F. Kennedy a été assassiné à Dallas, au Texas ; Lee Harvey Oswald a été inculpé mais tué avant son procès, engendrant des théories du complot durables.","tr":"22 Kasım 1963. Başkan John F. Kennedy, Dallas, Teksas'ta suikaste uğradı; Lee Harvey Oswald suçlandı ancak yargılanmadan öldürüldü ve bu durum kalıcı komplo teorilerine yol açtı.","nl":"22 november 1963. President John F. Kennedy werd vermoord in Dallas, Texas; Lee Harvey Oswald werd aangeklaagd maar voor het proces gedood, wat langdurige complottheorieën veroorzaakte.","ru":"22 ноября 1963 года. Президент Джон Ф. Кеннеди был убит в Далласе, штат Техас; Ли Харви Освальд был обвинён, но убит до суда, что породило устойчивые теории заговора.","zh":"1963年11月22日。约翰·F·肯尼迪总统在得克萨斯州达拉斯遇刺身亡；李·哈维·奥斯瓦尔德被指控但在审判前被杀，由此引发了持久的阴谋论。","pt_BR":"22 de novembro de 1963. O presidente John F. Kennedy foi assassinado em Dallas, Texas; Lee Harvey Oswald foi acusado, mas morto antes do julgamento, gerando teorias da conspiração duradouras.","pt_PT":"22 de novembro de 1963. O presidente John F. Kennedy foi assassinado em Dallas, Texas; Lee Harvey Oswald foi acusado, mas morto antes do julgamento, gerando teorias da conspiração duradouras."}},
  { id: 'dc-history-0105', deck_id: 'deck-history', front: 'Cultural Revolution (China)', back: '1966–1976. Mao Zedong\'s campaign to reassert communist ideology by purging traditional elements from Chinese society; it caused enormous social disruption and millions of deaths.', sort_order: 105 , front_translations: {"es":"Revolución Cultural (China)","de":"Kulturrevolution (China)","fr":"Révolution culturelle (Chine)","tr":"Kültür Devrimi (Çin)","nl":"Culturele Revolutie (China)","ru":"Культурная революция (Китай)","zh":"文化大革命（中国）","pt_BR":"Revolução Cultural (China)","pt_PT":"Revolução Cultural (China)"}, back_translations: {"es":"1966–1976. La campanha de Mao Zedong para reafirmar a ideologia comunista al expurgar elementos tradicionais de la sociedad chinesa; causou enorme perturbación social y milhões de mortes.","de":"1966–1976. Mao Zedongs Kampagne zur Wiederherstellung der kommunistischen Ideologie durch die Säuberung traditioneller Elemente aus der chinesischen Gesellschaft; sie verursachte enorme soziale Verwerfungen und Millionen von Toten.","fr":"1966–1976. La campagne de Mao Zedong pour réaffirmer l'idéologie communiste en purgeant les éléments traditionnels de la société chinoise ; elle provoqua d'énormes perturbations sociales et des millions de morts.","tr":"1966–1976. Mao Zedong'un geleneksel unsurları Çin toplumundan tasfiye ederek komünist ideolojiyi yeniden güçlendirme kampanyası; muazzam toplumsal çalkantıya ve milyonlarca ölüme yol açtı.","nl":"1966–1976. Mao Zedongs campagne om de communistische ideologie te herbevestigen door traditionele elementen uit de Chinese samenleving te zuiveren; het veroorzaakte enorme maatschappelijke ontwrichting en miljoenen doden.","ru":"1966–1976 годы. Кампания Мао Цзэдуна по утверждению коммунистической идеологии путём очищения китайского общества от традиционных элементов; вызвала колоссальные социальные потрясения и миллионы жертв.","zh":"1966–1976年。毛泽东发起的旨在通过清除中国社会传统元素来重申共产主义意识形态的运动；造成了巨大的社会动荡和数百万人死亡。","pt_BR":"1966–1976. A campanha de Mao Zedong para reafirmar a ideologia comunista ao expurgar elementos tradicionais da sociedade chinesa; causou enorme perturbação social e milhões de mortes.","pt_PT":"1966–1976. A campanha de Mao Zedong para reafirmar a ideologia comunista ao expurgar elementos tradicionais da sociedade chinesa; causou enormes perturbações sociais e milhões de mortes."}},
  { id: 'dc-history-0106', deck_id: 'deck-history', front: 'Tet Offensive', back: '1968. A massive North Vietnamese and Viet Cong offensive during the Vietnamese New Year; though militarily repulsed, it shattered American public confidence in the war.', sort_order: 106 , front_translations: {"es":"Ofensiva del Tet","de":"Tet-Offensive","fr":"Offensive du Tết","tr":"Tet Taarruzu","nl":"Tet-offensief","ru":"Тетское наступление","zh":"春节攻势","pt_BR":"Ofensiva do Tet","pt_PT":"Ofensiva do Tet"}, back_translations: {"es":"1968. Una ofensiva massiva norte-vietnamita y vietcongue durante el Ano Nuevo vietnamita; aunque repelida militarmente, abalou a confiança del público americano en la guerra.","de":"1968. Eine massive Offensive Nordvietnams und des Vietcong während des vietnamesischen Neujahrsfests; obwohl militärisch zurückgeschlagen, erschütterte sie das Vertrauen der amerikanischen Öffentlichkeit in den Krieg.","fr":"1968. Une offensive massive nord-vietnamienne et vietcong pendant le Nouvel An vietnamien ; bien que repoussée militairement, elle a brisé la confiance du public américain dans la guerre.","tr":"1968. Vietnam Yeni Yılı sırasında Kuzey Vietnam ve Vietkong tarafından düzenlenen büyük bir saldırı; askeri olarak püskürtülmesine rağmen, Amerikan kamuoyunun savaşa olan güvenini sarstı.","nl":"1968. Een massief Noord-Vietnamees en Vietcong-offensief tijdens het Vietnamese Nieuwjaar; hoewel militair afgeslagen, vernietigde het het vertrouwen van het Amerikaanse publiek in de oorlog.","ru":"1968 год. Масштабное наступление Северного Вьетнама и Вьетконга во время вьетнамского Нового года; хотя оно было отбито в военном отношении, оно подорвало уверенность американской общественности в войне.","zh":"1968年。北越和越共在越南新年期间发动的大规模攻势；虽然在军事上被击退，但它动摇了美国公众对战争的信心。","pt_BR":"1968. Uma ofensiva massiva norte-vietnamita e vietcongue durante o Ano Novo vietnamita; embora repelida militarmente, abalou a confiança do público americano na guerra.","pt_PT":"1968. Uma ofensiva massiva norte-vietnamita e vietcongue durante o Ano Novo vietnamita; embora repelida militarmente, abalou a confiança do público americano na guerra."}},
  { id: 'dc-history-0107', deck_id: 'deck-history', front: 'Tiananmen Square Massacre', back: '1989. Chinese troops violently suppressed pro-democracy protesters in Beijing\'s Tiananmen Square, killing hundreds to thousands; the "Tank Man" image became iconic.', sort_order: 107 , front_translations: {"es":"Massacre de la Praça de la Paz Celestial","de":"Massaker auf dem Platz des Himmlischen Friedens","fr":"Massacre de la place Tiananmen","tr":"Tiananmen Meydanı Katliamı","nl":"Bloedbad op het Tiananmenplein","ru":"Бойня на площади Тяньаньмэнь","zh":"天安门广场事件","pt_BR":"Massacre da Praça da Paz Celestial","pt_PT":"Massacre da Praça de Tiananmen"}, back_translations: {"es":"1989. Tropas chinesas reprimiram violentamente manifestantes pró-democracia en la Praça de la Paz Celestial en Pequim, matando centenas a milhares; a imaje del \"Hombre del Tanque\" tornou-se iconica.","de":"1989. Chinesische Truppen unterdrückten gewaltsam pro-demokratische Demonstranten auf dem Pekinger Platz des Himmlischen Friedens und töteten Hunderte bis Tausende; das Bild des \"Panzer-Mannes\" wurde zur Ikone.","fr":"1989. Les troupes chinoises ont violemment réprimé les manifestants pro-démocratie sur la place Tiananmen à Pékin, tuant des centaines à des milliers de personnes ; l'image de l'« Homme au tank » est devenue emblématique.","tr":"1989. Çin askerleri Pekin'deki Tiananmen Meydanı'nda demokrasi yanlısı göstericileri şiddetle bastırdı ve yüzlerce ila binlerce kişiyi öldürdü; \"Tank Adam\" görüntüsü ikonik hale geldi.","nl":"1989. Chinese troepen sloegen pro-democratische demonstranten op het Tiananmenplein in Peking gewelddadig neer, waarbij honderden tot duizenden mensen om het leven kwamen; het beeld van de \"Tankman\" werd iconisch.","ru":"1989 год. Китайские войска жестоко подавили продемократические протесты на площади Тяньаньмэнь в Пекине, убив от сотен до тысяч человек; фотография «Танкового человека» стала культовой.","zh":"1989年。中国军队在北京天安门广场暴力镇压民主运动示威者，造成数百至数千人死亡；\"坦克人\"的形象成为标志性画面。","pt_BR":"1989. Tropas chinesas reprimiram violentamente manifestantes pró-democracia na Praça da Paz Celestial em Pequim, matando centenas a milhares; a imagem do \"Homem do Tanque\" tornou-se icônica.","pt_PT":"1989. Tropas chinesas reprimiram violentamente manifestantes pró-democracia na Praça de Tiananmen em Pequim, matando centenas a milhares; a imagem do \"Homem do Tanque\" tornou-se icónica."}},
  { id: 'dc-history-0108', deck_id: 'deck-history', front: 'Rwandan Genocide', back: '1994. The mass slaughter of an estimated 500,000–800,000 Tutsi people by the Hutu-dominated government over 100 days; the international community\'s failure to intervene drew widespread condemnation.', sort_order: 108 , front_translations: {"es":"Genocídio de Ruanda","de":"Völkermord in Ruanda","fr":"Génocide rwandais","tr":"Ruanda Soykırımı","nl":"Rwandese genocide","ru":"Геноцид в Руанде","zh":"卢旺达大屠杀","pt_BR":"Genocídio de Ruanda","pt_PT":"Genocídio do Ruanda"}, back_translations: {"es":"1994. El massacre en masa de cerca de 500.000–800.000 tutsis por el gobierno dominado por los hutus en 100 dias; a falha de la comunidad internacional en intervir gerou ampla condenación.","de":"1994. Die Massentötung von schätzungsweise 500.000–800.000 Tutsi durch die von Hutu dominierte Regierung innerhalb von 100 Tagen; das Versagen der internationalen Gemeinschaft einzugreifen wurde weithin verurteilt.","fr":"1994. Le massacre de masse d'environ 500 000 à 800 000 Tutsis par le gouvernement dominé par les Hutus en 100 jours ; l'incapacité de la communauté internationale à intervenir a suscité une condamnation généralisée.","tr":"1994. Hutu egemenliğindeki hükümet tarafından 100 gün içinde tahminen 500.000–800.000 Tutsi'nin toplu katliamı; uluslararası toplumun müdahale etmemesi büyük kınama aldı.","nl":"1994. De massamoord op naar schatting 500.000–800.000 Tutsi's door de door Hutu's gedomineerde regering in 100 dagen; het falen van de internationale gemeenschap om in te grijpen werd alom veroordeeld.","ru":"1994 год. Массовое уничтожение от 500 000 до 800 000 тутси правительством, где доминировали хуту, за 100 дней; неспособность международного сообщества вмешаться вызвала широкое осуждение.","zh":"1994年。胡图族主导的政府在100天内屠杀了约50万至80万图西族人；国际社会未能干预的失败遭到广泛谴责。","pt_BR":"1994. O massacre em massa de cerca de 500.000–800.000 tutsis pelo governo dominado pelos hutus em 100 dias; a falha da comunidade internacional em intervir gerou ampla condenação.","pt_PT":"1994. O massacre em massa de cerca de 500.000–800.000 tutsis pelo governo dominado pelos hutus em 100 dias; a incapacidade da comunidade internacional de intervir gerou ampla condenação."}},
  { id: 'dc-history-0109', deck_id: 'deck-history', front: 'September 11 Attacks', back: '2001. Al-Qaeda terrorists hijacked four aircraft, crashing two into the World Trade Center and one into the Pentagon; ~3,000 people died, triggering the US "War on Terror."', sort_order: 109 , front_translations: {"es":"Ataques de 11 de Setembro","de":"Anschläge vom 11. September","fr":"Attentats du 11 septembre","tr":"11 Eylül Saldırıları","nl":"Aanslagen van 11 september","ru":"Теракты 11 сентября","zh":"九一一恐怖袭击","pt_BR":"Ataques de 11 de Setembro","pt_PT":"Ataques de 11 de Setembro"}, back_translations: {"es":"2001. Terroristas de la Al-Qaeda sequestraram cuatro aeronaves, lançando de los contra el World Trade Center y una contra el Pentágono; cerca de 3.000 personas morreram, desencadeando a \"Guerra al Terror\" de los EUA.","de":"2001. Terroristen von al-Qaida entführten vier Flugzeuge und steuerten zwei in das World Trade Center und eines in das Pentagon; etwa 3.000 Menschen starben, was den US-amerikanischen \"Krieg gegen den Terror\" auslöste.","fr":"2001. Des terroristes d'Al-Qaïda ont détourné quatre avions, en précipitant deux sur le World Trade Center et un sur le Pentagone ; environ 3 000 personnes sont mortes, déclenchant la « guerre contre le terrorisme » des États-Unis.","tr":"2001. El-Kaide teröristleri dört uçağı kaçırdı, ikisini Dünya Ticaret Merkezi'ne ve birini Pentagon'a çarptırdı; yaklaşık 3.000 kişi hayatını kaybetti ve ABD'nin \"Terörle Savaş\"ını başlattı.","nl":"2001. Al-Qaida-terroristen kaapten vier vliegtuigen en lieten er twee neerstorten op het World Trade Center en één op het Pentagon; ~3.000 mensen kwamen om, wat de Amerikaanse \"Oorlog tegen het Terrorisme\" ontketende.","ru":"2001 год. Террористы «Аль-Каиды» захватили четыре самолёта, направив два из них в башни Всемирного торгового центра и один — в Пентагон; погибло около 3 000 человек, что положило начало американской «войне с терроризмом».","zh":"2001年。基地组织恐怖分子劫持了四架飞机，两架撞入世界贸易中心，一架撞入五角大楼；约3000人遇难，引发了美国的\"反恐战争\"。","pt_BR":"2001. Terroristas da Al-Qaeda sequestraram quatro aeronaves, lançando duas contra o World Trade Center e uma contra o Pentágono; cerca de 3.000 pessoas morreram, desencadeando a \"Guerra ao Terror\" dos EUA.","pt_PT":"2001. Terroristas da Al-Qaeda sequestraram quatro aeronaves, lançando duas contra o World Trade Center e uma contra o Pentágono; cerca de 3.000 pessoas morreram, desencadeando a \"Guerra contra o Terrorismo\" dos EUA."}},
  { id: 'dc-history-0110', deck_id: 'deck-history', front: 'Arab Spring', back: '2010–2012. A wave of pro-democracy protests and uprisings across the Arab world; it led to the overthrow of governments in Tunisia, Egypt, Libya, and Yemen, with mixed long-term results.', sort_order: 110 , front_translations: {"es":"Primavera Árabe","de":"Arabischer Frühling","fr":"Printemps arabe","tr":"Arap Baharı","nl":"Arabische Lente","ru":"Арабская весна","zh":"阿拉伯之春","pt_BR":"Primavera Árabe","pt_PT":"Primavera Árabe"}, back_translations: {"es":"2010–2012. Una onda de protestos y revoltas pró-democracia por el mundo árabe; levou a la caída de gobiernos en la Tunísia, Egito, Líbia y Iemen, con resultados mistos a ancho prazo.","de":"2010–2012. Eine Welle prodemokratischer Proteste und Aufstände in der arabischen Welt; sie führte zum Sturz der Regierungen in Tunesien, Ägypten, Libyen und Jemen, mit gemischten langfristigen Ergebnissen.","fr":"2010–2012. Une vague de manifestations et de soulèvements pro-démocratie à travers le monde arabe ; elle a conduit au renversement des gouvernements en Tunisie, en Égypte, en Libye et au Yémen, avec des résultats mitigés à long terme.","tr":"2010–2012. Arap dünyasında demokrasi yanlısı protestolar ve ayaklanmalar dalgası; Tunus, Mısır, Libya ve Yemen'de hükümetlerin devrilmesine yol açtı, ancak uzun vadeli sonuçları karışık oldu.","nl":"2010–2012. Een golf van pro-democratische protesten en opstanden in de Arabische wereld; leidde tot de val van regeringen in Tunesië, Egypte, Libië en Jemen, met wisselende langetermijnresultaten.","ru":"2010–2012 годы. Волна продемократических протестов и восстаний в арабском мире; привела к свержению правительств в Тунисе, Египте, Ливии и Йемене с неоднозначными долгосрочными результатами.","zh":"2010–2012年。一场席卷阿拉伯世界的民主抗议和起义浪潮；导致突尼斯、埃及、利比亚和也门的政府被推翻，但长期结果喜忧参半。","pt_BR":"2010–2012. Uma onda de protestos e revoltas pró-democracia pelo mundo árabe; levou à queda de governos na Tunísia, Egito, Líbia e Iêmen, com resultados mistos a longo prazo.","pt_PT":"2010–2012. Uma vaga de protestos e revoltas pró-democracia pelo mundo árabe; levou à queda de governos na Tunísia, Egito, Líbia e Iémen, com resultados mistos a longo prazo."}},
  { id: 'dc-history-0111', deck_id: 'deck-history', front: 'Hannibal Barca', back: '247–183 BCE. Carthaginian general who famously crossed the Alps with war elephants to invade Italy; won several crushing victories against Rome despite ultimately being defeated.', sort_order: 111 , front_translations: {"es":"Aníbal Barca","de":"Hannibal Barkas","fr":"Hannibal Barca","tr":"Hannibal Barca","nl":"Hannibal Barca","ru":"Ганнибал Барка","zh":"汉尼拔·巴卡","pt_BR":"Aníbal Barca","pt_PT":"Aníbal Barca"}, back_translations: {"es":"247–183 a.C. General cartagines famoso por cruzar los Alpes con elefantes de guerra para invadir a Itália; obteve várias vitórias esmagadoras contra Roma, apesar de ter sido derrotado en el final.","de":"247–183 v. Chr. Karthagischer Feldherr, der berühmt mit Kriegselefanten über die Alpen zog, um Italien anzugreifen; errang mehrere vernichtende Siege gegen Rom, wurde aber letztlich besiegt.","fr":"247–183 av. J.-C. Général carthaginois célèbre pour avoir traversé les Alpes avec des éléphants de guerre afin d'envahir l'Italie ; il remporta plusieurs victoires écrasantes contre Rome malgré sa défaite finale.","tr":"MÖ 247–183. Savaş filleriyle Alpler'i geçerek İtalya'yı istila etmesiyle ünlü Kartacalı general; Roma'ya karşı birçok ezici zafer kazanmasına rağmen sonunda yenildi.","nl":"247–183 v.Chr. Carthaagse generaal die beroemd de Alpen overstak met oorlogsolifanten om Italië binnen te vallen; behaalde meerdere verpletterende overwinningen op Rome ondanks zijn uiteindelijke nederlaag.","ru":"247–183 до н. э. Карфагенский полководец, знаменитый переходом через Альпы с боевыми слонами для вторжения в Италию; одержал ряд сокрушительных побед над Римом, но в итоге потерпел поражение.","zh":"公元前247–183年。迦太基将军，以率领战象翻越阿尔卑斯山入侵意大利而闻名；曾多次大败罗马军队，但最终被击败。","pt_BR":"247–183 a.C. General cartaginês famoso por cruzar os Alpes com elefantes de guerra para invadir a Itália; obteve várias vitórias esmagadoras contra Roma, apesar de ter sido derrotado no final.","pt_PT":"247–183 a.C. General cartaginês famoso por atravessar os Alpes com elefantes de guerra para invadir a Itália; obteve várias vitórias esmagadoras contra Roma, apesar de ter sido derrotado no final."}},
  { id: 'dc-history-0112', deck_id: 'deck-history', front: 'Punic Wars', back: '264–146 BCE. Three wars between Rome and Carthage for dominance of the Mediterranean; ended with Carthage\'s complete destruction and Rome\'s emergence as the dominant Mediterranean power.', sort_order: 112 , front_translations: {"es":"Guerras Púnicas","de":"Punische Kriege","fr":"Guerres puniques","tr":"Pön Savaşları","nl":"Punische Oorlogen","ru":"Пунические войны","zh":"布匿战争","pt_BR":"Guerras Púnicas","pt_PT":"Guerras Púnicas"}, back_translations: {"es":"264–146 a.C. Tres guerras entre Roma y Cartago por la dominación del Mediterraneo; terminaram con a destrucción completa de Cartago y a ascensão de Roma como potencia dominante del Mediterraneo.","de":"264–146 v. Chr. Drei Kriege zwischen Rom und Karthago um die Vorherrschaft im Mittelmeerraum; endeten mit der vollständigen Zerstörung Karthagos und dem Aufstieg Roms zur dominierenden Mittelmeermacht.","fr":"264–146 av. J.-C. Trois guerres entre Rome et Carthage pour la domination de la Méditerranée ; elles se terminèrent par la destruction complète de Carthage et l'émergence de Rome comme puissance méditerranéenne dominante.","tr":"MÖ 264–146. Roma ile Kartaca arasında Akdeniz'deki hâkimiyet için yapılan üç savaş; Kartaca'nın tamamen yıkılması ve Roma'nın baskın Akdeniz gücü olarak yükselmesiyle sona erdi.","nl":"264–146 v.Chr. Drie oorlogen tussen Rome en Carthago om de heerschappij over de Middellandse Zee; eindigden met de volledige vernietiging van Carthago en de opkomst van Rome als de dominante Middellandse Zeemacht.","ru":"264–146 до н. э. Три войны между Римом и Карфагеном за господство в Средиземноморье; завершились полным разрушением Карфагена и утверждением Рима как доминирующей средиземноморской державы.","zh":"公元前264–146年。罗马与迦太基之间为争夺地中海霸权而进行的三次战争；以迦太基被彻底摧毁、罗马崛起为地中海霸主而告终。","pt_BR":"264–146 a.C. Três guerras entre Roma e Cartago pela dominação do Mediterrâneo; terminaram com a destruição completa de Cartago e a ascensão de Roma como potência dominante do Mediterrâneo.","pt_PT":"264–146 a.C. Três guerras entre Roma e Cartago pela dominação do Mediterrâneo; terminaram com a destruição completa de Cartago e a emergência de Roma como potência dominante do Mediterrâneo."}},
  { id: 'dc-history-0113', deck_id: 'deck-history', front: 'Pax Romana', back: '27 BCE–180 CE. A period of relative peace and prosperity across the Roman Empire under Augustus and his successors; trade, culture, and infrastructure flourished.', sort_order: 113 , front_translations: {"es":"Pax Romana","de":"Pax Romana","fr":"Pax Romana","tr":"Pax Romana","nl":"Pax Romana","ru":"Римский мир (Pax Romana)","zh":"罗马和平","pt_BR":"Pax Romana","pt_PT":"Pax Romana"}, back_translations: {"es":"27 a.C.–180 d.C. Un período de relativa paz y prosperidad en el Imperio Romano sob Augusto y sus sucessores; el comercio, a cultura y a infraestrutura floresceram.","de":"27 v. Chr.–180 n. Chr. Eine Periode relativen Friedens und Wohlstands im Römischen Reich unter Augustus und seinen Nachfolgern; Handel, Kultur und Infrastruktur blühten auf.","fr":"27 av. J.-C.–180 apr. J.-C. Une période de paix et de prospérité relatives dans l'Empire romain sous Auguste et ses successeurs ; le commerce, la culture et les infrastructures ont prospéré.","tr":"MÖ 27–MS 180. Augustus ve halefleri döneminde Roma İmparatorluğu'nda görece barış ve refah dönemi; ticaret, kültür ve altyapı gelişti.","nl":"27 v.Chr.–180 n.Chr. Een periode van relatieve vrede en welvaart in het Romeinse Rijk onder Augustus en zijn opvolgers; handel, cultuur en infrastructuur bloeiden.","ru":"27 до н. э. – 180 н. э. Период относительного мира и процветания в Римской империи при Августе и его преемниках; расцвели торговля, культура и инфраструктура.","zh":"公元前27年–公元180年。奥古斯都及其继任者统治下罗马帝国相对和平繁荣的时期；贸易、文化和基础设施蓬勃发展。","pt_BR":"27 a.C.–180 d.C. Um período de relativa paz e prosperidade no Império Romano sob Augusto e seus sucessores; o comércio, a cultura e a infraestrutura floresceram.","pt_PT":"27 a.C.–180 d.C. Um período de relativa paz e prosperidade no Império Romano sob Augusto e os seus sucessores; o comércio, a cultura e as infraestruturas floresceram."}},
  { id: 'dc-history-0114', deck_id: 'deck-history', front: 'Charlemagne', back: '742–814 CE. King of the Franks who unified much of Western Europe and was crowned Holy Roman Emperor in 800; his reign laid the foundations of modern France and Germany.', sort_order: 114 , front_translations: {"es":"Carlos Magno","de":"Karl der Große","fr":"Charlemagne","tr":"Şarlman","nl":"Karel de Grote","ru":"Карл Великий","zh":"查理曼大帝","pt_BR":"Carlos Magno","pt_PT":"Carlos Magno"}, back_translations: {"es":"742–814 d.C. Rey de los Francos que unificou grande parte de la Europa Ocidental y fue coroado Emperador del Sacro Imperio Romano en 800; su reinado lançou las bases de la França y de la Alemanha modernas.","de":"742–814 n. Chr. König der Franken, der weite Teile Westeuropas vereinte und im Jahr 800 zum Kaiser des Heiligen Römischen Reiches gekrönt wurde; seine Herrschaft legte die Grundlagen des modernen Frankreichs und Deutschlands.","fr":"742–814 apr. J.-C. Roi des Francs qui unifia une grande partie de l'Europe occidentale et fut couronné empereur du Saint-Empire en 800 ; son règne posa les fondations de la France et de l'Allemagne modernes.","tr":"742–814. Batı Avrupa'nın büyük bölümünü birleştiren ve 800 yılında Kutsal Roma İmparatoru olarak taçlanan Frank Kralı; hükümdarlığı modern Fransa ve Almanya'nın temellerini attı.","nl":"742–814 n.Chr. Koning der Franken die een groot deel van West-Europa verenigde en in 800 tot Heilig Rooms Keizer werd gekroond; zijn heerschappij legde de basis voor het moderne Frankrijk en Duitsland.","ru":"742–814 н. э. Король франков, объединивший значительную часть Западной Европы и коронованный императором Священной Римской империи в 800 году; его правление заложило основы современной Франции и Германии.","zh":"742–814年。法兰克国王，统一了西欧大部分地区，于800年加冕为神圣罗马帝国皇帝；他的统治奠定了现代法国和德国的基础。","pt_BR":"742–814 d.C. Rei dos Francos que unificou grande parte da Europa Ocidental e foi coroado Imperador do Sacro Império Romano em 800; seu reinado lançou as bases da França e da Alemanha modernas.","pt_PT":"742–814 d.C. Rei dos Francos que unificou grande parte da Europa Ocidental e foi coroado Imperador do Sacro Império Romano em 800; o seu reinado lançou as bases da França e da Alemanha modernas."}},
  { id: 'dc-history-0115', deck_id: 'deck-history', front: 'Viking Age', back: '793–1066 CE. Norse seafarers raided, traded, and settled across Europe, the North Atlantic, and even North America; they played a major role in shaping medieval Europe.', sort_order: 115 , front_translations: {"es":"Era Viking","de":"Wikingerzeit","fr":"Âge des Vikings","tr":"Viking Çağı","nl":"Vikingtijd","ru":"Эпоха викингов","zh":"维京时代","pt_BR":"Era Viking","pt_PT":"Era Viking"}, back_translations: {"es":"793–1066 d.C. Navegadores nórdicos saquearam, comercializaram y se estabeleceram por toda a Europa, en el Atlántico Norte y hasta en la América del Norte; desempenharam un papel importante en la formación de la Europa medieval.","de":"793–1066 n. Chr. Nordische Seefahrer überfielen, handelten und siedelten in ganz Europa, im Nordatlantik und sogar in Nordamerika; sie spielten eine wichtige Rolle bei der Gestaltung des mittelalterlichen Europas.","fr":"793–1066 apr. J.-C. Des navigateurs nordiques ont pillé, commercé et colonisé à travers l'Europe, l'Atlantique Nord et même l'Amérique du Nord ; ils ont joué un rôle majeur dans la formation de l'Europe médiévale.","tr":"793–1066. İskandinav denizciler Avrupa, Kuzey Atlantik ve hatta Kuzey Amerika genelinde akınlar düzenledi, ticaret yaptı ve yerleşimler kurdu; ortaçağ Avrupa'sının şekillenmesinde önemli bir rol oynadılar.","nl":"793–1066 n.Chr. Noorse zeevaarders plunderden, handelden en vestigden zich in heel Europa, de Noord-Atlantische Oceaan en zelfs Noord-Amerika; zij speelden een grote rol in de vorming van middeleeuws Europa.","ru":"793–1066 н. э. Скандинавские мореплаватели совершали набеги, торговали и основывали поселения по всей Европе, в Северной Атлантике и даже в Северной Америке; они сыграли важную роль в формировании средневековой Европы.","zh":"793–1066年。北欧航海者在整个欧洲、北大西洋甚至北美进行了劫掠、贸易和定居；他们在塑造中世纪欧洲方面发挥了重要作用。","pt_BR":"793–1066 d.C. Navegadores nórdicos saquearam, comercializaram e se estabeleceram por toda a Europa, no Atlântico Norte e até na América do Norte; desempenharam um papel importante na formação da Europa medieval.","pt_PT":"793–1066 d.C. Navegadores nórdicos saquearam, comerciaram e estabeleceram-se por toda a Europa, no Atlântico Norte e até na América do Norte; desempenharam um papel importante na formação da Europa medieval."}},
  { id: 'dc-history-0116', deck_id: 'deck-history', front: 'Feudalism', back: 'A hierarchical social and political system prevalent in medieval Europe where lords granted land (fiefs) to vassals in exchange for military service and loyalty.', sort_order: 116 , front_translations: {"es":"Feudalismo","de":"Feudalismus","fr":"Féodalisme","tr":"Feodalizm","nl":"Feodalisme","ru":"Феодализм","zh":"封建制度","pt_BR":"Feudalismo","pt_PT":"Feudalismo"}, back_translations: {"es":"Un sistema social y político hierárquico prevalente en la Europa medieval, donde senhores concediam terras (feudos) a vassalos en troca de serviço militar y lealdad.","de":"Ein hierarchisches Sozial- und Politiksystem im mittelalterlichen Europa, bei dem Lehnsherren Land (Lehen) an Vasallen vergaben, die im Gegenzug Militärdienst und Treue leisteten.","fr":"Un système social et politique hiérarchique répandu dans l'Europe médiévale, où les seigneurs accordaient des terres (fiefs) à des vassaux en échange de services militaires et de loyauté.","tr":"Ortaçağ Avrupa'sında yaygın olan, lordların askeri hizmet ve sadakat karşılığında vasallara toprak (tımar) verdiği hiyerarşik bir sosyal ve siyasi sistem.","nl":"Een hiërarchisch sociaal en politiek systeem dat wijdverbreid was in middeleeuws Europa, waarbij heren land (leengoederen) toekenden aan vazallen in ruil voor militaire dienst en loyaliteit.","ru":"Иерархическая социально-политическая система, распространённая в средневековой Европе, при которой сеньоры предоставляли землю (феоды) вассалам в обмен на военную службу и верность.","zh":"中世纪欧洲盛行的一种等级森严的社会政治制度，领主将土地（采邑）授予附庸，以换取军事服务和效忠。","pt_BR":"Um sistema social e político hierárquico prevalente na Europa medieval, onde senhores concediam terras (feudos) a vassalos em troca de serviço militar e lealdade.","pt_PT":"Um sistema social e político hierárquico prevalecente na Europa medieval, onde os senhores concediam terras (feudos) a vassalos em troca de serviço militar e lealdade."}},
  { id: 'dc-history-0117', deck_id: 'deck-history', front: 'Printing of the Domesday Book', back: '1086. Commissioned by William the Conqueror, it was the first comprehensive survey of land ownership in England; a foundational record of English medieval society.', sort_order: 117 , front_translations: {"es":"Compilación del Domesday Book","de":"Erstellung des Domesday Book","fr":"Rédaction du Domesday Book","tr":"Domesday Book'un Hazırlanması","nl":"Opstelling van het Domesday Book","ru":"Составление Книги Страшного суда","zh":"《末日审判书》的编纂","pt_BR":"Compilação do Domesday Book","pt_PT":"Compilação do Domesday Book"}, back_translations: {"es":"1086. Encomendado por Guilherme, el Conquistador, fue el primero levantamento abrangente de la propiedad de terras en la Inglaterra; un registro fundamental de la sociedad medieval inglesa.","de":"1086. Von Wilhelm dem Eroberer in Auftrag gegeben, war es die erste umfassende Erhebung des Grundbesitzes in England; ein grundlegendes Dokument der englischen mittelalterlichen Gesellschaft.","fr":"1086. Commandé par Guillaume le Conquérant, ce fut le premier recensement complet de la propriété foncière en Angleterre ; un document fondateur de la société médiévale anglaise.","tr":"1086. Fatih William tarafından yaptırılan, İngiltere'deki toprak mülkiyetinin ilk kapsamlı araştırmasıydı; İngiliz ortaçağ toplumunun temel bir kaydıdır.","nl":"1086. In opdracht van Willem de Veroveraar was het de eerste uitgebreide inventarisatie van grondbezit in Engeland; een fundamenteel document van de Engelse middeleeuwse samenleving.","ru":"1086 год. Составлена по приказу Вильгельма Завоевателя и стала первой всеобъемлющей описью земельной собственности в Англии; основополагающий документ английского средневекового общества.","zh":"1086年。由征服者威廉下令编纂，是英格兰首次全面的土地所有权调查；是英格兰中世纪社会的基础性记录。","pt_BR":"1086. Encomendado por Guilherme, o Conquistador, foi o primeiro levantamento abrangente da propriedade de terras na Inglaterra; um registro fundamental da sociedade medieval inglesa.","pt_PT":"1086. Encomendado por Guilherme, o Conquistador, foi o primeiro levantamento abrangente da propriedade fundiária em Inglaterra; um registo fundamental da sociedade medieval inglesa."}},
  { id: 'dc-history-0118', deck_id: 'deck-history', front: 'Aztec Empire', back: '1428–1521. A Mesoamerican civilization based at Tenochtitlan (modern Mexico City); known for pyramid temples, human sacrifice, and a complex bureaucracy before Spanish conquest.', sort_order: 118 , front_translations: {"es":"Imperio Asteca","de":"Aztekenreich","fr":"Empire aztèque","tr":"Aztek İmparatorluğu","nl":"Azteekse Rijk","ru":"Империя ацтеков","zh":"阿兹特克帝国","pt_BR":"Império Asteca","pt_PT":"Império Asteca"}, back_translations: {"es":"1428–1521. Una civilización mesoamericana sediada en Tenochtitlan (atual Cidad del México); conocida por templos piramidais, sacrifícios humanos y una burocracia complexa antes de la conquista espanhola.","de":"1428–1521. Eine mesoamerikanische Zivilisation mit Zentrum in Tenochtitlan (dem heutigen Mexiko-Stadt); bekannt für Pyramidentempel, Menschenopfer und eine komplexe Bürokratie vor der spanischen Eroberung.","fr":"1428–1521. Une civilisation mésoaméricaine basée à Tenochtitlan (l'actuelle Mexico) ; connue pour ses temples-pyramides, ses sacrifices humains et une bureaucratie complexe avant la conquête espagnole.","tr":"1428–1521. Tenochtitlan'da (bugünkü Meksika City) merkezlenmiş bir Mezoamerika uygarlığı; İspanyol fethinden önce piramit tapınakları, insan kurbanı ve karmaşık bürokratik yapısıyla tanınır.","nl":"1428–1521. Een Meso-Amerikaanse beschaving gevestigd in Tenochtitlan (het huidige Mexico-Stad); bekend om piramide-tempels, mensenoffers en een complexe bureaucratie vóór de Spaanse verovering.","ru":"1428–1521 годы. Мезоамериканская цивилизация со столицей в Теночтитлане (современный Мехико); известна пирамидальными храмами, человеческими жертвоприношениями и сложной бюрократией до испанского завоевания.","zh":"1428–1521年。以特诺奇蒂特兰（今墨西哥城）为中心的中美洲文明；以金字塔神庙、活人祭祀和复杂的官僚体系闻名，后被西班牙征服。","pt_BR":"1428–1521. Uma civilização mesoamericana sediada em Tenochtitlan (atual Cidade do México); conhecida por templos piramidais, sacrifícios humanos e uma burocracia complexa antes da conquista espanhola.","pt_PT":"1428–1521. Uma civilização mesoamericana sediada em Tenochtitlan (atual Cidade do México); conhecida pelos seus templos piramidais, sacrifícios humanos e uma burocracia complexa antes da conquista espanhola."}},
  { id: 'dc-history-0119', deck_id: 'deck-history', front: 'Inca Empire', back: '1438–1533. The largest empire in pre-Columbian America, centered in Peru; renowned for engineering feats (Machu Picchu, road networks) before Spanish conquest under Pizarro.', sort_order: 119 , front_translations: {"es":"Imperio Inca","de":"Inkareich","fr":"Empire inca","tr":"İnka İmparatorluğu","nl":"Incarijk","ru":"Империя инков","zh":"印加帝国","pt_BR":"Império Inca","pt_PT":"Império Inca"}, back_translations: {"es":"1438–1533. El mayor imperio de la América pré-colombiana, centrado en el Peru; famoso por feitos de engenharia (Machu Picchu, redes de estradas) antes de la conquista espanhola sob Pizarro.","de":"1438–1533. Das größte Reich im vorkolumbischen Amerika mit Zentrum in Peru; berühmt für Ingenieurleistungen (Machu Picchu, Straßennetze) vor der spanischen Eroberung unter Pizarro.","fr":"1438–1533. Le plus grand empire de l'Amérique précolombienne, centré au Pérou ; célèbre pour ses prouesses d'ingénierie (Machu Picchu, réseaux routiers) avant la conquête espagnole de Pizarro.","tr":"1438–1533. Peru merkezli, Kolomb öncesi Amerika'nın en büyük imparatorluğu; Pizarro komutasındaki İspanyol fethinden önce mühendislik başarılarıyla (Machu Picchu, yol ağları) ünlüdür.","nl":"1438–1533. Het grootste rijk in pre-Columbiaans Amerika, gecentreerd in Peru; vermaard om technische prestaties (Machu Picchu, wegennetwerken) vóór de Spaanse verovering onder Pizarro.","ru":"1438–1533 годы. Крупнейшая империя доколумбовой Америки с центром в Перу; славилась инженерными достижениями (Мачу-Пикчу, дорожные сети) до испанского завоевания под командованием Писарро.","zh":"1438–1533年。前哥伦布时期美洲最大的帝国，以秘鲁为中心；以工程壮举（马丘比丘、道路网络）闻名，后被皮萨罗率领的西班牙人征服。","pt_BR":"1438–1533. O maior império da América pré-colombiana, centrado no Peru; famoso por feitos de engenharia (Machu Picchu, redes de estradas) antes da conquista espanhola sob Pizarro.","pt_PT":"1438–1533. O maior império da América pré-colombiana, centrado no Peru; famoso pelas suas proezas de engenharia (Machu Picchu, redes de estradas) antes da conquista espanhola sob Pizarro."}},
  { id: 'dc-history-0120', deck_id: 'deck-history', front: 'The Enlightenment Philosophers (Locke, Voltaire, Rousseau)', back: 'Key thinkers who argued for natural rights, separation of powers, and popular sovereignty; their ideas directly inspired the American and French Revolutions.', sort_order: 120 , front_translations: {"es":"Los Filósofos del Iluminismo (Locke, Voltaire, Rousseau)","de":"Die Philosophen der Aufklärung (Locke, Voltaire, Rousseau)","fr":"Les philosophes des Lumières (Locke, Voltaire, Rousseau)","tr":"Aydınlanma Filozofları (Locke, Voltaire, Rousseau)","nl":"De Verlichtingsfilosofen (Locke, Voltaire, Rousseau)","ru":"Философы Просвещения (Локк, Вольтер, Руссо)","zh":"启蒙思想家（洛克、伏尔泰、卢梭）","pt_BR":"Os Filósofos do Iluminismo (Locke, Voltaire, Rousseau)","pt_PT":"Os Filósofos do Iluminismo (Locke, Voltaire, Rousseau)"}, back_translations: {"es":"Pensadores fundamentales que defenderam los derechos naturais, a separación de los poderes y a soberania popular; sus ideias inspiraram directamente las Revoluciones Americana y Francesa.","de":"Bedeutende Denker, die für natürliche Rechte, Gewaltenteilung und Volkssouveränität plädierten; ihre Ideen inspirierten direkt die Amerikanische und die Französische Revolution.","fr":"Penseurs majeurs qui défendaient les droits naturels, la séparation des pouvoirs et la souveraineté populaire ; leurs idées ont directement inspiré les Révolutions américaine et française.","tr":"Doğal haklar, kuvvetler ayrılığı ve halk egemenliğini savunan önemli düşünürler; fikirleri Amerikan ve Fransız Devrimlerini doğrudan etkiledi.","nl":"Belangrijke denkers die pleitten voor natuurlijke rechten, scheiding der machten en volkssoevereiniteit; hun ideeën inspireerden rechtstreeks de Amerikaanse en Franse Revolutie.","ru":"Ключевые мыслители, отстаивавшие естественные права, разделение властей и народный суверенитет; их идеи непосредственно вдохновили Американскую и Французскую революции.","zh":"主张天赋人权、三权分立和人民主权的重要思想家；他们的思想直接启发了美国革命和法国大革命。","pt_BR":"Pensadores fundamentais que defenderam os direitos naturais, a separação dos poderes e a soberania popular; suas ideias inspiraram diretamente as Revoluções Americana e Francesa.","pt_PT":"Pensadores fundamentais que defenderam os direitos naturais, a separação de poderes e a soberania popular; as suas ideias inspiraram diretamente as Revoluções Americana e Francesa."}},
  { id: 'dc-history-0121', deck_id: 'deck-history', front: 'Boston Massacre', back: '1770. British soldiers killed five colonists in Boston; used as propaganda by patriots to build anti-British sentiment leading to the American Revolution.', sort_order: 121 , front_translations: {"es":"Massacre de Boston","de":"Massaker von Boston","fr":"Massacre de Boston","tr":"Boston Katliamı","nl":"Bloedbad van Boston","ru":"Бостонская бойня","zh":"波士顿惨案","pt_BR":"Massacre de Boston","pt_PT":"Massacre de Boston"}, back_translations: {"es":"1770. Soldados britanicos mataram cinco colonos en Boston; usado como propaganda por patriotas para construir sentimiento antibritanico que levou a la Revolución Americana.","de":"1770. Britische Soldaten töteten fünf Kolonisten in Boston; von Patrioten als Propaganda genutzt, um antibritische Stimmung im Vorfeld der Amerikanischen Revolution zu schüren.","fr":"1770. Des soldats britanniques ont tué cinq colons à Boston ; utilisé comme propagande par les patriotes pour alimenter le sentiment antibritannique menant à la Révolution américaine.","tr":"1770. İngiliz askerleri Boston'da beş sömürgeci öldürdü; vatanseverler tarafından Amerikan Devrimi'ne giden yolda İngiliz karşıtı duyguları körüklemek için propaganda olarak kullanıldı.","nl":"1770. Britse soldaten doodden vijf kolonisten in Boston; door patriotten als propaganda gebruikt om anti-Brits sentiment op te bouwen in aanloop naar de Amerikaanse Revolutie.","ru":"1770 год. Британские солдаты убили пять колонистов в Бостоне; патриоты использовали это как пропаганду для разжигания антибританских настроений, приведших к Американской революции.","zh":"1770年。英国士兵在波士顿杀害了五名殖民者；爱国者将此事件用作宣传，煽动反英情绪，推动了美国革命的爆发。","pt_BR":"1770. Soldados britânicos mataram cinco colonos em Boston; usado como propaganda por patriotas para construir sentimento antibritânico que levou à Revolução Americana.","pt_PT":"1770. Soldados britânicos mataram cinco colonos em Boston; usado como propaganda por patriotas para fomentar o sentimento antibritânico que conduziu à Revolução Americana."}},
  { id: 'dc-history-0122', deck_id: 'deck-history', front: 'Lewis and Clark Expedition', back: '1804–1806. Meriwether Lewis and William Clark led the first American overland expedition to the Pacific coast, mapping and documenting the western frontier.', sort_order: 122 , front_translations: {"es":"Expedición de Lewis y Clark","de":"Lewis-und-Clark-Expedition","fr":"Expédition Lewis et Clark","tr":"Lewis ve Clark Keşif Seferi","nl":"Lewis-en-Clark-expeditie","ru":"Экспедиция Льюиса и Кларка","zh":"刘易斯与克拉克远征","pt_BR":"Expedição de Lewis e Clark","pt_PT":"Expedição de Lewis e Clark"}, back_translations: {"es":"1804–1806. Meriwether Lewis y William Clark lideraram a primera expedición terrestre americana hasta a costa del Pacífico, mapeando y documentando a frontera ocidental.","de":"1804–1806. Meriwether Lewis und William Clark leiteten die erste amerikanische Überlandexpedition zur Pazifikküste und kartierten und dokumentierten die westliche Grenze.","fr":"1804–1806. Meriwether Lewis et William Clark ont dirigé la première expédition terrestre américaine vers la côte du Pacifique, cartographiant et documentant la frontière occidentale.","tr":"1804–1806. Meriwether Lewis ve William Clark, Pasifik kıyısına ilk Amerikan kara seferini yönetti ve batı sınır bölgesinin haritasını çıkarıp belgeledi.","nl":"1804–1806. Meriwether Lewis en William Clark leidden de eerste Amerikaanse overlandexpeditie naar de Pacifische kust en brachten de westelijke grens in kaart.","ru":"1804–1806 годы. Мериуэзер Льюис и Уильям Кларк возглавили первую американскую сухопутную экспедицию к тихоокеанскому побережью, нанося на карту и документируя западные рубежи.","zh":"1804–1806年。梅里韦瑟·刘易斯和威廉·克拉克率领了首次美国陆路远征到达太平洋海岸，绘制地图并记录了西部边疆。","pt_BR":"1804–1806. Meriwether Lewis e William Clark lideraram a primeira expedição terrestre americana até a costa do Pacífico, mapeando e documentando a fronteira ocidental.","pt_PT":"1804–1806. Meriwether Lewis e William Clark lideraram a primeira expedição terrestre americana até à costa do Pacífico, cartografando e documentando a fronteira ocidental."}},
  { id: 'dc-history-0123', deck_id: 'deck-history', front: 'Monroe Doctrine', back: '1823. President Monroe declared that the Americas were no longer open to European colonization; it became a cornerstone of US foreign policy.', sort_order: 123 , front_translations: {"es":"Doutrina Monroe","de":"Monroe-Doktrin","fr":"Doctrine Monroe","tr":"Monroe Doktrini","nl":"Monroedoctrine","ru":"Доктрина Монро","zh":"门罗主义","pt_BR":"Doutrina Monroe","pt_PT":"Doutrina Monroe"}, back_translations: {"es":"1823. El presidente Monroe declarou que las Américas no estavam más abertas a la colonización europeia; tornou-se un pilar de la política externa de los EUA.","de":"1823. Präsident Monroe erklärte, dass die Amerikas nicht mehr für europäische Kolonisierung offen seien; die Doktrin wurde zum Eckpfeiler der US-Außenpolitik.","fr":"1823. Le président Monroe a déclaré que les Amériques n'étaient plus ouvertes à la colonisation européenne ; cette doctrine est devenue une pierre angulaire de la politique étrangère américaine.","tr":"1823. Başkan Monroe, Amerika kıtalarının artık Avrupa sömürgeciliğine açık olmadığını ilan etti; bu doktrin ABD dış politikasının temel taşı haline geldi.","nl":"1823. President Monroe verklaarde dat de Amerika's niet langer openstonden voor Europese kolonisatie; het werd een hoeksteen van het Amerikaans buitenlands beleid.","ru":"1823 год. Президент Монро заявил, что Америка больше не открыта для европейской колонизации; доктрина стала краеугольным камнем внешней политики США.","zh":"1823年。门罗总统宣布美洲不再对欧洲殖民开放；这一主张成为美国外交政策的基石。","pt_BR":"1823. O presidente Monroe declarou que as Américas não estavam mais abertas à colonização europeia; tornou-se um pilar da política externa dos EUA.","pt_PT":"1823. O presidente Monroe declarou que as Américas já não estavam abertas à colonização europeia; tornou-se um pilar da política externa dos EUA."}},
  { id: 'dc-history-0124', deck_id: 'deck-history', front: 'Crimean War', back: '1853–1856. A conflict in which Britain, France, and the Ottoman Empire fought Russia; notable for the role of Florence Nightingale in establishing modern nursing practices.', sort_order: 124 , front_translations: {"es":"Guerra de la Crimeia","de":"Krimkrieg","fr":"Guerre de Crimée","tr":"Kırım Savaşı","nl":"Krimoorlog","ru":"Крымская война","zh":"克里米亚战争","pt_BR":"Guerra da Crimeia","pt_PT":"Guerra da Crimeia"}, back_translations: {"es":"1853–1856. Un conflito en el qual a Grã-Bretanha, a França y el Imperio Otomano lutaram contra a Rússia; notable por el papel de Florence Nightingale en el estabelecimento de práticas modernas de enfermaje.","de":"1853–1856. Ein Konflikt, in dem Großbritannien, Frankreich und das Osmanische Reich gegen Russland kämpften; bemerkenswert für die Rolle von Florence Nightingale bei der Begründung moderner Krankenpflegepraktiken.","fr":"1853–1856. Un conflit au cours duquel la Grande-Bretagne, la France et l'Empire ottoman ont combattu la Russie ; notable pour le rôle de Florence Nightingale dans l'établissement des pratiques infirmières modernes.","tr":"1853–1856. İngiltere, Fransa ve Osmanlı İmparatorluğu'nun Rusya'ya karşı savaştığı bir çatışma; Florence Nightingale'in modern hemşirelik uygulamalarını kurmasındaki rolüyle dikkat çeker.","nl":"1853–1856. Een conflict waarin Groot-Brittannië, Frankrijk en het Ottomaanse Rijk tegen Rusland vochten; opmerkelijk vanwege de rol van Florence Nightingale bij het vestigen van moderne verpleegkundige praktijken.","ru":"1853–1856 годы. Конфликт, в котором Великобритания, Франция и Османская империя воевали против России; примечателен ролью Флоренс Найтингейл в становлении современного сестринского дела.","zh":"1853–1856年。英国、法国和奥斯曼帝国与俄罗斯之间的冲突；以弗洛伦斯·南丁格尔在建立现代护理实践中的作用而著称。","pt_BR":"1853–1856. Um conflito no qual a Grã-Bretanha, a França e o Império Otomano lutaram contra a Rússia; notável pelo papel de Florence Nightingale no estabelecimento de práticas modernas de enfermagem.","pt_PT":"1853–1856. Um conflito no qual a Grã-Bretanha, a França e o Império Otomano lutaram contra a Rússia; notável pelo papel de Florence Nightingale no estabelecimento de práticas modernas de enfermagem."}},
  { id: 'dc-history-0125', deck_id: 'deck-history', front: 'Bessemer Steel Process', back: '1856. Henry Bessemer\'s process for mass-producing steel cheaply transformed construction and manufacturing, becoming a cornerstone of the Industrial Revolution\'s second phase.', sort_order: 125 , front_translations: {"es":"Proceso Bessemer de Aço","de":"Bessemer-Stahlverfahren","fr":"Procédé Bessemer","tr":"Bessemer Çelik Üretim Yöntemi","nl":"Bessemerproces","ru":"Бессемеровский процесс","zh":"贝塞麦炼钢法","pt_BR":"Processo Bessemer de Aço","pt_PT":"Processo Bessemer de Aço"}, back_translations: {"es":"1856. El proceso de Henry Bessemer para producción en masa de aço barato transformou a construcción y a manufatura, tornando-se un pilar de la segunda fase de la Revolución Industrial.","de":"1856. Henry Bessemers Verfahren zur kostengünstigen Massenproduktion von Stahl revolutionierte das Bauwesen und die Fertigung und wurde zu einem Eckpfeiler der zweiten Phase der Industriellen Revolution.","fr":"1856. Le procédé de Henry Bessemer pour la production en masse d'acier à bas coût transforma la construction et l'industrie manufacturière, devenant une pierre angulaire de la deuxième phase de la révolution industrielle.","tr":"1856. Henry Bessemer'in ucuz çelik seri üretim yöntemi, inşaat ve imalat sektörünü dönüştürdü ve Sanayi Devrimi'nin ikinci aşamasının temel taşı oldu.","nl":"1856. Henry Bessemers proces voor de goedkope massaproductie van staal transformeerde de bouw en productie en werd een hoeksteen van de tweede fase van de Industriële Revolutie.","ru":"1856 год. Процесс Генри Бессемера для дешёвого массового производства стали преобразил строительство и промышленность, став краеугольным камнем второго этапа промышленной революции.","zh":"1856年。亨利·贝塞麦发明的低成本大规模炼钢工艺革新了建筑和制造业，成为第二次工业革命的基石。","pt_BR":"1856. O processo de Henry Bessemer para produção em massa de aço barato transformou a construção e a manufatura, tornando-se um pilar da segunda fase da Revolução Industrial.","pt_PT":"1856. O processo de Henry Bessemer para a produção em massa de aço barato transformou a construção e a manufatura, tornando-se um pilar da segunda fase da Revolução Industrial."}},
  { id: 'dc-history-0126', deck_id: 'deck-history', front: 'Emancipation Proclamation', back: '1863. President Lincoln declared all enslaved people in Confederate states to be free, transforming the Civil War into a battle for emancipation and preventing European recognition of the Confederacy.', sort_order: 126 , front_translations: {"es":"Proclamación de Emancipación","de":"Emanzipationsproklamation","fr":"Proclamation d'émancipation","tr":"Özgürlük Bildirisi","nl":"Emancipatieproclamatie","ru":"Прокламация об освобождении рабов","zh":"《解放奴隶宣言》","pt_BR":"Proclamação de Emancipação","pt_PT":"Proclamação de Emancipação"}, back_translations: {"es":"1863. El presidente Lincoln declarou livres todos los escravizados en los estados confederados, transformando a Guerra Civil en una batalla por la emancipación y impidiendo el reconhecimento europeu de la Confederación.","de":"1863. Präsident Lincoln erklärte alle versklavten Menschen in den Konföderationsstaaten für frei, verwandelte den Bürgerkrieg in einen Kampf für die Emanzipation und verhinderte die europäische Anerkennung der Konföderation.","fr":"1863. Le président Lincoln déclara libres tous les esclaves dans les États confédérés, transformant la guerre civile en une bataille pour l'émancipation et empêchant la reconnaissance européenne de la Confédération.","tr":"1863. Başkan Lincoln, Konfederasyon eyaletlerindeki tüm kölelerin özgür olduğunu ilan etti; bu adım İç Savaş'ı özgürleşme mücadelesine dönüştürdü ve Avrupa'nın Konfederasyonu tanımasını engelledi.","nl":"1863. President Lincoln verklaarde alle tot slaafgemaakten in de Geconfedereerde staten vrij, waarmee hij de Burgeroorlog omvormde tot een strijd voor emancipatie en Europese erkenning van de Confederatie voorkwam.","ru":"1863. Президент Линкольн объявил всех порабощённых людей в штатах Конфедерации свободными, превратив Гражданскую войну в борьбу за освобождение и предотвратив европейское признание Конфедерации.","zh":"1863年。林肯总统宣布联邦各州的所有奴隶获得自由，将内战转变为争取解放的战争，并阻止了欧洲对南部邦联的承认。","pt_BR":"1863. O presidente Lincoln declarou livres todos os escravizados nos estados confederados, transformando a Guerra Civil em uma batalha pela emancipação e impedindo o reconhecimento europeu da Confederação.","pt_PT":"1863. O presidente Lincoln declarou livres todos os escravizados nos estados confederados, transformando a Guerra Civil numa batalha pela emancipação e impedindo o reconhecimento europeu da Confederação."}},
  { id: 'dc-history-0127', deck_id: 'deck-history', front: 'Transcontinental Railroad Completed', back: '1869. The first railroad connecting the US East and West coasts was completed, accelerating westward expansion and integration of the American economy.', sort_order: 127 , front_translations: {"es":"Conclusão de la Ferrovia Transcontinental","de":"Transkontinentale Eisenbahn fertiggestellt","fr":"Achèvement du chemin de fer transcontinental","tr":"Transkontinental Demiryolu Tamamlandı","nl":"Voltooiing van de Transcontinentale Spoorweg","ru":"Завершение строительства трансконтинентальной железной дороги","zh":"横贯大陆铁路竣工","pt_BR":"Conclusão da Ferrovia Transcontinental","pt_PT":"Conclusão da Ferrovia Transcontinental"}, back_translations: {"es":"1869. La primera ferrovia ligando las costas leste y oeste de los EUA fue concluída, acelerando a expansão para el oeste y a integración de la economía americana.","de":"1869. Die erste Eisenbahn, die die Ost- und Westküste der USA verband, wurde fertiggestellt und beschleunigte die Westexpansion und die Integration der amerikanischen Wirtschaft.","fr":"1869. Le premier chemin de fer reliant les côtes est et ouest des États-Unis fut achevé, accélérant l'expansion vers l'ouest et l'intégration de l'économie américaine.","tr":"1869. ABD'nin doğu ve batı kıyılarını birbirine bağlayan ilk demiryolu tamamlandı; bu gelişme batıya doğru genişlemeyi ve Amerikan ekonomisinin bütünleşmesini hızlandırdı.","nl":"1869. De eerste spoorlijn die de oost- en westkust van de VS verbond, werd voltooid, wat de westwaartse expansie en de integratie van de Amerikaanse economie versnelde.","ru":"1869. Была завершена первая железная дорога, соединившая восточное и западное побережья США, ускорившая освоение запада и интеграцию американской экономики.","zh":"1869年。连接美国东西海岸的第一条铁路竣工，加速了西部扩张和美国经济的一体化进程。","pt_BR":"1869. A primeira ferrovia ligando as costas leste e oeste dos EUA foi concluída, acelerando a expansão para o oeste e a integração da economia americana.","pt_PT":"1869. A primeira ferrovia que ligava as costas leste e oeste dos EUA foi concluída, acelerando a expansão para oeste e a integração da economia americana."}},
  { id: 'dc-history-0128', deck_id: 'deck-history', front: 'Wright Brothers\' First Flight', back: '1903. Orville and Wilbur Wright achieved the first successful powered airplane flight at Kitty Hawk, North Carolina, launching the age of aviation.', sort_order: 128 , front_translations: {"es":"Primero Voo de los Irmãos Wright","de":"Erster Flug der Gebrüder Wright","fr":"Premier vol des frères Wright","tr":"Wright Kardeşlerin İlk Uçuşu","nl":"Eerste vlucht van de gebroeders Wright","ru":"Первый полёт братьев Райт","zh":"莱特兄弟首次飞行","pt_BR":"Primeiro Voo dos Irmãos Wright","pt_PT":"Primeiro Voo dos Irmãos Wright"}, back_translations: {"es":"1903. Orville y Wilbur Wright realizaram el primero voo bem-sucedido de avião motorizado en Kitty Hawk, Carolina del Norte, inaugurando a era de la aviación.","de":"1903. Orville und Wilbur Wright gelang der erste erfolgreiche Motorflug in Kitty Hawk, North Carolina, und läuteten damit das Zeitalter der Luftfahrt ein.","fr":"1903. Orville et Wilbur Wright réalisèrent le premier vol motorisé réussi à Kitty Hawk, en Caroline du Nord, inaugurant l'ère de l'aviation.","tr":"1903. Orville ve Wilbur Wright, Kuzey Carolina'daki Kitty Hawk'ta ilk başarılı motorlu uçak uçuşunu gerçekleştirerek havacılık çağını başlattı.","nl":"1903. Orville en Wilbur Wright slaagden in de eerste succesvolle gemotoriseerde vliegtuigvlucht bij Kitty Hawk, North Carolina, en luidden daarmee het tijdperk van de luchtvaart in.","ru":"1903 год. Орвилл и Уилбур Райт совершили первый успешный полёт на моторном самолёте в Китти-Хок, Северная Каролина, открыв эру авиации.","zh":"1903年。奥维尔和威尔伯·莱特在北卡罗来纳州基蒂霍克实现了首次成功的动力飞机飞行，开启了航空时代。","pt_BR":"1903. Orville e Wilbur Wright realizaram o primeiro voo bem-sucedido de avião motorizado em Kitty Hawk, Carolina do Norte, inaugurando a era da aviação.","pt_PT":"1903. Orville e Wilbur Wright realizaram o primeiro voo bem-sucedido de avião motorizado em Kitty Hawk, Carolina do Norte, inaugurando a era da aviação."}},
  { id: 'dc-history-0129', deck_id: 'deck-history', front: 'Women\'s Suffrage (USA)', back: '1920. The 19th Amendment to the US Constitution granted women the right to vote, the culmination of decades of activism by the suffragette movement.', sort_order: 129 , front_translations: {"es":"Sufrágio Feminino (EUA)","de":"Frauenwahlrecht (USA)","fr":"Suffrage féminin (États-Unis)","tr":"Kadınların Oy Hakkı (ABD)","nl":"Vrouwenkiesrecht (VS)","ru":"Избирательное право женщин (США)","zh":"美国女性选举权","pt_BR":"Sufrágio Feminino (EUA)","pt_PT":"Sufrágio Feminino (EUA)"}, back_translations: {"es":"1920. La 19ª Emenda a la Constitución de los EUA concedeu a las mujeres el derecho de voto, culminación de décadas de ativismo del movimiento sufragista.","de":"1920. Der 19. Zusatzartikel zur US-Verfassung gewährte Frauen das Wahlrecht – der Höhepunkt jahrzehntelangen Engagements der Suffragettenbewegung.","fr":"1920. Le 19e amendement à la Constitution américaine accorda le droit de vote aux femmes, aboutissement de décennies de militantisme du mouvement des suffragettes.","tr":"1920. ABD Anayasası'nın 19. Değişikliği kadınlara oy hakkı tanıdı; süfrajet hareketinin onlarca yıllık mücadelesinin doruk noktasıydı.","nl":"1920. Het 19e amendement op de Amerikaanse grondwet verleende vrouwen stemrecht, het hoogtepunt van decennia van activisme door de suffragettebeweging.","ru":"1920 год. 19-я поправка к Конституции США предоставила женщинам право голоса — итог десятилетий борьбы суфражистского движения.","zh":"1920年。美国宪法第十九修正案赋予女性投票权，这是妇女参政运动数十年奋斗的成果。","pt_BR":"1920. A 19ª Emenda à Constituição dos EUA concedeu às mulheres o direito de voto, culminação de décadas de ativismo do movimento sufragista.","pt_PT":"1920. A 19.ª Emenda à Constituição dos EUA concedeu às mulheres o direito de voto, culminação de décadas de ativismo do movimento sufragista."}},
  { id: 'dc-history-0130', deck_id: 'deck-history', front: 'New Deal', back: '1933–1939. President Roosevelt\'s programs responding to the Great Depression, expanding federal government\'s role in the economy through banking reform, public works, and social insurance.', sort_order: 130 , front_translations: {"es":"New Deal","de":"New Deal","fr":"New Deal","tr":"New Deal (Yeni Düzen)","nl":"New Deal","ru":"Новый курс","zh":"罗斯福新政","pt_BR":"New Deal","pt_PT":"New Deal"}, back_translations: {"es":"1933–1939. Los programas del presidente Roosevelt en respuesta a la Grande Depresión, expandindo el papel del gobierno federal en la economía por medio de reforma bancária, obras públicas y seguro social.","de":"1933–1939. Die Programme von Präsident Roosevelt als Antwort auf die Große Depression, die die Rolle der Bundesregierung in der Wirtschaft durch Bankenreform, öffentliche Arbeitsprogramme und Sozialversicherung ausweiteten.","fr":"1933–1939. Les programmes du président Roosevelt en réponse à la Grande Dépression, élargissant le rôle du gouvernement fédéral dans l'économie par la réforme bancaire, les travaux publics et l'assurance sociale.","tr":"1933–1939. Başkan Roosevelt'in Büyük Buhran'a yanıt olarak uyguladığı programlar; banka reformu, bayındırlık işleri ve sosyal sigorta yoluyla federal hükümetin ekonomideki rolünü genişletti.","nl":"1933–1939. De programma's van president Roosevelt als reactie op de Grote Depressie, die de rol van de federale overheid in de economie uitbreidden door middel van bankhervorming, openbare werken en sociale verzekeringen.","ru":"1933–1939 годы. Программы президента Рузвельта в ответ на Великую депрессию, расширившие роль федерального правительства в экономике посредством банковской реформы, общественных работ и социального страхования.","zh":"1933–1939年。罗斯福总统应对大萧条的系列计划，通过银行改革、公共工程和社会保险扩大了联邦政府在经济中的角色。","pt_BR":"1933–1939. Os programas do presidente Roosevelt em resposta à Grande Depressão, expandindo o papel do governo federal na economia por meio de reforma bancária, obras públicas e seguro social.","pt_PT":"1933–1939. Os programas do presidente Roosevelt em resposta à Grande Depressão, expandindo o papel do governo federal na economia através de reforma bancária, obras públicas e seguro social."}},
  { id: 'dc-history-0131', deck_id: 'deck-history', front: 'Battle of Britain', back: '1940. The RAF successfully defended Britain against the Luftwaffe\'s intense bombing campaign, denying Hitler the air superiority needed for a land invasion.', sort_order: 131 , front_translations: {"es":"Batalla de la Grã-Bretanha","de":"Luftschlacht um England","fr":"Bataille d'Angleterre","tr":"Britanya Savaşı","nl":"Slag om Engeland","ru":"Битва за Британию","zh":"不列颠之战","pt_BR":"Batalha da Grã-Bretanha","pt_PT":"Batalha de Inglaterra"}, back_translations: {"es":"1940. La RAF defendeu con éxito a Grã-Bretanha contra a intensa campanha de bombardeio de la Luftwaffe, negando a Hitler a superioridad aérea necesaria para una invasão terrestre.","de":"1940. Die RAF verteidigte Großbritannien erfolgreich gegen die intensive Bombenkampagne der Luftwaffe und verweigerte Hitler die Luftüberlegenheit, die für eine Landinvasion nötig gewesen wäre.","fr":"1940. La RAF défendit avec succès la Grande-Bretagne contre l'intense campagne de bombardement de la Luftwaffe, privant Hitler de la supériorité aérienne nécessaire à une invasion terrestre.","tr":"1940. RAF, Luftwaffe'nin yoğun bombardıman kampanyasına karşı İngiltere'yi başarıyla savunarak Hitler'in kara istilası için ihtiyaç duyduğu hava üstünlüğünü engelledi.","nl":"1940. De RAF verdedigde Groot-Brittannië met succes tegen de intense bombardementscampagne van de Luftwaffe en ontzegde Hitler de luchtoverheerschapping die nodig was voor een landinvasie.","ru":"1940 год. Королевские ВВС успешно защитили Британию от интенсивных бомбардировок люфтваффе, лишив Гитлера превосходства в воздухе, необходимого для сухопутного вторжения.","zh":"1940年。英国皇家空军成功抵御了德国空军的猛烈轰炸，使希特勒无法获得实施陆地入侵所需的制空权。","pt_BR":"1940. A RAF defendeu com sucesso a Grã-Bretanha contra a intensa campanha de bombardeio da Luftwaffe, negando a Hitler a superioridade aérea necessária para uma invasão terrestre.","pt_PT":"1940. A RAF defendeu com sucesso a Grã-Bretanha contra a intensa campanha de bombardeamento da Luftwaffe, negando a Hitler a superioridade aérea necessária para uma invasão terrestre."}},
  { id: 'dc-history-0132', deck_id: 'deck-history', front: 'Pearl Harbor Attack', back: '7 December 1941. Japan\'s surprise attack on the US naval base in Hawaii killed ~2,400 Americans, bringing the United States into WWII.', sort_order: 132 , front_translations: {"es":"Ataque a Pearl Harbor","de":"Angriff auf Pearl Harbor","fr":"Attaque de Pearl Harbor","tr":"Pearl Harbor Saldırısı","nl":"Aanval op Pearl Harbor","ru":"Нападение на Пёрл-Харбор","zh":"珍珠港事件","pt_BR":"Ataque a Pearl Harbor","pt_PT":"Ataque a Pearl Harbor"}, back_translations: {"es":"7 de dezembro de 1941. El ataque surpresa del Japão a la base naval de los EUA en el Havaí matou cerca de 2.400 americanos, trazendo los Estados Unidos para a Segunda Guerra Mundial.","de":"7. Dezember 1941. Japans Überraschungsangriff auf den US-Marinestützpunkt auf Hawaii tötete etwa 2.400 Amerikaner und führte zum Eintritt der Vereinigten Staaten in den Zweiten Weltkrieg.","fr":"7 décembre 1941. L'attaque surprise du Japon contre la base navale américaine à Hawaï tua environ 2 400 Américains, entraînant l'entrée des États-Unis dans la Seconde Guerre mondiale.","tr":"7 Aralık 1941. Japonya'nın Hawaii'deki ABD deniz üssüne düzenlediği sürpriz saldırıda yaklaşık 2.400 Amerikalı öldü ve ABD İkinci Dünya Savaşı'na girdi.","nl":"7 december 1941. Japans verrassingsaanval op de Amerikaanse marinebasis op Hawaï doodde ~2.400 Amerikanen en bracht de Verenigde Staten de Tweede Wereldoorlog in.","ru":"7 декабря 1941 года. Внезапное нападение Японии на американскую военно-морскую базу на Гавайях унесло жизни около 2 400 американцев и втянуло Соединённые Штаты во Вторую мировую войну.","zh":"1941年12月7日。日本突袭美国夏威夷海军基地，造成约2,400名美国人死亡，促使美国加入第二次世界大战。","pt_BR":"7 de dezembro de 1941. O ataque surpresa do Japão à base naval dos EUA no Havaí matou cerca de 2.400 americanos, trazendo os Estados Unidos para a Segunda Guerra Mundial.","pt_PT":"7 de dezembro de 1941. O ataque surpresa do Japão à base naval dos EUA no Havai matou cerca de 2.400 americanos, trazendo os Estados Unidos para a Segunda Guerra Mundial."}},
  { id: 'dc-history-0133', deck_id: 'deck-history', front: 'Manhattan Project', back: '1942–1945. The secret US-led project that developed the first nuclear weapons; the program employed ~130,000 people at sites across North America.', sort_order: 133 , front_translations: {"es":"Projeto Manhattan","de":"Manhattan-Projekt","fr":"Projet Manhattan","tr":"Manhattan Projesi","nl":"Manhattanproject","ru":"Манхэттенский проект","zh":"曼哈顿计划","pt_BR":"Projeto Manhattan","pt_PT":"Projeto Manhattan"}, back_translations: {"es":"1942–1945. El projeto secreto liderado por los EUA que desenvolveu las primeras armas nucleares; el programa empregou ~130.000 personas en instalaciones por toda a América del Norte.","de":"1942–1945. Das geheime, von den USA geleitete Projekt zur Entwicklung der ersten Atomwaffen; das Programm beschäftigte ~130.000 Menschen an Standorten in ganz Nordamerika.","fr":"1942–1945. Le projet secret dirigé par les États-Unis qui développa les premières armes nucléaires ; le programme employa ~130 000 personnes sur des sites à travers l'Amérique du Nord.","tr":"1942–1945. İlk nükleer silahları geliştiren ABD liderliğindeki gizli proje; program, Kuzey Amerika genelindeki tesislerde yaklaşık 130.000 kişiyi istihdam etti.","nl":"1942–1945. Het geheime door de VS geleide project dat de eerste kernwapens ontwikkelde; het programma stelde ~130.000 mensen tewerk op locaties door heel Noord-Amerika.","ru":"1942–1945. Секретный проект под руководством США по созданию первого ядерного оружия; в программе было задействовано ~130 000 человек на объектах по всей Северной Америке.","zh":"1942–1945年。美国主导的研发首批核武器的秘密计划，该计划在北美各地的基地雇用了约13万人。","pt_BR":"1942–1945. O projeto secreto liderado pelos EUA que desenvolveu as primeiras armas nucleares; o programa empregou ~130.000 pessoas em instalações por toda a América do Norte.","pt_PT":"1942–1945. O projeto secreto liderado pelos EUA que desenvolveu as primeiras armas nucleares; o programa empregou ~130.000 pessoas em instalações por toda a América do Norte."}},
  { id: 'dc-history-0134', deck_id: 'deck-history', front: 'Nuremberg Trials', back: '1945–1946. International military tribunals that tried Nazi war criminals; they established precedents for international law and the concept of crimes against humanity.', sort_order: 134 , front_translations: {"es":"Julgamentos de Nuremberg","de":"Nürnberger Prozesse","fr":"Procès de Nuremberg","tr":"Nürnberg Davaları","nl":"Processen van Neurenberg","ru":"Нюрнбергский процесс","zh":"纽伦堡审判","pt_BR":"Julgamentos de Nuremberg","pt_PT":"Julgamentos de Nuremberga"}, back_translations: {"es":"1945–1946. Tribunais militares internacionais que julgaram criminosos de guerra nazistas; estabeleceram precedentes para el derecho internacional y el concepto de crimes contra a humanidad.","de":"1945–1946. Internationale Militärtribunale, die NS-Kriegsverbrecher vor Gericht stellten; sie schufen Präzedenzfälle für das Völkerrecht und das Konzept der Verbrechen gegen die Menschlichkeit.","fr":"1945–1946. Des tribunaux militaires internationaux jugèrent les criminels de guerre nazis ; ils établirent des précédents pour le droit international et le concept de crimes contre l'humanité.","tr":"1945–1946. Nazi savaş suçlularını yargılayan uluslararası askeri mahkemeler; bu davalar uluslararası hukuk ve insanlığa karşı suçlar kavramı için emsal oluşturdu.","nl":"1945–1946. Internationale militaire rechtbanken die nazi-oorlogsmisdadigers berechtten; zij vestigden precedenten voor het internationaal recht en het concept van misdaden tegen de menselijkheid.","ru":"1945–1946. Международные военные трибуналы над нацистскими военными преступниками; они заложили прецеденты для международного права и концепции преступлений против человечности.","zh":"1945–1946年。审判纳粹战犯的国际军事法庭，为国际法及反人类罪概念确立了先例。","pt_BR":"1945–1946. Tribunais militares internacionais que julgaram criminosos de guerra nazistas; estabeleceram precedentes para o direito internacional e o conceito de crimes contra a humanidade.","pt_PT":"1945–1946. Tribunais militares internacionais que julgaram criminosos de guerra nazis; estabeleceram precedentes para o direito internacional e o conceito de crimes contra a humanidade."}},
  { id: 'dc-history-0135', deck_id: 'deck-history', front: 'Partition of India', back: '1947. Britain\'s withdrawal from India was accompanied by a partition creating Pakistan; massive population displacement and communal violence killed hundreds of thousands.', sort_order: 135 , front_translations: {"es":"Partición de la Índia","de":"Teilung Indiens","fr":"Partition de l'Inde","tr":"Hindistan'ın Bölünmesi","nl":"Deling van India","ru":"Раздел Индии","zh":"印巴分治","pt_BR":"Partição da Índia","pt_PT":"Partição da Índia"}, back_translations: {"es":"1947. La retirada británica de la Índia fue acompanhada por una partición que criou el Paquistão; deslocamentos populacionais massivos y violencia comunal mataram centenas de milhares.","de":"1947. Der Rückzug Großbritanniens aus Indien wurde von einer Teilung begleitet, die Pakistan hervorbrachte; massive Bevölkerungsverschiebungen und kommunale Gewalt forderten Hunderttausende Todesopfer.","fr":"1947. Le retrait britannique de l'Inde s'accompagna d'une partition créant le Pakistan ; des déplacements massifs de population et des violences communautaires causèrent la mort de centaines de milliers de personnes.","tr":"1947. İngiltere'nin Hindistan'dan çekilmesi, Pakistan'ı oluşturan bir bölünmeyle birlikte gerçekleşti; kitlesel nüfus göçleri ve toplumlar arası şiddet yüz binlerce kişinin ölümüne yol açtı.","nl":"1947. Het Britse vertrek uit India ging gepaard met een deling die Pakistan creëerde; massale bevolkingsverplaatsing en communaal geweld kostten honderdduizenden het leven.","ru":"1947 год. Уход Великобритании из Индии сопровождался разделом, в результате которого было создано Пакистан; массовое перемещение населения и межобщинное насилие унесли сотни тысяч жизней.","zh":"1947年。英国撤离印度的同时进行了分治，建立了巴基斯坦；大规模人口迁移和教派暴力导致数十万人死亡。","pt_BR":"1947. A retirada britânica da Índia foi acompanhada por uma partição que criou o Paquistão; deslocamentos populacionais massivos e violência comunal mataram centenas de milhares.","pt_PT":"1947. A retirada britânica da Índia foi acompanhada por uma partição que criou o Paquistão; deslocações populacionais massivas e violência comunitária mataram centenas de milhares."}},
  { id: 'dc-history-0136', deck_id: 'deck-history', front: 'Israel Founded', back: '1948. The State of Israel was declared, immediately followed by the Arab-Israeli War; the conflict over this territory has shaped Middle Eastern politics ever since.', sort_order: 136 , front_translations: {"es":"Fundación de Israel","de":"Gründung Israels","fr":"Fondation d'Israël","tr":"İsrail'in Kuruluşu","nl":"Oprichting van Israël","ru":"Основание Израиля","zh":"以色列建国","pt_BR":"Fundação de Israel","pt_PT":"Fundação de Israel"}, back_translations: {"es":"1948. El Estado de Israel fue declarado, imediatamente seguido por la Guerra Árabe-Israelense; el conflito por esse territorio moldou a política del Oriente Médio desde entonces.","de":"1948. Der Staat Israel wurde ausgerufen und sofort vom Arabisch-Israelischen Krieg gefolgt; der Konflikt um dieses Territorium hat die nahöstliche Politik seither geprägt.","fr":"1948. L'État d'Israël fut proclamé, immédiatement suivi par la guerre arabo-israélienne ; le conflit autour de ce territoire a façonné la politique du Proche-Orient depuis lors.","tr":"1948. İsrail Devleti ilan edildi ve hemen ardından Arap-İsrail Savaşı patlak verdi; bu topraklar üzerindeki çatışma o tarihten bu yana Orta Doğu siyasetini şekillendirmeye devam etmektedir.","nl":"1948. De staat Israël werd uitgeroepen, onmiddellijk gevolgd door de Arabisch-Israëlische Oorlog; het conflict over dit grondgebied heeft sindsdien de Midden-Oosterse politiek bepaald.","ru":"1948. Было провозглашено Государство Израиль, которое тут же вступило в арабо-израильскую войну; конфликт вокруг этих территорий по сей день определяет политику Ближнего Востока.","zh":"1948年。以色列国宣告成立，随即引发第一次阿以战争；围绕这片土地的冲突自此深刻影响了中东政治格局。","pt_BR":"1948. O Estado de Israel foi declarado, imediatamente seguido pela Guerra Árabe-Israelense; o conflito por esse território moldou a política do Oriente Médio desde então.","pt_PT":"1948. O Estado de Israel foi declarado, imediatamente seguido pela Guerra Árabe-Israelense; o conflito por esse território tem moldado a política do Médio Oriente desde então."}},
  { id: 'dc-history-0137', deck_id: 'deck-history', front: 'Berlin Airlift', back: '1948–1949. Western allies airlifted supplies to West Berlin for over a year after the Soviet Union blockaded land routes, in a major early Cold War standoff.', sort_order: 137 , front_translations: {"es":"Ponte Aérea de Berlim","de":"Berliner Luftbrücke","fr":"Pont aérien de Berlin","tr":"Berlin Hava Köprüsü","nl":"Berlijnse Luchtbrug","ru":"Берлинский воздушный мост","zh":"柏林空运","pt_BR":"Ponte Aérea de Berlim","pt_PT":"Ponte Aérea de Berlim"}, back_translations: {"es":"1948–1949. Los aliados ocidentais abasteceram Berlim Ocidental por via aérea por más de un ano após a União Soviética bloquear las rotas terrestres, en un de los primeros grandes confrontos de la Guerra Fría.","de":"1948–1949. Die westlichen Alliierten versorgten West-Berlin mehr als ein Jahr lang auf dem Luftweg, nachdem die Sowjetunion die Landwege blockiert hatte – ein früher großer Kalter-Kriegs-Konflikt.","fr":"1948–1949. Les Alliés occidentaux ravitaillèrent Berlin-Ouest par voie aérienne pendant plus d'un an après que l'Union soviétique eut bloqué les voies terrestres, dans l'un des premiers grands affrontements de la Guerre froide.","tr":"1948–1949. Sovyetler Birliği'nin kara yollarını abluka altına almasının ardından Batılı müttefikler Batı Berlin'e bir yıldan uzun süre hava yoluyla ikmal sağladı; bu, Soğuk Savaş'ın önemli ilk gerilimlerinden biriydi.","nl":"1948–1949. De westerse geallieerden bevoorraden West-Berlijn ruim een jaar per vliegtuig nadat de Sovjet-Unie de landroutes had geblokkeerd, in een van de eerste grote confrontaties van de Koude Oorlog.","ru":"1948–1949. Западные союзники более года снабжали Западный Берлин по воздуху после того, как СССР заблокировал наземные пути сообщения, — одно из первых крупных противостояний холодной войны.","zh":"1948–1949年。苏联封锁陆路通道后，西方盟国通过空运向西柏林供应物资长达一年有余，成为冷战初期的重大对峙事件。","pt_BR":"1948–1949. Os aliados ocidentais abasteceram Berlim Ocidental por via aérea por mais de um ano após a União Soviética bloquear as rotas terrestres, em um dos primeiros grandes confrontos da Guerra Fria.","pt_PT":"1948–1949. Os aliados ocidentais abasteceram Berlim Ocidental por via aérea durante mais de um ano após a União Soviética bloquear as rotas terrestres, numa das primeiras grandes confrontações da Guerra Fria."}},
  { id: 'dc-history-0138', deck_id: 'deck-history', front: 'Decolonization of Africa', back: '1950s–1970s. The wave of African nations gaining independence from European colonial powers; most of sub-Saharan Africa achieved independence within two decades of WWII.', sort_order: 138 , front_translations: {"es":"Descolonización de la África","de":"Entkolonialisierung Afrikas","fr":"Décolonisation de l'Afrique","tr":"Afrika'nın Sömürgeden Kurtulması","nl":"Dekolonisatie van Afrika","ru":"Деколонизация Африки","zh":"非洲去殖民化","pt_BR":"Descolonização da África","pt_PT":"Descolonização de África"}, back_translations: {"es":"Décadas de 1950–1970. La onda de naciones africanas conquistando independencia de las potencias coloniais europeias; a mayor parte de la África subsaariana alcançou a independencia en de los décadas após a Segunda Guerra Mundial.","de":"1950er–1970er. Die Welle afrikanischer Nationen, die die Unabhängigkeit von europäischen Kolonialmächten erlangten; der Großteil Subsahara-Afrikas erlangte innerhalb von zwei Jahrzehnten nach dem Zweiten Weltkrieg die Unabhängigkeit.","fr":"Années 1950–1970. La vague de nations africaines accédant à l'indépendance des puissances coloniales européennes ; la majeure partie de l'Afrique subsaharienne obtint son indépendance en moins de deux décennies après la Seconde Guerre mondiale.","tr":"1950'ler–1970'ler. Afrika ülkelerinin Avrupalı sömürgeci güçlerden bağımsızlığını kazandığı dönem; Sahra altı Afrika'nın büyük bölümü, II. Dünya Savaşı'nın ardından iki on yıl içinde bağımsızlığını elde etti.","nl":"Jaren 1950–1970. De golf van Afrikaanse naties die onafhankelijkheid verwierven van Europese koloniale machten; het grootste deel van sub-Saharaans Afrika bereikte onafhankelijkheid binnen twee decennia na WWII.","ru":"1950–1970-е годы. Волна обретения независимости африканскими странами от европейских колониальных держав; большинство государств Африки к югу от Сахары достигли независимости в течение двух десятилетий после Второй мировой войны.","zh":"20世纪50至70年代。非洲各国相继脱离欧洲殖民势力独立的浪潮；撒哈拉以南非洲大部分地区在二战后二十年内相继获得独立。","pt_BR":"Décadas de 1950–1970. A onda de nações africanas conquistando independência das potências coloniais europeias; a maior parte da África subsaariana alcançou a independência em duas décadas após a Segunda Guerra Mundial.","pt_PT":"Décadas de 1950–1970. A vaga de nações africanas a conquistar a independência das potências coloniais europeias; a maior parte da África subsaariana alcançou a independência nas duas décadas após a Segunda Guerra Mundial."}},
  { id: 'dc-history-0139', deck_id: 'deck-history', front: 'Yuri Gagarin First Human in Space', back: '1961. Soviet cosmonaut Yuri Gagarin became the first human to orbit Earth, a major victory in the Space Race and a milestone in human exploration.', sort_order: 139 , front_translations: {"es":"Yuri Gagarin – Primero Humano en el Espacio","de":"Juri Gagarin – Erster Mensch im Weltraum","fr":"Youri Gagarine, premier homme dans l'espace","tr":"Yuri Gagarin – Uzaydaki İlk İnsan","nl":"Joeri Gagarin – Eerste mens in de ruimte","ru":"Юрий Гагарин — первый человек в космосе","zh":"尤里·加加林——首位进入太空的人类","pt_BR":"Yuri Gagarin – Primeiro Humano no Espaço","pt_PT":"Yuri Gagarin – Primeiro Ser Humano no Espaço"}, back_translations: {"es":"1961. El cosmonauta soviético Yuri Gagarin tornou-se el primero humano a orbitar a Tierra, una grande vitória en la Corrida Espacial y un marco en la exploración humana.","de":"1961. Der sowjetische Kosmonaut Juri Gagarin wurde der erste Mensch, der die Erde umkreiste – ein bedeutender Sieg im Wettlauf ins All und ein Meilenstein der menschlichen Erforschung des Universums.","fr":"1961. Le cosmonaute soviétique Youri Gagarine devint le premier être humain à orbiter autour de la Terre, une victoire majeure dans la course à l'espace et une étape dans l'exploration humaine.","tr":"1961. Sovyet kozmonot Yuri Gagarin, Dünya'yı yörüngede dolanan ilk insan oldu; bu başarı Uzay Yarışı'nda büyük bir zafer ve insanlık tarihinde önemli bir kilometre taşıydı.","nl":"1961. De Sovjet-kosmonaut Joeri Gagarin werd de eerste mens die de aarde omcirkelde, een grote overwinning in de Ruimterace en een mijlpaal in de menselijke verkenning.","ru":"1961. Советский космонавт Юрий Гагарин стал первым человеком, совершившим орбитальный полёт вокруг Земли, — крупная победа в космической гонке и веха в истории освоения космоса.","zh":"1961年。苏联宇航员尤里·加加林成为首位绕地球飞行的人类，在太空竞赛中取得重大胜利，也是人类探索史上的里程碑。","pt_BR":"1961. O cosmonauta soviético Yuri Gagarin tornou-se o primeiro humano a orbitar a Terra, uma grande vitória na Corrida Espacial e um marco na exploração humana.","pt_PT":"1961. O cosmonauta soviético Yuri Gagarin tornou-se o primeiro ser humano a orbitar a Terra, uma grande vitória na Corrida Espacial e um marco na exploração humana."}},
  { id: 'dc-history-0140', deck_id: 'deck-history', front: 'Prague Spring', back: '1968. Czechoslovakia\'s attempt to liberalize under Alexander Dubček was crushed by Soviet-led Warsaw Pact invasion, demonstrating the limits of reform within the Soviet bloc.', sort_order: 140 , front_translations: {"es":"Primavera de Praga","de":"Prager Frühling","fr":"Printemps de Prague","tr":"Prag Baharı","nl":"Praagse Lente","ru":"Пражская весна","zh":"布拉格之春","pt_BR":"Primavera de Praga","pt_PT":"Primavera de Praga"}, back_translations: {"es":"1968. La tentativa de la Tchecoslováquia de se liberalizar sob Alexander Dubček fue esmagada por la invasão del Pacto de Varsóvia liderada por los soviéticos, demonstrando los limites de la reforma dentro del bloco soviético.","de":"1968. Der Versuch der Tschechoslowakei, sich unter Alexander Dubček zu liberalisieren, wurde durch die sowjetisch geführte Invasion des Warschauer Paktes niedergeschlagen und zeigte die Grenzen von Reformen innerhalb des Sowjetblocks auf.","fr":"1968. La tentative de libéralisation de la Tchécoslovaquie sous Alexander Dubček fut écrasée par l'invasion du Pacte de Varsovie menée par les Soviétiques, démontrant les limites de la réforme au sein du bloc soviétique.","tr":"1968. Çekoslovakya'nın Alexander Dubček yönetimindeki liberalleşme girişimi, Sovyet liderliğindeki Varşova Paktı işgaliyle bastırıldı ve Sovyet bloğu içindeki reform sınırlarını gözler önüne serdi.","nl":"1968. De poging van Tsjechoslowakije om onder Alexander Dubček te liberaliseren werd neergeslagen door de door de Sovjet-Unie geleide invasie van het Warschaupact, wat de grenzen van hervorming binnen het Sovjetblok aantoonde.","ru":"1968 год. Попытка Чехословакии провести либерализацию при Александре Дубчеке была подавлена вторжением войск Варшавского договора под руководством СССР, продемонстрировав пределы реформ в советском блоке.","zh":"1968年。捷克斯洛伐克在亚历山大·杜布切克领导下的自由化尝试被苏联主导的华约入侵所镇压，展示了苏联集团内改革的局限性。","pt_BR":"1968. A tentativa da Tchecoslováquia de se liberalizar sob Alexander Dubček foi esmagada pela invasão do Pacto de Varsóvia liderada pelos soviéticos, demonstrando os limites da reforma dentro do bloco soviético.","pt_PT":"1968. A tentativa da Checoslováquia de se liberalizar sob Alexander Dubček foi esmagada pela invasão do Pacto de Varsóvia liderada pelos soviéticos, demonstrando os limites da reforma dentro do bloco soviético."}},
  { id: 'dc-history-0141', deck_id: 'deck-history', front: 'Nixon\'s Visit to China', back: '1972. President Nixon\'s historic visit began normalization of relations between the US and the People\'s Republic of China after more than two decades of hostility.', sort_order: 141 , front_translations: {"es":"Visita de Nixon a la China","de":"Nixons Besuch in China","fr":"Visite de Nixon en Chine","tr":"Nixon'ın Çin Ziyareti","nl":"Nixons bezoek aan China","ru":"Визит Никсона в Китай","zh":"尼克松访华","pt_BR":"Visita de Nixon à China","pt_PT":"Visita de Nixon à China"}, back_translations: {"es":"1972. La visita histórica del presidente Nixon iniciou a normalización de las relaciones entre los EUA y a República Popular de la China após más de de los décadas de hostilidad.","de":"1972. Präsident Nixons historischer Besuch leitete die Normalisierung der Beziehungen zwischen den USA und der Volksrepublik China nach mehr als zwei Jahrzehnten der Feindseligkeit ein.","fr":"1972. La visite historique du président Nixon amorça la normalisation des relations entre les États-Unis et la République populaire de Chine après plus de deux décennies d'hostilité.","tr":"1972. Başkan Nixon'ın tarihi ziyareti, yirmi yılı aşkın düşmanlığın ardından ABD ile Çin Halk Cumhuriyeti arasındaki ilişkilerin normalleşme sürecini başlattı.","nl":"1972. Het historische bezoek van president Nixon begon de normalisering van de betrekkingen tussen de VS en de Volksrepubliek China na meer dan twee decennia van vijandschap.","ru":"1972 год. Исторический визит президента Никсона положил начало нормализации отношений между США и Китайской Народной Республикой после более чем двух десятилетий враждебности.","zh":"1972年。尼克松总统的历史性访问开启了中美关系正常化进程，结束了两国二十多年的敌对状态。","pt_BR":"1972. A visita histórica do presidente Nixon iniciou a normalização das relações entre os EUA e a República Popular da China após mais de duas décadas de hostilidade.","pt_PT":"1972. A visita histórica do presidente Nixon iniciou a normalização das relações entre os EUA e a República Popular da China após mais de duas décadas de hostilidade."}},
  { id: 'dc-history-0142', deck_id: 'deck-history', front: 'Watergate Scandal', back: '1972–1974. A political scandal arising from the break-in at the Democratic National Committee headquarters; it led to President Nixon\'s resignation to avoid impeachment.', sort_order: 142 , front_translations: {"es":"Escandalo de Watergate","de":"Watergate-Skandal","fr":"Scandale du Watergate","tr":"Watergate Skandalı","nl":"Watergateschandaal","ru":"Уотергейтский скандал","zh":"水门事件","pt_BR":"Escândalo de Watergate","pt_PT":"Escândalo de Watergate"}, back_translations: {"es":"1972–1974. Un escandalo político decorrente de la invasão a la sede del Comite Nacional Democrata; levou a la renúncia del presidente Nixon para evitar el impeachment.","de":"1972–1974. Ein politischer Skandal, der aus dem Einbruch in das Hauptquartier des Democratic National Committee hervorging; er führte zum Rücktritt von Präsident Nixon, um einer Amtsenthebung zu entgehen.","fr":"1972–1974. Un scandale politique né du cambriolage au siège du Comité national démocrate ; il conduisit à la démission du président Nixon pour éviter la destitution.","tr":"1972–1974. Demokrat Parti Ulusal Komitesi merkezine yapılan izinsiz girişten kaynaklanan siyasi skandal; Başkan Nixon'ın görevden alınmayı önlemek için istifa etmesine yol açtı.","nl":"1972–1974. Een politiek schandaal voortkomend uit de inbraak in het hoofdkwartier van het Democratic National Committee; het leidde tot het aftreden van president Nixon om afzetting te voorkomen.","ru":"1972–1974 годы. Политический скандал, возникший после взлома штаб-квартиры Демократического национального комитета; привёл к отставке президента Никсона во избежание импичмента.","zh":"1972–1974年。因民主党全国委员会总部遭非法闯入而引发的政治丑闻；最终导致尼克松总统为避免弹劾而辞职。","pt_BR":"1972–1974. Um escândalo político decorrente da invasão à sede do Comitê Nacional Democrata; levou à renúncia do presidente Nixon para evitar o impeachment.","pt_PT":"1972–1974. Um escândalo político decorrente da invasão à sede do Comité Nacional Democrata; levou à demissão do presidente Nixon para evitar a destituição."}},
  { id: 'dc-history-0143', deck_id: 'deck-history', front: 'Iranian Revolution', back: '1979. Shah Mohammad Reza Pahlavi was overthrown and replaced by an Islamic republic under Ayatollah Khomeini, transforming Iran and regional geopolitics.', sort_order: 143 , front_translations: {"es":"Revolución Iraniana","de":"Iranische Revolution","fr":"Révolution iranienne","tr":"İran Devrimi","nl":"Iraanse Revolutie","ru":"Иранская революция","zh":"伊朗伊斯兰革命","pt_BR":"Revolução Iraniana","pt_PT":"Revolução Iraniana"}, back_translations: {"es":"1979. El xá Mohammad Reza Pahlavi fue derrubado y substituído por una república islámica sob el aiatolá Khomeini, transformando el Irã y a geopolítica regional.","de":"1979. Schah Mohammad Reza Pahlavi wurde gestürzt und durch eine islamische Republik unter Ayatollah Khomeini ersetzt, was den Iran und die regionale Geopolitik grundlegend veränderte.","fr":"1979. Le shah Mohammad Reza Pahlavi fut renversé et remplacé par une république islamique sous l'ayatollah Khomeini, transformant l'Iran et la géopolitique régionale.","tr":"1979. Şah Muhammed Rıza Pehlevi devrildi ve yerine Ayetullah Humeyni liderliğinde İslam cumhuriyeti kuruldu; bu devrim İran'ı ve bölgesel jeopolitiği dönüştürdü.","nl":"1979. Sjah Mohammad Reza Pahlavi werd afgezet en vervangen door een islamitische republiek onder ayatollah Khomeini, wat Iran en de regionale geopolitiek transformeerde.","ru":"1979 год. Шах Мохаммед Реза Пехлеви был свергнут и заменён Исламской Республикой во главе с аятоллой Хомейни, что преобразило Иран и региональную геополитику.","zh":"1979年。沙阿穆罕默德·礼萨·巴列维被推翻，取而代之的是阿亚图拉霍梅尼领导的伊斯兰共和国，深刻改变了伊朗和地区地缘政治格局。","pt_BR":"1979. O xá Mohammad Reza Pahlavi foi derrubado e substituído por uma república islâmica sob o aiatolá Khomeini, transformando o Irã e a geopolítica regional.","pt_PT":"1979. O xá Mohammad Reza Pahlavi foi derrubado e substituído por uma república islâmica sob o aiatola Khomeini, transformando o Irão e a geopolítica regional."}},
  { id: 'dc-history-0144', deck_id: 'deck-history', front: 'Soviet Invasion of Afghanistan', back: '1979–1989. The USSR invaded Afghanistan to support a communist government; the decade-long war, aided by US-backed mujahideen, contributed to Soviet collapse and later fueled the Taliban.', sort_order: 144 , front_translations: {"es":"Invasão Soviética del Afeganistão","de":"Sowjetische Invasion in Afghanistan","fr":"Invasion soviétique de l'Afghanistan","tr":"Sovyetlerin Afganistan İşgali","nl":"Sovjet-invasie van Afghanistan","ru":"Советское вторжение в Афганистан","zh":"苏联入侵阿富汗","pt_BR":"Invasão Soviética do Afeganistão","pt_PT":"Invasão Soviética do Afeganistão"}, back_translations: {"es":"1979–1989. La URSS invadiu el Afeganistão para apoiar un gobierno comunista; a guerra de una década, auxiliada por mujahidin apoiados por los EUA, contribuiu para el colapso soviético y posteriormente alimentou el Talibã.","de":"1979–1989. Die UdSSR marschierte in Afghanistan ein, um eine kommunistische Regierung zu unterstützen; der jahrzehntelange Krieg, der von US-unterstützten Mudschaheddin geführt wurde, trug zum Zusammenbruch der Sowjetunion bei und befeuerte später die Taliban.","fr":"1979–1989. L'URSS envahit l'Afghanistan pour soutenir un gouvernement communiste ; la guerre d'une décennie, soutenue par les moudjahidines financés par les États-Unis, contribua à l'effondrement soviétique et alimenta par la suite les talibans.","tr":"1979–1989. SSCB, bir komünist hükümeti desteklemek için Afganistan'ı işgal etti; ABD destekli mücahitlerin yardımıyla süren on yıllık savaş Sovyet çöküşüne katkıda bulundu ve daha sonra Taliban'ı besledi.","nl":"1979–1989. De USSR viel Afghanistan binnen om een communistische regering te steunen; de tien jaar durende oorlog, gesteund door door de VS gefinancierde moedjahedien, droeg bij aan de Sovjet-ineenstorting en voedde later de Taliban.","ru":"1979–1989 годы. СССР вторгся в Афганистан для поддержки коммунистического правительства; десятилетняя война при поддержке американских моджахедов способствовала распаду Советского Союза и впоследствии подпитала движение Талибан.","zh":"1979–1989年。苏联入侵阿富汗以支持一个共产主义政府；在美国支持的圣战者协助下持续十年的战争促进了苏联的解体，并在后来催生了塔利班。","pt_BR":"1979–1989. A URSS invadiu o Afeganistão para apoiar um governo comunista; a guerra de uma década, auxiliada por mujahidin apoiados pelos EUA, contribuiu para o colapso soviético e posteriormente alimentou o Talibã.","pt_PT":"1979–1989. A URSS invadiu o Afeganistão para apoiar um governo comunista; a guerra de uma década, auxiliada por mujahidin apoiados pelos EUA, contribuiu para o colapso soviético e posteriormente alimentou os talibãs."}},
  { id: 'dc-history-0145', deck_id: 'deck-history', front: 'Chernobyl Disaster', back: '1986. An explosion at the Chernobyl nuclear power plant in Soviet Ukraine released massive radiation; it is the worst nuclear accident in history and a factor in Soviet decline.', sort_order: 145 , front_translations: {"es":"Desastre de Chernobyl","de":"Katastrophe von Tschernobyl","fr":"Catastrophe de Tchernobyl","tr":"Çernobil Felaketi","nl":"Ramp van Tsjernobyl","ru":"Чернобыльская катастрофа","zh":"切尔诺贝利核灾难","pt_BR":"Desastre de Chernobyl","pt_PT":"Desastre de Chernobil"}, back_translations: {"es":"1986. Una explosão en la usina nuclear de Chernobyl en la Ucrania Soviética liberou radiación massiva; es el peor acidente nuclear de la historia y un fator en el declínio soviético.","de":"1986. Eine Explosion im Kernkraftwerk Tschernobyl in der Sowjetukraine setzte massive Strahlung frei; es ist der schlimmste Nuklearunfall der Geschichte und ein Faktor im Niedergang der Sowjetunion.","fr":"1986. Une explosion à la centrale nucléaire de Tchernobyl en Ukraine soviétique libéra une radiation massive ; c'est le pire accident nucléaire de l'histoire et un facteur du déclin soviétique.","tr":"1986. Sovyet Ukraynası'ndaki Çernobil nükleer santralinde meydana gelen patlama büyük miktarda radyasyon yaydı; tarihin en büyük nükleer kazası olup Sovyet çöküşünün etkenlerinden biridir.","nl":"1986. Een explosie in de kerncentrale van Tsjernobyl in Sovjet-Oekraïne veroorzaakte massale straling; het is het ergste nucleaire ongeluk in de geschiedenis en een factor in het verval van de Sovjet-Unie.","ru":"1986 год. Взрыв на Чернобыльской атомной электростанции в Советской Украине привёл к выбросу огромного количества радиации; это самая тяжёлая ядерная авария в истории и один из факторов распада СССР.","zh":"1986年。苏联乌克兰切尔诺贝利核电站发生爆炸，释放大量辐射；这是历史上最严重的核事故，也是苏联衰落的因素之一。","pt_BR":"1986. Uma explosão na usina nuclear de Chernobyl na Ucrânia Soviética liberou radiação massiva; é o pior acidente nuclear da história e um fator no declínio soviético.","pt_PT":"1986. Uma explosão na central nuclear de Chernobil na Ucrânia Soviética libertou radiação massiva; é o pior acidente nuclear da história e um fator no declínio soviético."}},
  { id: 'dc-history-0146', deck_id: 'deck-history', front: 'Gulf War', back: '1990–1991. A US-led coalition expelled Iraqi forces from Kuwait after Saddam Hussein\'s invasion; the war demonstrated overwhelming US military dominance in the post-Cold War era.', sort_order: 146 , front_translations: {"es":"Guerra del Golfo","de":"Golfkrieg","fr":"Guerre du Golfe","tr":"Körfez Savaşı","nl":"Golfoorlog","ru":"Война в Персидском заливе","zh":"海湾战争","pt_BR":"Guerra do Golfo","pt_PT":"Guerra do Golfo"}, back_translations: {"es":"1990–1991. Una coalizão liderada por los EUA expulsou las fuerzas iraquianas del Kuwait após a invasão de Saddam Hussein; a guerra demonstrou a esmagadora dominancia militar de los EUA en la era pós-Guerra Fría.","de":"1990–1991. Eine von den USA geführte Koalition vertrieb irakische Truppen aus Kuwait nach Saddam Husseins Invasion; der Krieg demonstrierte die überwältigende militärische Dominanz der USA in der Ära nach dem Kalten Krieg.","fr":"1990–1991. Une coalition menée par les États-Unis expulsa les forces irakiennes du Koweït après l'invasion de Saddam Hussein ; la guerre démontra l'écrasante domination militaire américaine dans l'ère post-guerre froide.","tr":"1990–1991. Saddam Hüseyin'in işgalinin ardından ABD liderliğindeki koalisyon Irak güçlerini Kuveyt'ten çıkardı; savaş, Soğuk Savaş sonrası dönemde ABD'nin ezici askeri üstünlüğünü ortaya koydu.","nl":"1990–1991. Een door de VS geleide coalitie verdreef Iraakse troepen uit Koeweit na de invasie van Saddam Hoessein; de oorlog demonstreerde de overweldigende Amerikaanse militaire dominantie in het post-Koude Oorlog-tijdperk.","ru":"1990–1991 годы. Коалиция во главе с США изгнала иракские войска из Кувейта после вторжения Саддама Хусейна; война продемонстрировала подавляющее военное превосходство США в эпоху после холодной войны.","zh":"1990–1991年。萨达姆·侯赛因入侵科威特后，以美国为首的联军将伊拉克军队驱逐出境；这场战争展示了冷战后美国压倒性的军事优势。","pt_BR":"1990–1991. Uma coalizão liderada pelos EUA expulsou as forças iraquianas do Kuwait após a invasão de Saddam Hussein; a guerra demonstrou a esmagadora dominância militar dos EUA na era pós-Guerra Fria.","pt_PT":"1990–1991. Uma coligação liderada pelos EUA expulsou as forças iraquianas do Kuwait após a invasão de Saddam Hussein; a guerra demonstrou a esmagadora dominância militar dos EUA na era pós-Guerra Fria."}},
  { id: 'dc-history-0147', deck_id: 'deck-history', front: 'Kyoto Protocol', back: '1997. An international treaty committing nations to reduce greenhouse gas emissions; a landmark in global environmental diplomacy, though its effectiveness was limited by non-participation of key emitters.', sort_order: 147 , front_translations: {"es":"Protocolo de Quioto","de":"Kyoto-Protokoll","fr":"Protocole de Kyoto","tr":"Kyoto Protokolü","nl":"Kyotoprotocol","ru":"Киотский протокол","zh":"京都议定书","pt_BR":"Protocolo de Quioto","pt_PT":"Protocolo de Quioto"}, back_translations: {"es":"1997. Un tratado internacional comprometendo naciones a reduzir emisiones de gases de efecto invernadero; un marco en la diplomacia ambiental global, aunque su eficácia tenha sido limitada por la no participación de emissores-chave.","de":"1997. Ein internationales Abkommen, das Staaten zur Reduzierung von Treibhausgasemissionen verpflichtete; ein Meilenstein der globalen Umweltdiplomatie, dessen Wirksamkeit jedoch durch die Nichtteilnahme wichtiger Emittenten eingeschränkt war.","fr":"1997. Un traité international engageant les nations à réduire les émissions de gaz à effet de serre ; une étape majeure de la diplomatie environnementale mondiale, bien que son efficacité ait été limitée par la non-participation d'émetteurs clés.","tr":"1997. Ülkeleri sera gazı emisyonlarını azaltmaya taahhüt eden uluslararası anlaşma; küresel çevre diplomasisinde bir dönüm noktası olmasına rağmen, önemli kirleticilerin katılmaması nedeniyle etkinliği sınırlı kaldı.","nl":"1997. Een internationaal verdrag dat landen verplichtte tot het verminderen van broeikasgasemissies; een mijlpaal in de mondiale milieudiplomatie, hoewel de effectiviteit beperkt was door niet-deelname van belangrijke uitstoters.","ru":"1997 год. Международный договор, обязывающий государства сокращать выбросы парниковых газов; важная веха глобальной экологической дипломатии, хотя его эффективность была ограничена неучастием крупнейших загрязнителей.","zh":"1997年。一项承诺各国减少温室气体排放的国际条约；是全球环境外交的里程碑，但由于主要排放国未参与，其成效有限。","pt_BR":"1997. Um tratado internacional comprometendo nações a reduzir emissões de gases de efeito estufa; um marco na diplomacia ambiental global, embora sua eficácia tenha sido limitada pela não participação de emissores-chave.","pt_PT":"1997. Um tratado internacional comprometendo nações a reduzir emissões de gases com efeito de estufa; um marco na diplomacia ambiental global, embora a sua eficácia tenha sido limitada pela não participação de emissores-chave."}},
  { id: 'dc-history-0148', deck_id: 'deck-history', front: 'Iraq War', back: '2003–2011. The US-led invasion of Iraq toppled Saddam Hussein based on disputed WMD claims; the war destabilized the region and contributed to the rise of ISIS.', sort_order: 148 , front_translations: {"es":"Guerra del Iraque","de":"Irakkrieg","fr":"Guerre d'Irak","tr":"Irak Savaşı","nl":"Irakoorlog","ru":"Война в Ираке","zh":"伊拉克战争","pt_BR":"Guerra do Iraque","pt_PT":"Guerra do Iraque"}, back_translations: {"es":"2003–2011. La invasão del Iraque liderada por los EUA derrubou Saddam Hussein con base en alegaciones controversas de armas de destrucción en masa; a guerra desestabilizou a región y contribuiu para a ascensão del ISIS.","de":"2003–2011. Die von den USA geführte Invasion im Irak stürzte Saddam Hussein auf der Grundlage umstrittener Behauptungen über Massenvernichtungswaffen; der Krieg destabilisierte die Region und trug zum Aufstieg des IS bei.","fr":"2003–2011. L'invasion de l'Irak menée par les États-Unis renversa Saddam Hussein sur la base d'allégations contestées d'armes de destruction massive ; la guerre déstabilisa la région et contribua à la montée de l'État islamique.","tr":"2003–2011. ABD liderliğindeki Irak işgali, tartışmalı kitle imha silahları iddialarına dayanarak Saddam Hüseyin'i devirdi; savaş bölgeyi istikrarsızlaştırdı ve IŞİD'in yükselişine katkıda bulundu.","nl":"2003–2011. De door de VS geleide invasie van Irak zette Saddam Hoessein af op basis van betwiste claims over massavernietigingswapens; de oorlog destabiliseerde de regio en droeg bij aan de opkomst van ISIS.","ru":"2003–2011 годы. Вторжение в Ирак под руководством США свергло Саддама Хусейна на основании спорных заявлений об оружии массового уничтожения; война дестабилизировала регион и способствовала подъёму ИГИЛ.","zh":"2003–2011年。美国领导的入侵以有争议的大规模杀伤性武器为由推翻了萨达姆·侯赛因政权；这场战争动摇了该地区的稳定，并促成了ISIS的崛起。","pt_BR":"2003–2011. A invasão do Iraque liderada pelos EUA derrubou Saddam Hussein com base em alegações controversas de armas de destruição em massa; a guerra desestabilizou a região e contribuiu para a ascensão do ISIS.","pt_PT":"2003–2011. A invasão do Iraque liderada pelos EUA derrubou Saddam Hussein com base em alegações controversas de armas de destruição maciça; a guerra desestabilizou a região e contribuiu para a ascensão do Estado Islâmico."}},
  { id: 'dc-history-0149', deck_id: 'deck-history', front: 'Global Financial Crisis', back: '2007–2008. A severe worldwide economic crisis triggered by the collapse of the US subprime mortgage market; the worst financial crisis since the Great Depression.', sort_order: 149 , front_translations: {"es":"Crise Financera Global","de":"Globale Finanzkrise","fr":"Crise financière mondiale","tr":"Küresel Mali Kriz","nl":"Wereldwijde financiële crisis","ru":"Мировой финансовый кризис","zh":"全球金融危机","pt_BR":"Crise Financeira Global","pt_PT":"Crise Financeira Global"}, back_translations: {"es":"2007–2008. Una grave crise económica mundial desencadeada por el colapso del mercado de hipotecas subprime de los EUA; a peor crise financera desde a Grande Depresión.","de":"2007–2008. Eine schwere weltweite Wirtschaftskrise, ausgelöst durch den Zusammenbruch des US-Subprime-Hypothekenmarktes; die schlimmste Finanzkrise seit der Großen Depression.","fr":"2007–2008. Une grave crise économique mondiale déclenchée par l'effondrement du marché américain des prêts hypothécaires à risque ; la pire crise financière depuis la Grande Dépression.","tr":"2007–2008. ABD yüksek riskli (subprime) ipotek piyasasının çöküşünün tetiklediği ciddi küresel ekonomik kriz; Büyük Buhran'dan bu yana yaşanan en ağır mali kriz.","nl":"2007–2008. Een ernstige wereldwijde economische crisis veroorzaakt door de ineenstorting van de Amerikaanse subprime-hypotheekmarkt; de ergste financiële crisis sinds de Grote Depressie.","ru":"2007–2008 годы. Тяжелейший мировой экономический кризис, вызванный крахом рынка субстандартной ипотеки в США; худший финансовый кризис со времён Великой депрессии.","zh":"2007–2008年。由美国次级抵押贷款市场崩溃引发的严重全球经济危机；是大萧条以来最严重的金融危机。","pt_BR":"2007–2008. Uma grave crise econômica mundial desencadeada pelo colapso do mercado de hipotecas subprime dos EUA; a pior crise financeira desde a Grande Depressão.","pt_PT":"2007–2008. Uma grave crise económica mundial desencadeada pelo colapso do mercado de hipotecas subprime dos EUA; a pior crise financeira desde a Grande Depressão."}},
  { id: 'dc-history-0150', deck_id: 'deck-history', front: 'COVID-19 Pandemic', back: '2019–2022. A global pandemic caused by the SARS-CoV-2 virus, resulting in millions of deaths worldwide and unprecedented disruption to economies and daily life.', sort_order: 150 , front_translations: {"es":"Pandemia de COVID-19","de":"COVID-19-Pandemie","fr":"Pandémie de COVID-19","tr":"COVID-19 Pandemisi","nl":"COVID-19-pandemie","ru":"Пандемия COVID-19","zh":"新冠疫情","pt_BR":"Pandemia de COVID-19","pt_PT":"Pandemia de COVID-19"}, back_translations: {"es":"2019–2022. Una pandemia global causada por el virus SARS-CoV-2, resultando en milhões de mortes en todo el mundo y perturbaciones sin precedentes en las economias y en la vida cotidiana.","de":"2019–2022. Eine globale Pandemie, verursacht durch das SARS-CoV-2-Virus, die weltweit Millionen von Todesopfern forderte und beispiellose Störungen der Wirtschaft und des täglichen Lebens verursachte.","fr":"2019–2022. Une pandémie mondiale causée par le virus SARS-CoV-2, entraînant des millions de morts dans le monde et des perturbations sans précédent des économies et de la vie quotidienne.","tr":"2019–2022. SARS-CoV-2 virüsünün neden olduğu küresel salgın; dünya genelinde milyonlarca ölüme ve ekonomi ile günlük yaşamda benzeri görülmemiş aksamalara yol açtı.","nl":"2019–2022. Een wereldwijde pandemie veroorzaakt door het SARS-CoV-2-virus, die miljoenen doden wereldwijd veroorzaakte en ongekende ontwrichting van economieën en het dagelijks leven.","ru":"2019–2022 годы. Глобальная пандемия, вызванная вирусом SARS-CoV-2, унёсшая миллионы жизней по всему миру и вызвавшая беспрецедентные потрясения в экономике и повседневной жизни.","zh":"2019–2022年。由SARS-CoV-2病毒引起的全球大流行，导致全球数百万人死亡，经济和日常生活遭受前所未有的冲击。","pt_BR":"2019–2022. Uma pandemia global causada pelo vírus SARS-CoV-2, resultando em milhões de mortes em todo o mundo e perturbações sem precedentes nas economias e na vida cotidiana.","pt_PT":"2019–2022. Uma pandemia global causada pelo vírus SARS-CoV-2, resultando em milhões de mortes em todo o mundo e perturbações sem precedentes nas economias e na vida quotidiana."}},
];
